// #region Backend & Cache Layer

const callBackend = async (action: string, payload: any) => {
    try {
        console.log(`[Backend Call] Action: ${action}`, payload.model ? `Model: ${payload.model}` : '');
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 55000);

        // NOTE: In local development without Vercel CLI, /api/gemini might not exist (404).
        // This fetch call requires the Backend Serverless Function to be running.
        const res = await fetch('/api/gemini', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action, payload }),
            signal: controller.signal
        });
        clearTimeout(timeoutId);

        const contentType = res.headers.get("content-type");
        if (contentType && contentType.indexOf("application/json") === -1) {
             const text = await res.text();
             console.error("Non-JSON Response from Backend:", text.substring(0, 100));
             throw new Error("Backend Connection Failed (API Route 404 or Server Error). Please ensure Vercel Functions are running.");
        }

        const text = await res.text();
        let data;
        try { data = JSON.parse(text); } 
        catch (e) { throw new Error(`Server returned invalid JSON: ${text.substring(0, 50)}...`); }

        if (!res.ok) throw new Error(data.error || 'Server Error');
        if (action !== 'getServiceStatus') trackApiLoad(); // Don't track monitoring calls
        return data;
    } catch (e: any) {
        console.error(`Backend API Error [${action}]:`, e);
        if (e.name === 'AbortError') throw new Error("請求逾時 (Server Timeout)。");
        throw e;
    }
};

const CACHE_TTL = 12 * 60 * 60 * 1000;

// Refactored Cache Logic: uses `system_cache` with strictly formatted keys
const getSystemCache = async (key: string): Promise<any | null> => {
    if (isMock) return null;
    try {
        const doc = await db.collection('system_cache').doc(key).get();
        if (doc.exists) {
            const data = doc.data();
            if (data && (Date.now() - data.timestamp) < CACHE_TTL) {
                console.log(`[Cache] Hit: ${key}`);
                return data.data;
            }
        }
    } catch (e) { console.warn("Cache Read Error", e); }
    return null;
};

const setSystemCache = async (key: string, data: any) => {
    if (isMock) return;
    try {
        await db.collection('system_cache').doc(key).set({
            data,
            timestamp: Date.now()
        });
    } catch (e) { console.warn("Cache Write Error", e); }
};

