const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);
  const [view, setView] = useState<AppView>(AppView.LOGIN);
  const [settings, setSettings] = useState<BrandSettings>(defaultSettings);
  const [posts, setPosts] = useState<Post[]>([]);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [showReportModal, setShowReportModal] = useState(false);
  const [showKeyModal, setShowKeyModal] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Mobile toggle

  useEffect(() => {
    const unsubscribe = subscribeAuth(async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const profile = await getUserProfile(currentUser.uid);
        setUserProfile(profile);
        setView(AppView.CREATE);
        loadLocalSettings();
        const cloudPosts = await fetchUserPostsFromCloud(currentUser.uid);
        setPosts(cloudPosts);
      } else {
        setUserProfile(null);
        setView(AppView.LOGIN);
      }
      setLoadingAuth(false);
    });
    return () => unsubscribe();
  }, []);

  const loadLocalSettings = () => {
    const savedSettings = localStorage.getItem('autosocial_settings');
    if (savedSettings) {
        try {
            const parsed = JSON.parse(savedSettings);
            setSettings({ ...defaultSettings, ...parsed });
        } catch (e) {}
    }
  };

  const handleLogout = async () => {
    await logout();
    setView(AppView.LOGIN);
  };

  const refreshProfile = async () => {
    if (user) {
      const profile = await getUserProfile(user.uid);
      setUserProfile(profile);
    }
  };

  const handleSaveSettings = (newSettings: BrandSettings) => {
    setSettings(newSettings);
    localStorage.setItem('autosocial_settings', JSON.stringify(newSettings));
  };

  const handlePostCreated = async (newPost: Post) => {
    if (!user || !userProfile) return;

    if (newPost.status === 'scheduled') {
        const scheduledCount = posts.filter(p => p.status === 'scheduled' && p.id !== newPost.id).length;
        const role = userProfile.role;
        let limit = 3; 
        if (role === 'pro') limit = 5;
        else if (role === 'business') limit = 10;
        else if (role === 'admin') limit = 100;

        if (scheduledCount >= limit) {
            alert(`⚠️ 排程空間不足！您的方案最多儲存 ${limit} 篇排程貼文。`);
            return;
        }
    }

    try {
        setPosts(prev => {
            const exists = prev.find(p => p.id === newPost.id);
            if (exists) return prev.map(p => p.id === newPost.id ? newPost : p);
            return [newPost, ...prev];
        });

        await syncPostToCloud(user.uid, newPost);
        const updatedPosts = await fetchUserPostsFromCloud(user.uid);
        setPosts(updatedPosts);
        setEditingPost(null);
        setView(AppView.SCHEDULE);
    } catch (e: any) {
        alert(`同步失敗: ${e.message}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
      if (!user) return;
      // Note: Actual API deletion logic is handled inside ScheduleList component now for better encapsulation
      // This function mainly handles local/cloud sync state removal
      try {
          await deletePostFromCloud(user.uid, postId);
          setPosts(prev => prev.filter(p => p.id !== postId));
      } catch (e) {
          alert("刪除失敗");
      }
  };

  const handleEditPost = (post: Post) => {
      setEditingPost(post);
      setView(AppView.CREATE);
  };

  const role = userProfile?.role || 'user';
  const isAdmin = role === 'admin';
  const isStarterPlus = ['starter', 'pro', 'business', 'admin'].includes(role);
  const isProPlus = ['pro', 'business', 'admin'].includes(role);
  const isBusinessPlus = ['business', 'admin'].includes(role);

  const hasAnalyticsAccess = isStarterPlus || userProfile?.unlockedFeatures?.includes('ANALYTICS');
  const hasAutomationAccess = isBusinessPlus || userProfile?.unlockedFeatures?.includes('AUTOMATION');
  const hasSeoAccess = isProPlus || userProfile?.unlockedFeatures?.includes('SEO');
  const hasThreadsAccess = isProPlus || userProfile?.unlockedFeatures?.includes('THREADS');

  if (loadingAuth) return <div className="h-screen flex items-center justify-center bg-bg text-primary text-xl animate-pulse font-mono tracking-widest">INITIALIZING SYSTEM...</div>;
  if (view === AppView.LOGIN) return <Login onLoginSuccess={() => {}} />;

  const NavItem = ({ viewId, label, active, onClick, disabled = false, badge = "", icon }: any) => (
    <button 
      onClick={() => {
          if (!disabled) {
              onClick(viewId);
              setIsSidebarOpen(false); // Close mobile menu on click
          }
      }} 
      className={`relative w-full text-left px-6 py-3.5 transition-all duration-300 flex items-center justify-between group 
        ${active ? 'bg-primary/10 text-primary' : 'text-gray-400 hover:text-white hover:bg-white/5'} 
        ${disabled ? 'opacity-40 cursor-not-allowed grayscale' : ''}
        border-l-2 ${active ? 'border-primary' : 'border-transparent hover:border-white/30'}
      `}
    >
      {active && <div className="absolute inset-0 bg-primary/5 shadow-[0_0_20px_rgba(0,242,234,0.1)]"></div>}
      <div className="flex items-center gap-3 relative z-10">
          <span className={`transition-transform duration-300 ${active ? 'scale-110' : 'group-hover:scale-110'}`}>{icon}</span>
          <span className="text-[14px] font-medium tracking-wide">{label}</span>
      </div>
      {badge && <span className="text-[9px] bg-black/50 border border-gray-700 px-1.5 py-0.5 rounded uppercase tracking-tighter text-gray-400 font-bold">{badge}</span>}
    </button>
  );

  return (
    <div className="min-h-screen text-gray-200 flex flex-col md:flex-row relative font-sans overflow-hidden">

      {/* Mobile Header */}
      <div className="md:hidden flex justify-between items-center p-4 glass-panel border-b border-white/10 relative z-50">
          <h1 className="text-lg font-black tracking-tighter text-white flex items-center gap-2">
            AUTO<span className="text-neon-cyan">SOCIAL</span>
          </h1>
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="text-white p-2">
             {isSidebarOpen ? Icons.Close : Icons.Menu}
          </button>
      </div>

      {/* Glass Sidebar */}
      <aside className={`
          fixed md:relative inset-y-0 left-0 w-72 glass-panel z-40 transform transition-transform duration-300 ease-out flex flex-col
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-8 pb-4">
          <h1 className="text-2xl font-black text-white tracking-tighter cursor-pointer flex items-center gap-2 select-none" onClick={() => setView(AppView.CREATE)}>
            AUTO<span className="text-neon-cyan drop-shadow-[0_0_8px_rgba(0,242,234,0.6)]">SOCIAL</span>
          </h1>
          <div className="mt-6 p-4 glass-card rounded-xl border border-white/10 bg-black/20">
            {userProfile ? (
                <>
                    <div className="flex justify-between items-start mb-2">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-primary to-accent flex items-center justify-center text-black font-bold text-xs">
                            {userProfile.email[0].toUpperCase()}
                        </div>
                        <div className={`text-[10px] px-2 py-0.5 rounded font-black uppercase tracking-wider ${
                            userProfile.role === 'admin' ? 'bg-red-500/20 text-red-400 border border-red-500/50' : 
                            userProfile.role === 'business' ? 'bg-yellow-500/20 text-yellow-400 border border-yellow-500/50' : 
                            'bg-primary/20 text-primary border border-primary/50'
                        }`}>
                            {userProfile.role}
                        </div>
                    </div>
                    <p className="truncate text-xs text-gray-400 mb-3 font-mono">{userProfile.email}</p>
                    <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden mb-1">
                        <div className="h-full bg-primary shadow-[0_0_10px_#00f2ea]" style={{ width: `${Math.min(100, (userProfile.quota_used / userProfile.quota_total) * 100)}%` }}></div>
                    </div>
                    <div className="flex justify-between text-[10px] text-gray-500 font-bold">
                        <span>點數</span>
                        <span>{userProfile.quota_used} / {userProfile.quota_total}</span>
                    </div>
                </>
            ) : <p className="text-xs text-gray-500">GUEST MODE</p>}
          </div>
        </div>

        <nav className="flex-1 py-4 space-y-1 overflow-y-auto custom-scrollbar">
          <NavItem viewId={AppView.CREATE} label="內容創作" icon={Icons.Create} active={view === AppView.CREATE} onClick={setView} />
          <NavItem viewId={AppView.SCHEDULE} label="排程與歷史" icon={Icons.Schedule} active={view === AppView.SCHEDULE} onClick={setView} />
          <NavItem viewId={AppView.SETTINGS} label="品牌設定" icon={Icons.Settings} active={view === AppView.SETTINGS} onClick={setView} />

          <div className="mt-6 mb-2 px-6">
              <p className="text-[10px] text-gray-500 font-black tracking-[0.2em] uppercase">智慧功能</p>
          </div>

          <NavItem viewId={AppView.ANALYTICS} label="數據分析" icon={Icons.Analytics} active={view === AppView.ANALYTICS} onClick={() => hasAnalyticsAccess ? setView(AppView.ANALYTICS) : alert("需升級至 Starter 方案")} disabled={!hasAnalyticsAccess} badge={!hasAnalyticsAccess ? "LOCKED" : ""} />
          <NavItem viewId={AppView.AUTOMATION} label="全自動化" icon={Icons.Automation} active={view === AppView.AUTOMATION} onClick={() => hasAutomationAccess ? setView(AppView.AUTOMATION) : alert("需升級至 Business 方案")} disabled={!hasAutomationAccess} badge={!hasAutomationAccess ? "LOCKED" : ""} />
          <NavItem viewId={AppView.SEO_ARTICLES} label="SEO 文章" icon={Icons.Seo} active={view === AppView.SEO_ARTICLES} onClick={() => hasSeoAccess ? setView(AppView.SEO_ARTICLES) : alert("需升級至 Pro 方案")} disabled={!hasSeoAccess} badge={!hasSeoAccess ? "LOCKED" : ""} />
          <NavItem viewId={AppView.THREADS_NURTURE} label="Threads 農場" icon={Icons.Threads} active={view === AppView.THREADS_NURTURE} onClick={() => hasThreadsAccess ? setView(AppView.THREADS_NURTURE) : alert("需升級至 Pro 方案")} disabled={!hasThreadsAccess} badge={!hasThreadsAccess ? "LOCKED" : ""} />

          <div className="mt-6 mb-2 px-6">
              <p className="text-[10px] text-gray-500 font-black tracking-[0.2em] uppercase">成長工具</p>
          </div>
          <NavItem viewId={AppView.REFERRAL} label="推薦計畫" icon={Icons.Referral} active={view === AppView.REFERRAL} onClick={setView} />
        </nav>

        <div className="p-4 bg-black/20 space-y-2 border-t border-white/5">
          <button onClick={() => setShowKeyModal(true)} className="w-full text-left px-4 py-3 text-xs rounded-lg transition-all font-bold bg-yellow-500/10 text-yellow-400 hover:bg-yellow-500/20 border border-yellow-500/20 flex items-center gap-2 group">
              <span className="opacity-80 group-hover:scale-110 transition-transform">{Icons.Key}</span> 兌換序號 (Redeem)
          </button>

          {isAdmin && (
            <button onClick={() => setView(AppView.ADMIN)} className={`w-full text-left px-4 py-3 text-xs rounded-lg transition-all font-bold flex items-center gap-2 group ${view === AppView.ADMIN ? 'bg-red-600 text-white shadow-lg' : 'text-red-400 hover:bg-red-900/20 border border-red-900/30'}`}>
              <span className="opacity-80 group-hover:scale-110 transition-transform">{Icons.Admin}</span> 管理員後台
            </button>
          )}
          <button onClick={handleLogout} className="w-full text-left px-4 py-3 text-xs text-gray-500 hover:text-white transition-colors flex items-center gap-2 group hover:bg-white/5 rounded-lg">
            <span className="opacity-80 group-hover:scale-110 transition-transform">{Icons.Logout}</span> 登出系統
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 p-4 md:p-8 lg:p-12 overflow-y-auto h-screen custom-scrollbar relative">
        <div className="max-w-7xl mx-auto">
            {view === AppView.CREATE && (
              <PostCreator 
                settings={settings} 
                user={userProfile} 
                onPostCreated={handlePostCreated} 
                onQuotaUpdate={refreshProfile} 
                editPost={editingPost} 
                onCancel={() => setEditingPost(null)}
                scheduledPostsCount={posts.filter(p => p.status === 'scheduled').length}
              />
            )}
            {view === AppView.SCHEDULE && (
              <ScheduleList 
                  posts={posts} 
                  onUpdatePosts={async (updated) => {
                      const originalIds = posts.map(p => p.id);
                      const updatedIds = updated.map(p => p.id);

                      // Identify deletion
                      const deletedId = originalIds.find(id => !updatedIds.includes(id));
                      if (deletedId) await handleDeletePost(deletedId);
                      else {
                          // Identify update (e.g. status change from calendar view)
                          const changed = updated.find((p, i) => JSON.stringify(p) !== JSON.stringify(posts.find(op => op.id === p.id)));
                          if (changed && user) await syncPostToCloud(user.uid, changed);
                          setPosts(updated);
                      }
                  }} 
                  onEditPost={handleEditPost}
                  settings={settings} // Pass settings for API token access
              />
            )}
            {view === AppView.SETTINGS && <SettingsForm onSave={handleSaveSettings} initialSettings={settings} />}
            {view === AppView.ANALYTICS && <AnalyticsDashboard settings={settings} />}
            {view === AppView.AUTOMATION && <AutomationPanel settings={settings} onSave={handleSaveSettings} />}
            {view === AppView.SEO_ARTICLES && <SeoArticleGenerator user={userProfile} onQuotaUpdate={refreshProfile} />}
            {view === AppView.THREADS_NURTURE && <ThreadsNurturePanel settings={settings} user={userProfile} onSaveSettings={handleSaveSettings} onQuotaUpdate={refreshProfile} />}
            {view === AppView.REFERRAL && <ReferralPanel user={userProfile} onQuotaUpdate={refreshProfile} />}
            {view === AppView.ADMIN && isAdmin && <AdminPanel currentUser={userProfile!} />}
        </div>
      </main>

      {/* Report Floating Button */}
      <button 
        onClick={() => setShowReportModal(true)} 
        className="fixed bottom-6 right-6 bg-red-600 hover:bg-red-500 text-white w-12 h-12 rounded-full z-50 shadow-[0_0_20px_rgba(220,38,38,0.5)] transition-transform active:scale-90 flex items-center justify-center font-bold text-xl backdrop-blur-md border border-white/20"
        title="回報問題"
      >
        !
      </button>

      {/* Modals */}
      {showReportModal && <ErrorReportModal user={userProfile} currentView={view} onClose={() => setShowReportModal(false)} />}
      {showKeyModal && userProfile && <KeyRedemptionModal user={userProfile} onClose={() => setShowKeyModal(false)} onSuccess={refreshProfile} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ViralType, ViralPlatform } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string }> = ({ message }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">AI Processing...</p>
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  // 排程上限判定 (For local DB record keeping)
  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");
      const allowed = await checkAndUseQuota(user.user_id, 1, 'TREND_SEARCH');
      if (!allowed) return; // Alert handled in service
      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);

          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;

    const allowed = await checkAndUseQuota(user.user_id, 2, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);
            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: res.imagePrompt || `Professional photo about ${topic}` 
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);

            const fallbackPrompt = `A creative, photorealistic image about ${topic}, 8k resolution, cinematic lighting, commercial photography style`;

            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: res.imagePrompt || fallbackPrompt
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    if (!draft.imagePrompt.trim()) return alert("請輸入圖片提示詞 (Prompt)");

    const cost = mediaUrl ? 2 : 5;
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI', { prompt: draft.imagePrompt });
    if (!allowed) return;

    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      let url = await generateImage(draft.imagePrompt, user.role, settings.brandStylePrompt);
      if (settings.logoUrl) url = await applyWatermark(url, settings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
    }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;

    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");

        // Calculate Unix Timestamp (Seconds)
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;

        // Facebook Native Scheduling Validation (10 mins to 30 days)
        if (diffMinutes < 10) {
            return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        }
        if (diffMinutes > 30 * 24 * 60) {
            return alert("FB 規定：排程時間不能超過 30 天。");
        }

        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        // Unified Publishing Logic (Both Instant & Scheduled go to FB API)
        const res = await publishPostToFacebook(
            settings.facebookPageId, 
            settings.facebookToken, 
            draft.caption, 
            mediaUrl, 
            draft.firstComment, 
            syncInstagram,
            scheduledUnixTime // Pass timestamp if scheduled
        );

        if (res.success) {
            newPost.publishedUrl = res.url;
            // Even if scheduled, we mark it as successful in our local tracking
            // 'scheduled' status in our DB means "Scheduled on Platform"
            newPost.status = schedule ? 'scheduled' : 'published';

            await onPostCreated(newPost);

            if (schedule) {
                setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
            } else {
                setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
            }
        } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
        }

    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 正在繪製視覺素材..." />;
  if (isPublishing) return <LoadingOverlay message="正在傳送至 Facebook..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-12 animate-fade-in pt-10">
          <div className="text-center space-y-3">
              <h2 className="text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  What's Next?
              </h2>
              <p className="text-gray-400 font-bold tracking-widest uppercase">輸入核心主題，讓 AI 為您打造吸睛內容</p>
          </div>

          <div className="glass-card p-12 rounded-[2rem] shadow-2xl space-y-8 relative overflow-hidden">
              {/* Decorative Glow */}
              <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none"></div>

              <div className="flex p-1.5 bg-black/40 rounded-2xl border border-white/5 relative z-10">
                  <button 
                    onClick={() => setMode('brand')}
                    className={`flex-1 py-4 rounded-xl font-bold tracking-wide transition-all ${mode === 'brand' ? 'bg-primary text-black shadow-[0_0_20px_rgba(0,242,234,0.4)]' : 'text-gray-500 hover:text-white'}`}
                  >
                    品牌模式
                  </button>
                  <button 
                    onClick={() => setMode('viral')}
                    className={`flex-1 py-4 rounded-xl font-bold tracking-wide transition-all ${mode === 'viral' ? 'bg-secondary text-white shadow-[0_0_20px_rgba(255,0,85,0.4)]' : 'text-gray-500 hover:text-white'}`}
                  >
                    爆文模式 (小紅書)
                  </button>
              </div>

              <div className="flex gap-3 relative z-10">
                  <input 
                    value={topic} 
                    onChange={e => setTopic(e.target.value)} 
                    className="flex-1 p-5 rounded-2xl text-xl font-medium placeholder-gray-600 outline-none" 
                    placeholder="輸入主題 (例如：夏季保養、今日新聞...)" 
                  />
                  <button 
                    onClick={loadTrends} 
                    className="bg-gray-800 hover:bg-gray-700 px-8 rounded-2xl text-white font-bold transition-all flex flex-col items-center justify-center gap-1 border border-gray-700 hover:border-white/20"
                  >
                    <span className="text-sm">🔥 挖掘靈感</span>
                    <span className="text-[9px] bg-primary/20 text-primary px-2 rounded-full font-black">1 點數</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader border-t-primary"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-white/5 rounded-2xl bg-black/20 custom-scrollbar relative z-10">
                      {trendingTopics.map((t, i) => (
                          <div 
                            key={i} 
                            onClick={() => setTopic(t.title)} 
                            className={`p-4 rounded-xl cursor-pointer transition-all group backdrop-blur-md ${topic === t.title ? 'bg-primary/20 border-primary border' : 'bg-white/5 border-transparent border hover:border-white/20 hover:bg-white/10'}`}
                          >
                              <h4 className="font-bold text-white text-sm mb-1 line-clamp-1 group-hover:text-primary transition-colors">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button 
                onClick={handleNext} 
                disabled={!topic} 
                className={`w-full py-6 rounded-2xl font-black text-white shadow-2xl hover:opacity-90 transition-all disabled:opacity-30 text-xl tracking-widest uppercase relative z-10 ${mode === 'viral' ? 'bg-gradient-to-r from-orange-600 to-red-600' : 'bg-gradient-to-r from-blue-600 to-primary'}`}
              >
                開始生成內容 <span className="text-sm font-normal opacity-70 ml-2">(2 點數)</span>
              </button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pt-4">
        <div className="space-y-6">
            <div className="glass-card p-8 rounded-3xl relative overflow-hidden">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯器 ({mode === 'viral' ? '爆文模式' : '品牌模式'})</h3>
                    <button onClick={() => setStep(1)} className="text-[10px] font-bold text-red-400 hover:text-white transition-colors uppercase tracking-widest border border-red-500/30 px-2 py-1 rounded">← 重設主題</button>
                </div>

                {/* Caption Editor */}
                <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">貼文文案 (Caption)</label>
                <textarea 
                    value={draft.caption} 
                    onChange={e => setDraft({...draft, caption: e.target.value})} 
