const ScheduleList: React.FC<Props> = ({ posts, onUpdatePosts, onEditPost, settings }) => {
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('list');
  const [isApiLoading, setIsApiLoading] = useState(false);

  const sortedPosts = [...posts].sort((a, b) => b.createdAt - a.createdAt);

  const scheduledPosts = sortedPosts.filter(p => p.status === 'scheduled');
  const historyPosts = sortedPosts.filter(p => p.status !== 'scheduled');

  const extractFbPostId = (post: Post): string | null => {
      if (!post.publishedUrl) return null;
      // Url format usually: https://facebook.com/{POST_ID} or https://facebook.com/{PAGE_ID}/posts/{POST_ID}
      const parts = post.publishedUrl.split('/');
      // Removing empty strings from split
      const validParts = parts.filter(p => p);
      return validParts[validParts.length - 1];
  };

  const handleDelete = async (id: string) => {
    const targetPost = posts.find(p => p.id === id);
    if (!targetPost) return;

    const isNativeScheduled = targetPost.status === 'scheduled' && targetPost.publishedUrl;

    if (confirm(`確定要永久移除此紀錄嗎？${isNativeScheduled ? '\n\n⚠️ 注意：這是一篇「FB 原生排程」貼文，刪除此紀錄將同步刪除 FB 後台的排程。' : ''}`)) {

      // 1. If it's a real FB scheduled post, delete from FB first
      if (isNativeScheduled) {
          if (!settings?.facebookToken) return alert("❌ 錯誤：缺少 Page Token，無法刪除 FB 排程。請先至設定頁面檢查。");

          const fbId = extractFbPostId(targetPost);
          if (fbId) {
              setIsApiLoading(true);
              const res = await deleteFbPost(fbId, settings.facebookToken);
              setIsApiLoading(false);

              if (!res.success) {
                  return alert(`❌ FB 刪除失敗: ${res.error}\n(本地紀錄未刪除)`);
              }
          }
      }

      // 2. Delete Local Record
      const updated = posts.filter(p => p.id !== id);
      onUpdatePosts(updated);
    }
  };

  const handleClearHistory = () => {
    if (confirm('確定要清除所有已發佈或失敗的歷史紀錄嗎？')) {
      const updated = posts.filter(p => p.status === 'scheduled');
      onUpdatePosts(updated);
    }
  };

  // Handler for Calendar Drag-and-Drop
  const handleReschedule = async (post: Post, newDateStr: string) => {
      if (!settings?.facebookToken) throw new Error("缺少 Page Token，無法連線 FB。");

      const fbId = extractFbPostId(post);
      if (!fbId) throw new Error("找不到 FB Post ID (publishedUrl 格式不符)。");

      const newUnix = Math.floor(new Date(newDateStr).getTime() / 1000);

      // Call API
      const res = await reschedulePost(fbId, settings.facebookToken, newUnix);

      if (!res.success) {
          throw new Error(`FB API 拒絕請求: ${res.error}`);
      }

      // Success: Update local state
      const updated = posts.map(p => p.id === post.id ? { ...p, scheduledDate: newDateStr } : p);
      onUpdatePosts(updated);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-10 animate-fade-in pb-10 pt-4 relative">

      {isApiLoading && (
          <div className="absolute inset-0 bg-black/50 z-50 flex items-center justify-center backdrop-blur-sm rounded-xl">
              <div className="text-white font-bold flex flex-col items-center">
                  <div className="loader border-t-red-500 mb-2"></div>
                  同步刪除中...
              </div>
          </div>
      )}

      <div className="flex justify-between items-center border-b border-gray-800 pb-6">
          <h2 className="text-3xl font-black text-white tracking-tighter uppercase">排程管理與歷史</h2>
          <div className="bg-dark/80 border border-gray-800 rounded-xl p-1.5 flex gap-1 shadow-inner">
              <button 
                  onClick={() => setViewMode('list')}
                  className={`px-6 py-2 rounded-lg text-xs font-black tracking-widest uppercase transition-all ${viewMode === 'list' ? 'bg-primary text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
              >
                  列表
              </button>
              <button 
                  onClick={() => setViewMode('calendar')}
                  className={`px-6 py-2 rounded-lg text-xs font-black tracking-widest uppercase transition-all ${viewMode === 'calendar' ? 'bg-primary text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
              >
                  行事曆
              </button>
          </div>
      </div>

      {viewMode === 'calendar' ? (
          <CalendarView 
              posts={posts} 
              onUpdatePosts={onUpdatePosts} 
              onEditPost={onEditPost} 
              onReschedule={handleReschedule}
          />
      ) : (
          <div className="space-y-16">
              <section>
                <div className="flex items-center gap-3 mb-6">
                    <h3 className="text-sm font-black text-blue-400 uppercase tracking-[0.2em]">待發佈任務</h3>
                    <span className="text-[10px] bg-blue-900/30 text-blue-400 px-2 py-0.5 rounded-full border border-blue-500/20 font-black">{scheduledPosts.length}</span>
                </div>

                {scheduledPosts.length === 0 ? (
                    <div className="text-center text-gray-600 py-16 bg-dark/20 rounded-3xl border-2 border-dashed border-gray-800 flex flex-col items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest">目前無待處理的排程貼文</span>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {scheduledPosts.map(post => (
                            <PostItem 
                                key={post.id} 
                                post={post} 
                                onDelete={handleDelete} 
                                onEdit={onEditPost} 
                            />
                        ))}
                    </div>
                )}
              </section>

              <section>
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                        <h3 className="text-sm font-black text-gray-500 uppercase tracking-[0.2em]">歷史發佈紀錄</h3>
                        <span className="text-[10px] bg-gray-800 text-gray-500 px-2 py-0.5 rounded-full border border-gray-700 font-black">{historyPosts.length}</span>
                    </div>
                    {historyPosts.length > 0 && (
                      <button onClick={handleClearHistory} className="text-[10px] font-black text-red-400/60 hover:text-red-400 uppercase tracking-widest transition-colors">
                        清除所有歷史
                      </button>
                    )}
                </div>

                {historyPosts.length === 0 ? (
                    <div className="text-center text-gray-700 py-16 bg-dark/10 rounded-3xl border border-gray-800">
                        <span className="text-[10px] font-black uppercase tracking-widest">尚無歷史紀錄</span>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {historyPosts.map(post => (
                            <PostItem 
                                key={post.id} 
                                post={post} 
                                onDelete={handleDelete} 
                                onEdit={onEditPost} 
                            />
                        ))}
                    </div>
                )}
              </section>
          </div>
      )}
    </div>
  );
};

export default ScheduleList;

import React, { useState, useEffect } from 'react';
import { BrandSettings, AutoReplyRule, AutoPilotConfig, ThreadsAutoPilotConfig } from '../types';
import { api } from '../services/apiClient';
import { getCurrentUser, updateUserSettings } from '../services/authService';

interface Props {
  settings: BrandSettings;
  onSave: (settings: BrandSettings) => void;
}

const AutomationPanel: React.FC<Props> = ({ settings, onSave }) => {
  const [activeTab, setActiveTab] = useState<'autopilot' | 'threads_autopilot' | 'reply'>('autopilot');

  // Auto Reply State
  const [replyEnabled, setReplyEnabled] = useState(settings.autoReply?.enabled || false);
  const [defaultResponse, setDefaultResponse] = useState(settings.autoReply?.defaultResponse || '');
  const [rules, setRules] = useState<AutoReplyRule[]>(settings.autoReply?.rules || []);
  const [newKeyword, setNewKeyword] = useState('');
  const [newResponse, setNewResponse] = useState('');

  // FB Auto Pilot State
  const defaultAutoPilot: AutoPilotConfig = {
      enabled: false,
      frequency: 'daily',
      postWeekDays: [1], 
      postTime: '09:00',
      source: 'trending',
      keywords: [],
      mediaTypePreference: 'image'
  };

  const [apConfig, setApConfig] = useState<AutoPilotConfig>(() => {
      const config = settings.autoPilot || defaultAutoPilot;
      if ((config as any).postWeekDay !== undefined && !config.postWeekDays) {
          config.postWeekDays = [(config as any).postWeekDay];
      }
      if (!config.postWeekDays) config.postWeekDays = [1];
      // Fallback if legacy competitor source exists
      if ((config.source as any) === 'competitor') config.source = 'trending';

      config.mediaTypePreference = 'image';
      return config;
  });

  // Threads Auto Pilot State
  const defaultThreadsAP: ThreadsAutoPilotConfig = {
      enabled: false,
      frequency: 'daily',
      postWeekDays: [1],
      postTime: '10:00',
      imageMode: 'ai_url',
      targetAccountIds: []
  };

  const [threadsApConfig, setThreadsApConfig] = useState<ThreadsAutoPilotConfig>(() => {
      const config = settings.threadsAutoPilot || defaultThreadsAP;
      if (!config.targetAccountIds) {
          config.targetAccountIds = settings.threadsAccounts?.map(a => a.id) || [];
      }
      return config;
  });

  const [newApKeyword, setNewApKeyword] = useState('');
  const [triggering, setTriggering] = useState(false);
  const [triggeringThreads, setTriggeringThreads] = useState(false);

  const weekDays = ['日', '一', '二', '三', '四', '五', '六'];

  const handleSaveSettings = async () => {
    const newSettings = {
      ...settings,
      autoReply: { enabled: replyEnabled, defaultResponse, rules },
      autoPilot: apConfig,
      threadsAutoPilot: threadsApConfig
    };

    // 1. Local Update
    onSave(newSettings);

    // 2. Cloud Sync (For Backend Cron)
    const user = getCurrentUser();
    if (user) {
        await updateUserSettings(user.uid, newSettings);
    }

    alert('設定已儲存！(同步至雲端)');
  };

  const addRule = () => {
    if (newKeyword && newResponse) {
      setRules([...rules, { keyword: newKeyword, response: newResponse }]);
      setNewKeyword('');
      setNewResponse('');
    }
  };

  const removeRule = (index: number) => {
    setRules(rules.filter((_, i) => i !== index));
  };

  // FB Trigger
  const handleTriggerAutoPilot = async () => {
      setTriggering(true);
      try {
          const result = await api.automation.trigger(settings);
          alert(`🚀 FB 任務執行成功！\n主題: ${result.topic}\n狀態: ${result.message}`);
      } catch (e: any) {
          console.error(e);
          alert(`啟動失敗: ${e.message}`);
      } finally {
          setTriggering(false);
      }
  };

  // Threads Trigger
  const handleTriggerThreadsAP = async () => {
      const tempSettings = { ...settings, threadsAutoPilot: threadsApConfig };
      setTriggeringThreads(true);
      try {
          const result = await api.automation.triggerThreads(tempSettings);
          alert(`🚀 Threads 任務執行成功！\n帳號: ${result.targetAccount}\n主題: ${result.topic}\n狀態: ${result.message}`);
      } catch (e: any) {
          console.error(e);
          alert(`啟動失敗: ${e.message}`);
      } finally {
          setTriggeringThreads(false);
      }
  };

  const addApKeyword = () => {
      if (newApKeyword) {
          setApConfig({...apConfig, keywords: [...apConfig.keywords, newApKeyword]});
          setNewApKeyword('');
      }
  };

  const removeApKeyword = (index: number) => {
      setApConfig(prev => ({
          ...prev,
          keywords: prev.keywords.filter((_, i) => i !== index)
      }));
  };

  const toggleWeekDay = (config: any, setConfig: any, dayIndex: number) => {
      const current = config.postWeekDays || [];
      if (current.includes(dayIndex)) {
          if (current.length === 1) return;
          setConfig({...config, postWeekDays: current.filter((d: number) => d !== dayIndex).sort()});
      } else {
          if (current.length >= 6) {
              alert("最多只能選擇 6 天！");
              return;
          }
          setConfig({...config, postWeekDays: [...current, dayIndex].sort()});
      }
  };

  const toggleThreadAccount = (id: string) => {
      const current = threadsApConfig.targetAccountIds || [];
      if (current.includes(id)) {
          setThreadsApConfig({...threadsApConfig, targetAccountIds: current.filter(aid => aid !== id)});
      } else {
          setThreadsApConfig({...threadsApConfig, targetAccountIds: [...current, id]});
      }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-20">
      <h2 className="text-2xl font-bold text-white mb-6">自動化中心</h2>

      {/* Tabs */}
      <div className="flex border-b border-gray-700 mb-6 overflow-x-auto">
        <button 
          onClick={() => setActiveTab('autopilot')}
          className={`px-4 md:px-6 py-3 font-bold transition-colors whitespace-nowrap ${activeTab === 'autopilot' ? 'text-primary border-b-2 border-primary' : 'text-gray-400 hover:text-white'}`}
        >
          Facebook 自動發文
        </button>
        <button 
          onClick={() => setActiveTab('threads_autopilot')}
          className={`px-4 md:px-6 py-3 font-bold transition-colors whitespace-nowrap ${activeTab === 'threads_autopilot' ? 'text-white border-b-2 border-white' : 'text-gray-400 hover:text-white'}`}
        >
          Threads 養號
        </button>
        <button 
          onClick={() => setActiveTab('reply')}
          className={`px-4 md:px-6 py-3 font-bold transition-colors whitespace-nowrap ${activeTab === 'reply' ? 'text-primary border-b-2 border-primary' : 'text-gray-400 hover:text-white'}`}
        >
          Messenger 自動回覆
        </button>
      </div>

      {/* VIEW: FB AUTO PILOT */}
      {activeTab === 'autopilot' && (
          <div className="bg-card p-6 rounded-xl border border-gray-700 space-y-6">
              <div className="flex items-center justify-between border-b border-gray-700 pb-6">
                  <div>
                      <h3 className="text-xl font-bold text-white">Facebook 自動排程</h3>
