                          <select 
                              value={threadsApConfig.imageMode} 
                              onChange={(e) => setThreadsApConfig({...threadsApConfig, imageMode: e.target.value as any})}
                              className="w-full bg-dark border border-gray-600 rounded p-2 text-white"
                          >
                              <option value="ai_url">🎨 AI 生成 (Pollinations) - 推薦</option>
                              <option value="stock_url">📷 圖庫搜尋 (LoremFlickr)</option>
                              <option value="none">❌ 純文字 (無圖片)</option>
                          </select>
                      </div>

                      {/* Targeted Account Selection */}
                      <div className="md:col-span-2">
                          <label className="block text-sm text-gray-400 mb-2">指定養號名單 (多選)</label>
                          <div className="bg-dark p-4 rounded border border-gray-600 max-h-40 overflow-y-auto">
                              {settings.threadsAccounts && settings.threadsAccounts.length > 0 ? (
                                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                                      {settings.threadsAccounts.map(acc => (
                                          <label key={acc.id} className="flex items-center gap-2 p-2 rounded hover:bg-gray-800 cursor-pointer">
                                              <input 
                                                  type="checkbox" 
                                                  checked={threadsApConfig.targetAccountIds?.includes(acc.id)}
                                                  onChange={() => toggleThreadAccount(acc.id)}
                                                  className="w-4 h-4 rounded border-gray-500 text-primary focus:ring-primary bg-gray-900"
                                              />
                                              <span className={`text-sm ${acc.isActive ? 'text-white' : 'text-gray-500'}`}>
                                                  {acc.username}
                                                  {!acc.isActive && <span className="text-[10px] ml-1">(暫停中)</span>}
                                              </span>
                                          </label>
                                      ))}
                                  </div>
                              ) : (
                                  <div className="text-gray-500 text-sm">
                                      目前無帳號。請先至「Threads 養號」頁面新增帳號。
                                  </div>
                              )}
                          </div>
                      </div>
                  </div>
              </div>

              <div className="pt-4 border-t border-gray-700 flex justify-between items-center">
                  <button onClick={handleTriggerThreadsAP} disabled={!threadsApConfig.enabled || triggeringThreads} className="text-yellow-400 border border-yellow-600 px-4 py-2 rounded font-bold text-sm disabled:opacity-50 hover:bg-yellow-900/30">
                        {triggeringThreads ? '執行中...' : '⚡ 手動觸發一次 (扣 1 點)'}
                  </button>
                  <button onClick={handleSaveSettings} className="bg-primary hover:bg-blue-600 text-white px-6 py-2 rounded font-bold">儲存設定</button>
              </div>
          </div>
      )}

      {/* VIEW: REPLY */}
      {activeTab === 'reply' && (
          <div className="bg-card p-6 rounded-xl border border-gray-700 space-y-6">
              <div className="flex items-center justify-between border-b border-gray-700 pb-6">
                  <div>
                      <h3 className="text-xl font-bold text-white">Messenger 自動回覆</h3>
                  </div>
                  <div className="flex items-center gap-3">
                      <span className={`text-sm font-bold ${replyEnabled ? 'text-green-400' : 'text-gray-500'}`}>
                          {replyEnabled ? '已啟用' : '已停用'}
                      </span>
                      <button 
                          onClick={() => setReplyEnabled(!replyEnabled)}
                          className={`w-12 h-6 rounded-full transition-colors relative ${replyEnabled ? 'bg-green-600' : 'bg-gray-600'}`}
                      >
                          <div className={`absolute top-1 left-1 bg-white w-4 h-4 rounded-full transition-transform ${replyEnabled ? 'translate-x-6' : ''}`}></div>
                      </button>
                  </div>
              </div>

              <div>
                  <label className="block text-sm text-gray-400 mb-1">預設回覆</label>
                  <textarea 
                      value={defaultResponse}
                      onChange={e => setDefaultResponse(e.target.value)}
                      placeholder="小編目前不在線上..."
                      className="w-full h-24 bg-dark border border-gray-600 rounded p-3 text-white"
                  />
              </div>

              <div>
                  <label className="block text-sm text-gray-400 mb-2">關鍵字規則</label>
                  <div className="space-y-2 mb-4">
                      {rules.map((rule, i) => (
                          <div key={i} className="flex gap-2 items-start bg-dark p-3 rounded border border-gray-600">
                              <div className="flex-1">
                                  <div className="text-xs text-blue-400 font-bold mb-1">關鍵字: {rule.keyword}</div>
                                  <div className="text-sm text-gray-300">{rule.response}</div>
                              </div>
                              <button onClick={() => removeRule(i)} className="text-red-400 hover:text-red-300">刪除</button>
                          </div>
                      ))}
                  </div>

                  <div className="bg-dark/50 p-4 rounded border border-gray-600">
                      <input 
                          value={newKeyword}
                          onChange={e => setNewKeyword(e.target.value)}
                          placeholder="觸發關鍵字"
                          className="w-full bg-dark border border-gray-600 rounded p-2 text-white mb-2 text-sm"
                      />
                      <textarea 
                          value={newResponse}
                          onChange={e => setNewResponse(e.target.value)}
                          placeholder="回覆內容"
                          className="w-full h-20 bg-dark border border-gray-600 rounded p-2 text-white mb-2 text-sm"
                      />
                      <button onClick={addRule} className="w-full bg-gray-600 hover:bg-gray-500 text-white py-2 rounded text-sm font-bold">新增規則</button>
                  </div>
              </div>

              <div className="pt-4 border-t border-gray-700 flex justify-end">
                  <button onClick={handleSaveSettings} className="bg-primary hover:bg-blue-600 text-white px-6 py-2 rounded font-bold">儲存回覆設定</button>
              </div>
          </div>
      )}
    </div>
  );
};

export default AutomationPanel;

import React, { useState, useEffect } from 'react';
import { 
  getAllUsers, generateAdminKey, 
  getDashboardStats, getSystemLogs, getSystemConfig, updateSystemConfig, 
  getUserReports
} from '../services/authService';
import { getApiServiceStatus } from '../services/geminiService'; // Import new service
import { db, isMock } from '../services/firebase';
import { UserProfile, UserRole, DashboardStats, LogEntry, SystemConfig, UserReport } from '../types';
import { SecurityActionModal } from './admin/SecurityActionModal';
import { ApiMonitor } from './admin/ApiMonitor';
import { UserTable } from './admin/UserTable';

interface Props {
  currentUser: UserProfile;
}

const TAB_NAMES: Record<string, string> = {
    dashboard: '儀表板',
    users: '會員管理',
    keys: '金鑰生成',
    api_monitor: '流量監控',
    reports: '回報單',
    system: '系統設定'
};

const AdminPanel: React.FC<Props> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'users' | 'api_monitor' | 'reports' | 'system' | 'keys'>('dashboard');

  // State
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [reports, setReports] = useState<UserReport[]>([]);
  const [apiUsage, setApiUsage] = useState<any>(null);
  const [apiStatus, setApiStatus] = useState<{ keyStatus: boolean[], hasOpenAI: boolean }>({ keyStatus: [], hasOpenAI: false }); // New State
  const [securityTarget, setSecurityTarget] = useState<{uid: string, type: 'DOWNLOAD'|'DELETE'} | null>(null);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [config, setConfig] = useState<SystemConfig>({ maintenanceMode: false, dryRunMode: false });
  const [generatedKey, setGeneratedKey] = useState('');

  useEffect(() => {
    loadAllData();
  }, []);

  useEffect(() => {
      if (activeTab === 'api_monitor') {
          loadApiUsage();
          const timer = setInterval(loadApiUsage, 5000);
          return () => clearInterval(timer);
      }
  }, [activeTab]);

  const loadAllData = async () => {
    setStats(await getDashboardStats());
    setUsers(await getAllUsers());
    setLogs(getSystemLogs());
    setConfig(getSystemConfig());
    setReports(await getUserReports());
  };

  const loadApiUsage = async () => {
      // Load Key Status
      const statusData = await getApiServiceStatus();
      setApiStatus(statusData);

      if (isMock) {
          setApiUsage({ key_1: 1250, key_2: 890, key_3: 450, key_4: 120, key_5: 5, total_calls: 2715 });
          return;
      }
      try {
          const doc = await db.collection('system_stats').doc('api_usage').get();
          if (doc.exists) setApiUsage(doc.data());
      } catch (e) { console.error("Load API Usage failed", e); }
  };

  const handleGenerateKey = async (type: 'RESET_QUOTA' | 'UPGRADE_ROLE', role?: UserRole) => {
    const key = await generateAdminKey(currentUser.user_id, type, role);
    setGeneratedKey(key);
    loadAllData();
  };

  const handleGenerateFeatureKey = async (feature: 'ANALYTICS' | 'AUTOMATION' | 'SEO' | 'THREADS') => {
    const key = await generateAdminKey(currentUser.user_id, 'UNLOCK_FEATURE', undefined, feature);
    setGeneratedKey(key);
    loadAllData();
  };

  const toggleDryRun = () => { updateSystemConfig({ dryRunMode: !config.dryRunMode }); loadAllData(); };
  const toggleMaintenance = () => { updateSystemConfig({ maintenanceMode: !config.maintenanceMode }); loadAllData(); };

  return (
    <div className="max-w-7xl mx-auto p-4 space-y-6 animate-fade-in pb-20">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold text-white">管理員中控台</h2>
        <div className="flex gap-2">
           {config.dryRunMode && <span className="px-3 py-1 bg-yellow-600 text-white rounded-full text-xs font-bold animate-pulse">模擬模式 (Dry Run) 開啟</span>}
           {config.maintenanceMode && <span className="px-3 py-1 bg-red-600 text-white rounded-full text-xs font-bold animate-pulse">維護模式開啟</span>}
        </div>
      </div>

      <div className="flex border-b border-gray-700 overflow-x-auto">
        {Object.keys(TAB_NAMES).map(tabKey => (
            <button 
                key={tabKey} 
                onClick={() => setActiveTab(tabKey as any)} 
                className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === tabKey ? 'text-primary border-b-2 border-primary' : 'text-gray-400 hover:text-white'}`}
            >
                {TAB_NAMES[tabKey]}
            </button>
        ))}
      </div>

      {activeTab === 'dashboard' && stats && (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="bg-card p-6 rounded-xl border border-gray-700"><p className="text-gray-400 text-sm">總會員數</p><p className="text-3xl font-bold text-white mt-2">{stats.totalUsers}</p></div>
                <div className="bg-card p-6 rounded-xl border border-gray-700"><p className="text-gray-400 text-sm">今日活躍用戶 (DAU)</p><p className="text-3xl font-bold text-green-400 mt-2">{stats.activeUsersToday}</p></div>
                <div className="bg-card p-6 rounded-xl border border-gray-700"><p className="text-gray-400 text-sm">今日 API 使用量</p><p className="text-3xl font-bold text-blue-400 mt-2">{stats.totalApiCallsToday}</p></div>
                <div className="bg-card p-6 rounded-xl border border-gray-700"><p className="text-gray-400 text-sm">待處理回報</p><p className="text-3xl font-bold text-red-400 mt-2">{reports.filter(r => r.status === 'OPEN').length}</p></div>
            </div>
        </div>
      )}

      {activeTab === 'keys' && (
          <div className="bg-card p-6 rounded-xl border border-gray-700">
              <h3 className="text-xl font-bold text-white mb-4">🔑 生成管理金鑰 (Admin Key)</h3>
              <div className="mb-6">
                  <p className="text-xs text-gray-400 mb-2 uppercase tracking-wider font-bold">配額與角色升級</p>
                  <div className="flex flex-wrap gap-2">
                       <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'starter')} className="bg-green-700 hover:bg-green-600 text-white px-4 py-2 rounded font-bold">Starter Key</button>
                       <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'pro')} className="bg-purple-700 hover:bg-purple-600 text-white px-4 py-2 rounded font-bold">Pro Key</button>
                       <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'business')} className="bg-yellow-700 hover:bg-yellow-600 text-white px-4 py-2 rounded font-bold">Business Key</button>
                       <button onClick={() => handleGenerateKey('RESET_QUOTA')} className="bg-gray-700 hover:bg-gray-600 text-white px-4 py-2 rounded font-bold">Reset Quota Key</button>
                  </div>
              </div>
              <div>
                  <p className="text-xs text-gray-400 mb-2 uppercase tracking-wider font-bold">單項功能解鎖</p>
                  <div className="flex flex-wrap gap-2">
                       {['ANALYTICS', 'AUTOMATION', 'SEO', 'THREADS'].map(f => (
                           <button key={f} onClick={() => handleGenerateFeatureKey(f as any)} className="bg-blue-900/50 border border-blue-600 hover:bg-blue-900 text-blue-200 px-4 py-2 rounded font-bold text-sm">解鎖: {f}</button>
                       ))}
                  </div>
              </div>
              {generatedKey && <div className="mt-6 p-4 bg-black/30 border border-green-500 rounded text-center"><p className="text-green-400 font-bold mb-2">✅ 金鑰生成成功！請複製 (24小時內有效)：</p><p className="text-2xl font-mono text-white select-all tracking-wider">{generatedKey}</p></div>}
          </div>
      )}

      {/* Pass apiStatus to Monitor */}
      {activeTab === 'api_monitor' && <ApiMonitor apiUsage={apiUsage} apiStatus={apiStatus} />}

      {activeTab === 'users' && <UserTable users={users} onRefresh={loadAllData} onSecurityAction={(uid, type) => setSecurityTarget({uid, type})} />}

      {activeTab === 'reports' && (
          <div className="bg-card p-6 rounded-xl border border-gray-700">
              <div className="flex justify-between items-center mb-4"><h3 className="text-xl font-bold text-white">🚨 用戶問題回報 ({reports.length})</h3><button onClick={loadAllData} className="text-sm text-primary hover:underline">刷新</button></div>
              {reports.length === 0 ? <div className="text-center py-10 text-gray-500 border border-dashed border-gray-700 rounded">目前無待處理的回報單。</div> : (
                  <div className="space-y-4">
                      {reports.map((report) => (
                          <div key={report.id} className="bg-dark p-4 rounded border border-gray-600">
                              <div className="flex justify-between items-start mb-2"><div><span className="font-bold text-white">{report.userEmail}</span><span className="text-xs text-gray-500 ml-2">{new Date(report.timestamp).toLocaleString()}</span></div><span className="text-xs bg-red-900 text-red-200 px-2 py-1 rounded">{report.status}</span></div>
                              <div className="bg-gray-800 p-3 rounded text-sm text-gray-200 mb-2">{report.description}</div>
                              <div className="text-xs text-gray-500 font-mono break-all bg-black/20 p-2 rounded"><div>View: {report.currentView}</div><div>UA: {report.userAgent}</div></div>
                          </div>
                      ))}
                  </div>
              )}
          </div>
      )}

      {activeTab === 'system' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="space-y-6">
                  <div className="bg-card p-6 rounded-xl border border-gray-700">
                      <h3 className="text-xl font-bold text-white mb-4">🔧 系統全域設定</h3>
                      <div className="space-y-4">
