    </div>
);

const ScheduleList: React.FC<Props> = ({ posts, onUpdatePosts, onEditPost, settings }) => {
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('list');
  const [isApiLoading, setIsApiLoading] = useState(false);

  const sortedPosts = [...posts].sort((a, b) => b.createdAt - a.createdAt);

  const scheduledPosts = sortedPosts.filter(p => p.status === 'scheduled');
  const historyPosts = sortedPosts.filter(p => p.status !== 'scheduled');

  const extractFbPostId = (post: Post): string | null => {
      if (!post.publishedUrl) return null;
      // Url format usually: https://facebook.com/{POST_ID} or https://facebook.com/{PAGE_ID}/posts/{POST_ID}
      const parts = post.publishedUrl.split('/');
      // Removing empty strings from split
      const validParts = parts.filter(p => p);
      return validParts[validParts.length - 1];
  };

  const handleDelete = async (id: string) => {
    const targetPost = posts.find(p => p.id === id);
    if (!targetPost) return;

    const isNativeScheduled = targetPost.status === 'scheduled' && targetPost.publishedUrl;

    if (confirm(`確定要永久移除此紀錄嗎？${isNativeScheduled ? '\n\n⚠️ 注意：這是一篇「FB 原生排程」貼文，刪除此紀錄將同步刪除 FB 後台的排程。' : ''}`)) {

      // 1. If it's a real FB scheduled post, delete from FB first
      if (isNativeScheduled) {
          if (!settings?.facebookToken) return alert("❌ 錯誤：缺少 Page Token，無法刪除 FB 排程。請先至設定頁面檢查。");

          const fbId = extractFbPostId(targetPost);
          if (fbId) {
              setIsApiLoading(true);
              const res = await deleteFbPost(fbId, settings.facebookToken);
              setIsApiLoading(false);

              if (!res.success) {
                  return alert(`❌ FB 刪除失敗: ${res.error}\n(本地紀錄未刪除)`);
              }
          }
      }

      // 2. Delete Local Record
      const updated = posts.filter(p => p.id !== id);
      onUpdatePosts(updated);
    }
  };

  const handleClearHistory = () => {
    if (confirm('確定要清除所有已發佈或失敗的歷史紀錄嗎？')) {
      const updated = posts.filter(p => p.status === 'scheduled');
      onUpdatePosts(updated);
    }
  };

  // Handler for Calendar Drag-and-Drop
  const handleReschedule = async (post: Post, newDateStr: string) => {
      if (!settings?.facebookToken) throw new Error("缺少 Page Token，無法連線 FB。");

      const fbId = extractFbPostId(post);
      if (!fbId) throw new Error("找不到 FB Post ID (publishedUrl 格式不符)。");

      const newUnix = Math.floor(new Date(newDateStr).getTime() / 1000);

      // Call API
      const res = await reschedulePost(fbId, settings.facebookToken, newUnix);

      if (!res.success) {
          throw new Error(`FB API 拒絕請求: ${res.error}`);
      }

      // Success: Update local state
      const updated = posts.map(p => p.id === post.id ? { ...p, scheduledDate: newDateStr } : p);
      onUpdatePosts(updated);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-10 animate-fade-in pb-10 pt-4 relative">

      {isApiLoading && (
          <div className="absolute inset-0 bg-black/50 z-50 flex items-center justify-center backdrop-blur-sm rounded-xl">
              <div className="text-white font-bold flex flex-col items-center">
                  <div className="loader border-t-red-500 mb-2"></div>
                  同步刪除中...
              </div>
          </div>
      )}

      {/* RESPONSIVE CHANGE: Stack header contents on mobile */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-gray-800 pb-6">
          <h2 className="text-3xl font-black text-white tracking-tighter uppercase">排程管理與歷史</h2>
          <div className="bg-dark/80 border border-gray-800 rounded-xl p-1.5 flex gap-1 shadow-inner w-full md:w-auto">
              <button 
                  onClick={() => setViewMode('list')}
                  className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black tracking-widest uppercase transition-all ${viewMode === 'list' ? 'bg-primary text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
              >
                  列表
              </button>
              <button 
                  onClick={() => setViewMode('calendar')}
                  className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black tracking-widest uppercase transition-all ${viewMode === 'calendar' ? 'bg-primary text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
              >
                  行事曆
              </button>
          </div>
      </div>

      {viewMode === 'calendar' ? (
          <CalendarView 
              posts={posts} 
              onUpdatePosts={onUpdatePosts} 
              onEditPost={onEditPost} 
              onReschedule={handleReschedule}
          />
      ) : (
          <div className="space-y-16">
              <section>
                <div className="flex items-center gap-3 mb-6">
                    <h3 className="text-sm font-black text-blue-400 uppercase tracking-[0.2em]">待發佈任務</h3>
                    <span className="text-[10px] bg-blue-900/30 text-blue-400 px-2 py-0.5 rounded-full border border-blue-500/20 font-black">{scheduledPosts.length}</span>
                </div>

                {scheduledPosts.length === 0 ? (
                    <div className="text-center text-gray-600 py-16 bg-dark/20 rounded-3xl border-2 border-dashed border-gray-800 flex flex-col items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest">目前無待處理的排程貼文</span>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {scheduledPosts.map(post => (
                            <PostItem 
                                key={post.id} 
                                post={post} 
                                onDelete={handleDelete} 
                                onEdit={onEditPost} 
                            />
                        ))}
                    </div>
                )}
              </section>

              <section>
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                        <h3 className="text-sm font-black text-gray-500 uppercase tracking-[0.2em]">歷史發佈紀錄</h3>
                        <span className="text-[10px] bg-gray-800 text-gray-500 px-2 py-0.5 rounded-full border border-gray-700 font-black">{historyPosts.length}</span>
                    </div>
                    {historyPosts.length > 0 && (
                      <button onClick={handleClearHistory} className="text-[10px] font-black text-red-400/60 hover:text-red-400 uppercase tracking-widest transition-colors">
                        清除所有歷史
                      </button>
                    )}
                </div>

                {historyPosts.length === 0 ? (
                    <div className="text-center text-gray-700 py-16 bg-dark/10 rounded-3xl border border-gray-800">
                        <span className="text-[10px] font-black uppercase tracking-widest">尚無歷史紀錄</span>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {historyPosts.map(post => (
                            <PostItem 
                                key={post.id} 
                                post={post} 
                                onDelete={handleDelete} 
                                onEdit={onEditPost} 
                            />
                        ))}
                    </div>
                )}
              </section>
          </div>
      )}
    </div>
  );
};

export default ScheduleList;

import React, { useState, useEffect } from 'react';
import { BrandSettings, ReferenceFile } from '../types';
import { validateFacebookToken, fetchRecentPostCaptions } from '../services/facebookService';
import { analyzeBrandTone } from '../services/geminiService';
import { getCurrentUser, updateUserSettings } from '../services/authService';
import { initFacebookSdk, loginAndGetPages, FacebookPage } from '../services/facebookAuth';
import TokenTutorialModal from './TokenTutorialModal';

interface Props {
  onSave: (settings: BrandSettings) => void;
  initialSettings: BrandSettings;
}

interface BrandProfile {
    id: string;
    name: string;
    settings: BrandSettings;
}

const SettingsForm: React.FC<Props> = ({ onSave, initialSettings }) => {
  const [profiles, setProfiles] = useState<BrandProfile[]>([]);
  const [currentProfileId, setCurrentProfileId] = useState<string>('default');
  const [formData, setFormData] = useState<BrandSettings>(initialSettings);

  const [tokenStatus, setTokenStatus] = useState<'idle' | 'checking' | 'valid' | 'invalid' | 'partial'>('idle');
  const [missingPerms, setMissingPerms] = useState<string[]>([]);
  const [validationError, setValidationError] = useState('');
  const [debugData, setDebugData] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [isAnalyzingTone, setIsAnalyzingTone] = useState(false);
  const [showTutorial, setShowTutorial] = useState(false);

  // OAuth State
  const [fbAppId, setFbAppId] = useState((import.meta as any).env?.VITE_FB_APP_ID || '');
  const [isSdkReady, setIsSdkReady] = useState(false);
  const [availablePages, setAvailablePages] = useState<FacebookPage[]>([]);
  const [showPageSelector, setShowPageSelector] = useState(false);
  const [oauthError, setOauthError] = useState<{ msg: string; link?: string } | null>(null);

  useEffect(() => {
      // Load Profiles
      const savedProfiles = localStorage.getItem('autosocial_brand_profiles');
      if (savedProfiles) {
          const parsed = JSON.parse(savedProfiles);
          setProfiles(parsed);
          const lastId = localStorage.getItem('autosocial_last_profile_id');
          if (lastId && parsed.find((p: any) => p.id === lastId)) {
              setCurrentProfileId(lastId);
              const target = parsed.find((p: any) => p.id === lastId);
              if(target) loadSettingsIntoForm(target.settings);
          } else if (parsed.length > 0) {
              setCurrentProfileId(parsed[0].id);
              loadSettingsIntoForm(parsed[0].settings);
          }
      } else {
          const defaultProfile = { id: 'default', name: initialSettings.industry || '預設品牌', settings: initialSettings };
          setProfiles([defaultProfile]);
          setCurrentProfileId('default');
          loadSettingsIntoForm(initialSettings);
      }

      // Initialize FB SDK
      if (fbAppId) {
          initFacebookSdk(fbAppId).then(() => setIsSdkReady(true)).catch(e => console.error("FB Init Failed", e));
      }
  }, []);

  const loadSettingsIntoForm = (settings: BrandSettings) => {
      setFormData({
          ...initialSettings,
          ...settings,
          referenceFiles: settings.referenceFiles || []
      });
      setTokenStatus('idle');
      setValidationError('');
      setMissingPerms([]);
      setDebugData(null);
  };

  useEffect(() => {
      if (profiles.length > 0) localStorage.setItem('autosocial_brand_profiles', JSON.stringify(profiles));
  }, [profiles]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (name === 'facebookToken') {
        setTokenStatus('idle');
        setValidationError('');
        setDebugData(null);
    }
  };

  const handleConnectFacebook = async () => {
      setOauthError(null);
      if (!fbAppId) {
          alert("系統錯誤：開發者未設定 Facebook App ID。請在環境變數中設定 VITE_FB_APP_ID。");
          return;
      }

      try {
          const pages = await loginAndGetPages();
          if (pages.length === 0) {
              setOauthError({ msg: "連結成功，但您的帳號下沒有可管理的粉絲專頁 (或權限不足)。" });
          } else {
              setAvailablePages(pages);
              setShowPageSelector(true);
          }
      } catch (e: any) {
          const msg = e.message || '';
          console.error("Auth Error", msg);

          const currentOrigin = window.location.origin + '/';

          // Detect common configuration errors including Chinese error messages
          if (msg.includes('JSSDK') || msg.includes('JavaScript SDK') || msg.includes('未切換至開啟')) {
              setOauthError({ 
                  msg: "設定錯誤：JSSDK 未啟用。請至 Meta 後台「Facebook 登入 > 設定」將「使用 JavaScript SDK 登入」設為「是」。",
                  link: `https://developers.facebook.com/apps/${fbAppId}/fb-login/settings/`
              });
          } else if (msg.includes('URL Blocked') || msg.includes('App not setup') || msg.includes('domain')) {
               setOauthError({ 
                  msg: `網域未授權：請至 Meta 後台「Facebook 登入 > 設定」確認「允許的 JavaScript SDK 網域」已填寫：${currentOrigin}`,
                  link: `https://developers.facebook.com/apps/${fbAppId}/fb-login/settings/`
              });
          } else {
              setOauthError({ msg: `連結失敗: ${msg}` });
          }
      }
  };

  const handleSelectPage = (page: FacebookPage) => {
      setFormData(prev => ({
          ...prev,
          facebookPageId: page.id,
          facebookToken: page.access_token,
          industry: prev.industry || page.category || '' // Auto-fill category if empty
      }));
      setShowPageSelector(false);

      // Auto Validate
      setTimeout(() => checkToken(page.access_token), 500);
  };

  const checkToken = async (tokenOverride?: string) => {
    const tokenToCheck = tokenOverride || formData.facebookToken;
    if (!tokenToCheck) {
        setValidationError('請先填寫 Token');
        setTokenStatus('invalid');
        return;
    }

    setTokenStatus('checking');
    setValidationError('');
    setMissingPerms([]);
    setDebugData(null);

    try {
        const res = await validateFacebookToken(tokenToCheck);
        if (res.valid) {
            setTokenStatus(res.status === 'VALID' ? 'valid' : 'partial');
            setMissingPerms(res.missingPermissions);
            setDebugData(res.debugInfo);
        } else {
            setTokenStatus('invalid');
            setValidationError(res.error || 'Token 無效');
            setDebugData(res.debugInfo);
        }
    } catch (e: any) {
        setTokenStatus('invalid');
        setValidationError(e.message || '發生錯誤');
    }
  };

  const handleAutoAnalyzeStyle = async () => {
      if (!formData.facebookPageId || !formData.facebookToken) {
          alert("請先填寫並驗證 Facebook Page ID 與 Token");
          return;
      }
      setIsAnalyzingTone(true);
      try {
          const posts = await fetchRecentPostCaptions(formData.facebookPageId, formData.facebookToken, 15);
          if (posts.length < 3) throw new Error("貼文數量過少，無法有效分析 (至少需要 3 篇)。");
          const styleGuide = await analyzeBrandTone(posts);
          setFormData(prev => ({ ...prev, brandStyleGuide: styleGuide }));
          alert("✅ 分析完成！已更新「品牌風格指南」。");
      } catch (e: any) {
          alert(`分析失敗: ${e.message}`);
      } finally {
          setIsAnalyzingTone(false);
      }
  };

  const handleRefFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const text = await file.text();
      const newFile: ReferenceFile = { name: file.name, content: text };
      setFormData(prev => ({ ...prev, referenceFiles: [...(prev.referenceFiles || []), newFile] }));
  };

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file && file.size < 500000) {
          const reader = new FileReader();
          reader.onload = (ev) => setFormData(p => ({ ...p, logoUrl: ev.target?.result as string }));
          reader.readAsDataURL(file);
      } else alert("檔案過大（上限 500KB）");
  };

  const handleSaveWrapper = async () => {
      setIsSaving(true);
      try {
          const updatedProfiles = profiles.map(p => p.id === currentProfileId ? { ...p, settings: formData } : p);
          setProfiles(updatedProfiles);
          onSave(formData);
          const user = getCurrentUser();
          if (user) await updateUserSettings(user.uid, formData);
          alert("設定已儲存");
      } catch (e) {
          alert("儲存失敗");
      } finally {
          setIsSaving(false);
      }
  };

  return (
    <div className="max-w-5xl mx-auto p-6 bg-card rounded-xl border border-gray-700 animate-fade-in pb-24">
      {/* Header & Profile Switcher */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8 border-b border-gray-700 pb-4">
          <div className="flex flex-col w-full md:w-auto">
              <label className="text-xs text-gray-500 mb-1 font-bold">當前品牌身份</label>
              <select 
                value={currentProfileId} 
                onChange={(e) => {
                    const target = profiles.find(p => p.id === e.target.value);
                    if (target) { 
                        setCurrentProfileId(e.target.value); 
                        loadSettingsIntoForm(target.settings); 
                        localStorage.setItem('autosocial_last_profile_id', e.target.value);
                    }
                }} 
                className="bg-dark border border-primary rounded p-2 text-white font-bold text-xl outline-none w-full"
              >
                  {profiles.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
          </div>
          <button onClick={() => {
              const name = prompt("請輸入新品牌名稱:");
              if (name) {
                  const id = 'brand_' + Date.now();
                  const newProfiles = [...profiles, { id, name, settings: initialSettings }];
                  setProfiles(newProfiles);
                  setCurrentProfileId(id); 
                  loadSettingsIntoForm(initialSettings);
              }
          }} className="bg-green-700 hover:bg-green-600 text-white px-4 py-2 rounded text-sm transition-colors w-full md:w-auto">+ 新增品牌</button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: API Connection */}
        <div className="lg:col-span-1 space-y-6 border-r-0 lg:border-r border-gray-800 pr-0 lg:pr-4">
          <h3 className="text-lg font-bold text-primary border-l-4 border-primary pl-3">1. API 連結設定</h3>

          {/* OAuth Button */}
          <div className={`p-4 rounded-xl border ${fbAppId ? 'bg-blue-900/20 border-blue-800/50' : 'bg-red-900/20 border-red-800/50'}`}>
              <button 
                  onClick={handleConnectFacebook}
                  disabled={!fbAppId}
                  className={`w-full text-white py-3 rounded-lg font-bold shadow-lg flex items-center justify-center gap-2 transition-transform active:scale-95 ${fbAppId ? 'bg-[#1877F2] hover:bg-[#166fe5]' : 'bg-gray-600 cursor-not-allowed opacity-50'}`}
              >
                  <svg className="w-5 h-5 fill-current" viewBox="0 0 24 24"><path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z"/></svg>
                  {fbAppId ? '快速連結 (推薦)' : '系統未設定 App ID'}
              </button>
              {fbAppId ? (
                  <p className="text-[10px] text-blue-200 mt-2 text-center">自動獲取永久 Token，免去手動複製困擾。</p>
              ) : (
                  <p className="text-[10px] text-red-300 mt-2 text-center font-bold">請開發者於環境變數設定 VITE_FB_APP_ID</p>
              )}
              {oauthError && (
                  <div className="mt-3 p-3 bg-red-950 border border-red-500 rounded text-xs text-red-200 shadow-xl">
                      <p className="mb-2 font-bold flex items-center gap-2">⚠️ 連線錯誤</p>
                      <p className="mb-3 leading-relaxed break-all">{oauthError.msg}</p>
                      {oauthError.link && (
                          <a 
                              href={oauthError.link} 
                              target="_blank" 
                              rel="noreferrer" 
                              className="block text-center bg-white text-red-900 hover:bg-gray-200 py-2 rounded font-bold transition-colors"
                          >
                              👉 點此前往後台修正
                          </a>
                      )}
                  </div>
              )}
          </div>

          <div className="relative">
              <div className="absolute inset-0 flex items-center" aria-hidden="true">
                  <div className="w-full border-t border-gray-700"></div>
              </div>
              <div className="relative flex justify-center">
                  <span className="bg-card px-2 text-xs text-gray-500">OR 手動輸入</span>
              </div>
          </div>

          <div>
            <label className="block text-sm text-gray-400 mb-1">Facebook 粉絲專頁 ID</label>
            <input name="facebookPageId" value={formData.facebookPageId || ''} onChange={handleChange} className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-sm font-mono" placeholder="Page ID" />
