                                  </div>
                              )}
                          </div>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* VIEW: GENERATOR (Simplified Layout for brevity) */}
      {activeTab === 'generator' && (
          <div className="space-y-6">
              {genStep === 1 && (
                  <div className="bg-card p-6 rounded-xl border border-gray-700">
                       <h3 className="text-xl font-bold text-white mb-4">步驟 1: 選擇話題</h3>

