// Role Quota Definition
const getQuotaForRole = (role: UserRole): number => {
  switch (role) {
    case 'user': return 10;
    case 'starter': return 500;
    case 'pro': return 2500;
    case 'business': return 10000;
    case 'admin': return 99999;
    default: return 10;
  }
};

