const getIndustryLogic = (industry: string): string => {
    // Basic keyword matching
    const lower = industry.toLowerCase();
    if (lower.includes('food') || lower.includes('餐廳') || lower.includes('美食')) return 'Food photography, macro shot, steam rising, appetizing, shallow depth of field, delicious textures.';
    if (lower.includes('beauty') || lower.includes('美妝') || lower.includes('skincare')) return 'Beauty editorial, soft skin texture, water droplets, pastel tones, purity, spa atmosphere.';
    if (lower.includes('tech') || lower.includes('3c') || lower.includes('電子')) return 'Product rendering, studio lighting, sharp details, exploded view, modern gadget.';
    if (lower.includes('travel') || lower.includes('旅遊')) return 'Wide angle scenic shot, adventure, wanderlust, travel photography, iconic landmarks.';
    if (lower.includes('fashion') || lower.includes('服飾')) return 'Fashion lookbook, model pose, street style, fabric texture details, trendy outfit.';
    return 'Commercial photography, high quality.';
};

const getIntentLogic = (intent: ImageIntent): string => {
    switch (intent) {
        case 'product_showcase': return 'Focus on the product in the center. Clean studio background. Sharp focus on product details. "Hero shot" composition.';
        case 'promotion': return 'Layout designed for an ad banner. Leave 30% empty negative space on the right side for text overlay. Eye-catching background but not distracting.';
        case 'lifestyle': return 'Candid shot of people using the product in real life. Authentic emotion. Natural lighting. Not posed.';
        case 'educational': return 'Infographic style layout. Clean flat lay composition. Knolling photography. Organized items.';
        case 'festival': return 'Festive atmosphere. Holiday decorations. Celebration vibe. Sparkles and confetti elements.';
        default: return '';
    }
};

export const buildCommercialImagePrompt = (
    subject: string,
    settings: BrandSettings,
    intent: ImageIntent,
    userRole: string
): string => {
    const styleKeywords = getStyleKeywords(settings.visualStyle);
    const industryKeywords = getIndustryLogic(settings.industry);
    const intentKeywords = getIntentLogic(intent);

    // Color Logic
    let colorInstruction = '';
    if (settings.brandColors && settings.brandColors.length > 0) {
        colorInstruction = `Dominant Color Palette: ${settings.brandColors.join(', ')}. Use these colors for background, lighting, or accents to maintain brand consistency.`;
    }

    // Brand Name Injection (For Ideogram mainly, or advanced models)
    let textInstruction = '';
    if (settings.brandName) {
        // Only ask for text if the intent warrants it, otherwise it might look messy on basic models
        if (intent === 'product_showcase' || intent === 'promotion') {
            textInstruction = `Visible Text: "${settings.brandName}" integrated naturally on the product or background sign. Typography should match the ${settings.visualStyle} style.`;
        }
    }

    // Assembly
    // We construct a structured prompt optimized for modern diffusion models (Flux/Ideogram/Imagen 3)
    return `
    [Subject]: ${subject}
    [Industry Context]: ${industryKeywords}
    [Design Style]: ${styleKeywords}
    [Layout/Intent]: ${intentKeywords}
    [Brand Colors]: ${colorInstruction}
    ${textInstruction}

    [Technical Specs]: 8k resolution, highly detailed, commercial quality, no artifacts, perfect composition.
    `;
};

