  };

  useEffect(() => {
      if (profiles.length > 0) localStorage.setItem('autosocial_brand_profiles', JSON.stringify(profiles));
  }, [profiles]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (name === 'facebookToken') {
        setTokenStatus('idle');
        setValidationError('');
        setDebugData(null);
    }
  };

  const handleColorChange = (index: number, value: string) => {
      const newColors = [...(formData.brandColors || ['#000000', '#ffffff', '#cccccc'])];
      newColors[index] = value;
      setFormData(prev => ({ ...prev, brandColors: newColors }));
  };

  const handleConnectFacebook = async () => {
      // ... (Existing OAuth Logic)
      setOauthError(null);
      if (!fbAppId) {
          alert("系統錯誤：開發者未設定 Facebook App ID。請在環境變數中設定 VITE_FB_APP_ID。");
          return;
      }

      try {
          const pages = await loginAndGetPages();
          if (pages.length === 0) {
              setOauthError({ msg: "連結成功，但您的帳號下沒有可管理的粉絲專頁 (或權限不足)。" });
          } else {
              setAvailablePages(pages);
              setShowPageSelector(true);
          }
      } catch (e: any) {
          const msg = e.message || '';
          console.error("Auth Error", msg);
          // ... error handling
      }
  };

  const handleSelectPage = (page: FacebookPage) => {
      setFormData(prev => ({
          ...prev,
          facebookPageId: page.id,
          facebookToken: page.access_token,
          // industry: prev.industry || page.category || '' 
      }));
      setShowPageSelector(false);
      setTimeout(() => checkToken(page.access_token), 500);
  };

  const checkToken = async (tokenOverride?: string) => {
    const tokenToCheck = tokenOverride || formData.facebookToken;
    if (!tokenToCheck) {
        setValidationError('請先填寫 Token');
        setTokenStatus('invalid');
        return;
    }
    setTokenStatus('checking');
    try {
        const res = await validateFacebookToken(tokenToCheck);
        if (res.valid) {
            setTokenStatus(res.status === 'VALID' ? 'valid' : 'partial');
            setMissingPerms(res.missingPermissions);
            setDebugData(res.debugInfo);
        } else {
            setTokenStatus('invalid');
            setValidationError(res.error || 'Token 無效');
        }
    } catch (e: any) {
        setTokenStatus('invalid');
        setValidationError(e.message || '發生錯誤');
    }
  };

  const handleAutoAnalyzeStyle = async () => {
      if (!formData.facebookPageId || !formData.facebookToken) {
          alert("請先填寫並驗證 Facebook Page ID 與 Token");
          return;
      }
      setIsAnalyzingTone(true);
      try {
          const posts = await fetchRecentPostCaptions(formData.facebookPageId, formData.facebookToken, 15);
          if (posts.length < 3) throw new Error("貼文數量過少，無法有效分析 (至少需要 3 篇)。");
          const styleGuide = await analyzeBrandTone(posts);
          setFormData(prev => ({ ...prev, brandStyleGuide: styleGuide }));
          alert("✅ 分析完成！已更新「品牌風格指南」。");
      } catch (e: any) {
          alert(`分析失敗: ${e.message}`);
      } finally {
          setIsAnalyzingTone(false);
      }
  };

  const handleRefFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const text = await file.text();
      const newFile: ReferenceFile = { name: file.name, content: text };
      setFormData(prev => ({ ...prev, referenceFiles: [...(prev.referenceFiles || []), newFile] }));
  };

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file && file.size < 500000) {
          const reader = new FileReader();
          reader.onload = (ev) => setFormData(p => ({ ...p, logoUrl: ev.target?.result as string }));
          reader.readAsDataURL(file);
      } else alert("檔案過大（上限 500KB）");
  };

  const handleSaveWrapper = async () => {
      setIsSaving(true);
      try {
          const updatedProfiles = profiles.map(p => p.id === currentProfileId ? { ...p, settings: formData } : p);
          setProfiles(updatedProfiles);
          onSave(formData);
          const user = getCurrentUser();
          if (user) await updateUserSettings(user.uid, formData);
          alert("設定已儲存");
      } catch (e) {
          alert("儲存失敗");
      } finally {
          setIsSaving(false);
      }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 bg-card rounded-xl border border-gray-700 animate-fade-in pb-24">
      {/* Header & Profile Switcher */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8 border-b border-gray-700 pb-4">
          <div className="flex flex-col w-full md:w-auto">
              <label className="text-xs text-gray-500 mb-1 font-bold">當前品牌身份</label>
              <select 
                value={currentProfileId} 
                onChange={(e) => {
                    const target = profiles.find(p => p.id === e.target.value);
                    if (target) { 
                        setCurrentProfileId(e.target.value); 
                        loadSettingsIntoForm(target.settings); 
                        localStorage.setItem('autosocial_last_profile_id', e.target.value);
                    }
                }} 
                className="bg-dark border border-primary rounded p-2 text-white font-bold text-xl outline-none w-full"
              >
                  {profiles.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
          </div>
          <button onClick={() => {
              const name = prompt("請輸入新品牌名稱:");
              if (name) {
                  const id = 'brand_' + Date.now();
                  const newProfiles = [...profiles, { id, name, settings: initialSettings }];
                  setProfiles(newProfiles);
                  setCurrentProfileId(id); 
                  loadSettingsIntoForm(initialSettings);
              }
          }} className="bg-green-700 hover:bg-green-600 text-white px-4 py-2 rounded text-sm transition-colors w-full md:w-auto">+ 新增品牌</button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: API & Basic Info */}
        <div className="lg:col-span-1 space-y-6 border-r-0 lg:border-r border-gray-800 pr-0 lg:pr-4">
          <h3 className="text-lg font-bold text-primary border-l-4 border-primary pl-3">1. 帳號與基本資料</h3>

          {/* OAuth Button (Simplified for Brevity) */}
          <div className="p-4 rounded-xl border bg-blue-900/20 border-blue-800/50">
              <button 
                  onClick={handleConnectFacebook}
                  disabled={!fbAppId}
                  className={`w-full text-white py-3 rounded-lg font-bold shadow-lg flex items-center justify-center gap-2 ${fbAppId ? 'bg-[#1877F2]' : 'bg-gray-600'}`}
              >
                  {fbAppId ? '連結 Facebook 粉專' : '未設定 App ID'}
              </button>
              {tokenStatus === 'valid' && <p className="text-[10px] text-green-400 mt-2 text-center">✅ 已連線: {debugData?.name}</p>}
          </div>

          <div>
            <label className="block text-sm text-gray-400 mb-1">品牌名稱 (Brand Name)</label>
            <input name="brandName" value={formData.brandName || ''} onChange={handleChange} className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-sm" placeholder="例如：星巴克" />
          </div>

          <div>
            <label className="block text-sm text-gray-400 mb-1">產業類別 (Industry)</label>
            <select name="industry" value={formData.industry || ''} onChange={handleChange} className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-sm">
                <option value="" disabled>請選擇...</option>
                {INDUSTRIES.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                <option value="other">其他 (自填)</option>
            </select>
          </div>

          <div>
            <label className="block text-sm text-gray-400 mb-1">目標受眾 (Audience)</label>
            <textarea name="targetAudience" value={formData.targetAudience || ''} onChange={handleChange} className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-sm h-20" placeholder="例如：20-35歲都會女性，喜愛旅遊與美食..." />
          </div>
        </div>

        {/* Middle Column: Visual Identity (NEW) */}
        <div className="lg:col-span-1 space-y-6">
          <h3 className="text-lg font-bold text-pink-500 border-l-4 border-pink-500 pl-3">2. 品牌視覺識別 (VI)</h3>
          <p className="text-xs text-gray-400">設定後，AI 將生成符合品牌色調與風格的商業設計圖。</p>

          {/* Color Palette */}
          <div>
              <label className="block text-sm text-gray-400 mb-2">品牌色票 (Color Palette)</label>
              <div className="flex gap-4 items-center">
                  {(formData.brandColors || ['#000000', '#ffffff', '#cccccc']).map((color, idx) => (
                      <div key={idx} className="flex flex-col items-center gap-1">
                          <div className="w-12 h-12 rounded-full overflow-hidden border-2 border-white/20 shadow-lg relative cursor-pointer hover:scale-110 transition-transform">
                              <input 
                                  type="color" 
                                  value={color} 
                                  onChange={(e) => handleColorChange(idx, e.target.value)}
                                  className="absolute -top-2 -left-2 w-20 h-20 cursor-pointer p-0 border-0"
                              />
                          </div>
                          <span className="text-[10px] font-mono text-gray-500">{color}</span>
                          <span className="text-[9px] text-gray-600 font-bold">{idx === 0 ? '主色' : idx === 1 ? '輔色' : '強調色'}</span>
                      </div>
                  ))}
              </div>
          </div>

          {/* Visual Style Selector */}
          <div>
              <label className="block text-sm text-gray-400 mb-2">視覺風格偏好</label>
              <div className="grid grid-cols-2 gap-2 max-h-60 overflow-y-auto custom-scrollbar pr-1">
                  {STYLE_OPTIONS.map(style => (
                      <div 
                          key={style.id} 
                          onClick={() => setFormData(prev => ({ ...prev, visualStyle: style.id }))}
                          className={`p-3 rounded-lg border cursor-pointer transition-all relative overflow-hidden ${formData.visualStyle === style.id ? 'bg-pink-900/30 border-pink-500 shadow-[0_0_15px_rgba(236,72,153,0.3)]' : 'bg-dark border-gray-700 hover:border-gray-500'}`}
                      >
                          <div className="flex items-center gap-2 mb-1">
                              <span className="text-xl">{style.icon}</span>
                              <span className={`font-bold text-sm ${formData.visualStyle === style.id ? 'text-pink-400' : 'text-gray-300'}`}>{style.label}</span>
                          </div>
                          <p className="text-[10px] text-gray-500 leading-tight">{style.desc}</p>
                      </div>
                  ))}
              </div>
          </div>

          <div><label className="block text-sm text-gray-400 mb-1">Logo 浮水印</label><div className="flex items-center gap-4">{formData.logoUrl && <img src={formData.logoUrl} className="w-12 h-12 object-contain bg-black/20 rounded border border-gray-700" alt="Logo" />}<input type="file" accept="image/*" onChange={handleLogoUpload} className="text-[10px] text-gray-500" /></div></div>
        </div>

        {/* Right Column: Text Strategy */}
        <div className="lg:col-span-1 space-y-6 border-l-0 lg:border-l border-gray-800 pl-0 lg:pl-4">
          <h3 className="text-lg font-bold text-primary border-l-4 border-primary pl-3">3. 文案策略</h3>

          <div className="bg-gradient-to-br from-indigo-900/30 to-purple-900/30 p-4 rounded-xl border border-indigo-500/30">
              <div className="flex justify-between items-center mb-2">
                  <label className="text-sm font-bold text-indigo-200">🔮 語氣風格指南</label>
                  <button onClick={handleAutoAnalyzeStyle} disabled={isAnalyzingTone} className="text-xs bg-indigo-600 hover:bg-indigo-500 text-white px-2 py-1 rounded shadow-lg transition-colors disabled:opacity-50">
                      {isAnalyzingTone ? '分析中...' : '一鍵分析過往貼文'}
                  </button>
              </div>
              <textarea name="brandStyleGuide" value={formData.brandStyleGuide || ''} onChange={handleChange} className="w-full bg-dark/80 border border-indigo-500/30 rounded p-2 text-gray-300 text-xs h-32 leading-relaxed" placeholder="AI 自動分析結果..." />
          </div>

          <div><label className="block text-sm text-gray-400 mb-1">服務/產品詳情</label><textarea name="services" value={formData.services || ''} onChange={handleChange} className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-xs h-20" placeholder="主要販售內容..." /></div>
          <div><label className="block text-sm text-gray-400 mb-1">固定 Hashtags</label><input name="fixedHashtags" value={formData.fixedHashtags || ''} onChange={handleChange} className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-xs" placeholder="#品牌名 #產品" /></div>
        </div>
      </div>

      <div className="mt-12 flex justify-end border-t border-gray-700 pt-6">
        <button onClick={handleSaveWrapper} disabled={isSaving} className="bg-primary hover:bg-blue-600 text-white px-12 py-3 rounded-lg font-bold shadow-lg transform transition-all active:scale-95 disabled:opacity-50 w-full md:w-auto">{isSaving ? '儲存中...' : '儲存品牌設定'}</button>
      </div>

      {showTutorial && <TokenTutorialModal platform="facebook" onClose={() => setShowTutorial(false)} />}

      {/* Page Selector Modal */}
      {showPageSelector && (
          <div className="fixed inset-0 bg-black/90 flex items-center justify-center z-[300] animate-fade-in p-4">
              <div className="bg-card p-6 rounded-xl border border-gray-600 max-w-md w-full relative shadow-2xl">
                  <button onClick={() => setShowPageSelector(false)} className="absolute top-4 right-4 text-gray-400 hover:text-white">✕</button>
                  <h3 className="text-xl font-bold text-white mb-4">請選擇要管理的粉絲專頁</h3>
                  <div className="max-h-[60vh] overflow-y-auto custom-scrollbar space-y-2">
                      {availablePages.map(page => (
                          <button 
                              key={page.id} 
                              onClick={() => handleSelectPage(page)}
                              className="w-full text-left p-4 bg-dark border border-gray-700 rounded-lg hover:bg-gray-800 hover:border-primary transition-all group"
                          >
                              <div className="font-bold text-white group-hover:text-primary">{page.name}</div>
                              <div className="text-xs text-gray-500 flex justify-between mt-1">
                                  <span>ID: {page.id}</span>
                                  <span>{page.category || 'Page'}</span>
                              </div>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default SettingsForm;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ImageIntent } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string }> = ({ message }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">AI Processing...</p>
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle'); // NEW

  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");
      const allowed = await checkAndUseQuota(user.user_id, 3, 'TREND_SEARCH'); 
      if (!allowed) return; 
      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);
          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, 10, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);
            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: res.imagePrompt || `Professional commercial photo of ${topic}` 
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: res.imagePrompt || ''
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    if (!draft.imagePrompt.trim()) return alert("請輸入圖片提示詞 (Prompt)");

    const cost = mediaUrl ? 1 : 3; 
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI', { prompt: draft.imagePrompt });
    if (!allowed) return;

    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      // Use new generateImage with Settings & Intent
      let url = await generateImage(draft.imagePrompt, user.role, settings, imageIntent);
      if (settings.logoUrl) url = await applyWatermark(url, settings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
    }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;
        if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        const res = await publishPostToFacebook(
            settings.facebookPageId, 
            settings.facebookToken, 
            draft.caption, 
            mediaUrl, 
            draft.firstComment, 
            syncInstagram,
            scheduledUnixTime
        );

        if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = schedule ? 'scheduled' : 'published';
            await onPostCreated(newPost);

            if (schedule) setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
            else setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
        } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
        }

    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 設計師正在繪製商業圖..." />;
  if (isPublishing) return <LoadingOverlay message="正在傳送至 Facebook..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 md:space-y-12 animate-fade-in pt-4 md:pt-10">
          <div className="text-center space-y-3">
              <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  What's Next?
              </h2>
              <p className="text-gray-400 font-bold tracking-widest uppercase text-xs md:text-base">輸入核心主題，讓 AI 為您打造吸睛內容</p>
          </div>

          <div className="glass-card p-6 md:p-12 rounded-[2rem] shadow-2xl space-y-6 md:space-y-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none"></div>

              <div className="flex p-1.5 bg-black/40 rounded-2xl border border-white/5 relative z-10">
