      {showKeyModal && userProfile && <KeyRedemptionModal user={userProfile} onClose={() => setShowKeyModal(false)} onSuccess={refreshProfile} />}
    </div>
  );
};

export default App;

module.exports = async function (req, res) {
  // CORS Headers
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader(
    'Access-Control-Allow-Headers',
    'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version'
  );

  if (req.method === 'OPTIONS') {
    res.status(200).end();
    return;
  }

  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  if (!req.body) {
      return res.status(400).json({ error: 'Missing Request Body' });
  }

  // --- Key Manager & Load Balancing ---
  class KeyManager {
      constructor() {
          this.geminiKeys = [
              process.env.API_KEY,
              process.env.API_KEY_2,
              process.env.API_KEY_3,
              process.env.API_KEY_4,
              process.env.API_KEY_5
          ].filter(k => k && k.length > 0 && k !== 'undefined'); 

          this.openAIKey = process.env.OPENAI_API_KEY;

          // New: Commercial Keys
          this.ideogramKeys = [
              process.env.IDEOGRAM_API_KEY,
              process.env.IDEOGRAM_API_KEY_2
          ].filter(k => k && k.length > 0 && k !== 'undefined');

          this.grokKey = process.env.GROK_API_KEY;

          this.currentIndex = this.geminiKeys.length > 0 
              ? Math.floor(Math.random() * this.geminiKeys.length) 
              : 0;
      }

      getCurrentKey() {
          if (this.geminiKeys.length === 0) return null;
          return this.geminiKeys[this.currentIndex];
      }

      getIdeogramKey() {
          if (this.ideogramKeys.length === 0) return null;
          // Random Load Balancing for Ideogram
          return this.ideogramKeys[Math.floor(Math.random() * this.ideogramKeys.length)];
      }

      getGrokKey() { return this.grokKey; }
      getOpenAIKey() { return this.openAIKey; }

      getKeyConfigStatus() {
          return [
              !!(process.env.API_KEY && process.env.API_KEY !== 'undefined'),
              !!(process.env.API_KEY_2 && process.env.API_KEY_2 !== 'undefined'),
              !!(process.env.IDEOGRAM_API_KEY && process.env.IDEOGRAM_API_KEY !== 'undefined'),
              !!(process.env.IDEOGRAM_API_KEY_2 && process.env.IDEOGRAM_API_KEY_2 !== 'undefined'),
              !!(process.env.GROK_API_KEY && process.env.GROK_API_KEY !== 'undefined')
          ];
      }

      switchToNextKey() {
          if (this.geminiKeys.length > 1) {
              const oldIndex = this.currentIndex;
              this.currentIndex = (this.currentIndex + 1) % this.geminiKeys.length;
              console.warn(`[KeyManager] ⚠️ Switching Gemini Key: Slot ${oldIndex + 1} -> Slot ${this.currentIndex + 1}`);
              return true;
          }
          return false;
      }
  }

  const keyManager = new KeyManager();
  const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

  // --- PROVIDER IMPLEMENTATIONS ---

  // 1. Ideogram V2 (Priority 1)
  async function generateIdeogramImage(prompt) {
      const apiKey = keyManager.getIdeogramKey();
      if (!apiKey) return null; // Not configured, skip

      console.log("[Image Gen] Attempting with Ideogram V2...");

      // Ideogram requires explicit aspect ratio strings
      // We default to 1:1 or 10:16 based on prompt keywords if needed, but let's stick to 1:1 for now or 9:16 for stories
      // Detect layout intent from prompt
      let ar = "ASPECT_1_1";
      if (prompt.includes("16:9")) ar = "ASPECT_16_9";
      if (prompt.includes("9:16")) ar = "ASPECT_9_16";

      const response = await fetch("https://api.ideogram.ai/generate", {
          method: "POST",
          headers: {
              "Api-Key": apiKey,
              "Content-Type": "application/json"
          },
          body: JSON.stringify({
              image_request: {
                  prompt: prompt,
                  aspect_ratio: ar,
                  model: "V_2",
                  magic_prompt_option: "AUTO" 
              }
          })
      });

      if (!response.ok) {
          const err = await response.text();
          throw new Error(`Ideogram Error: ${response.status} - ${err}`);
      }

      const data = await response.json();
      const imageUrl = data.data?.[0]?.url;
      if (!imageUrl) throw new Error("Ideogram returned no image URL");

      // Proxy image to Base64 to avoid hotlink/CORS issues on client
      const imgRes = await fetch(imageUrl);
      const arrayBuffer = await imgRes.arrayBuffer();
      return Buffer.from(arrayBuffer).toString('base64');
  }

  // 2. Grok / xAI (Priority 3 - Backup 2)
  async function generateGrokImage(prompt) {
      const apiKey = keyManager.getGrokKey();
      if (!apiKey) return null;

      console.log("[Image Gen] Attempting with Grok (xAI)...");

      // Note: xAI API structure for images might mirror OpenAI or be specific.
      // Assuming OpenAI compatible endpoint for Flux/Grok-Vision if available.
      // If not standard yet, this serves as a placeholder for when they enable it via API.
      const response = await fetch("https://api.x.ai/v1/images/generations", {
          method: "POST",
          headers: {
              "Authorization": `Bearer ${apiKey}`,
              "Content-Type": "application/json"
          },
          body: JSON.stringify({
              prompt: prompt,
              model: "grok-beta", // or flux
              n: 1,
              size: "1024x1024",
              response_format: "b64_json"
          })
      });

      if (!response.ok) {
          // Fail silently to fallback
          const err = await response.text();
          console.warn("Grok Gen Failed:", err);
          throw new Error(`Grok Error: ${err}`);
      }

      const data = await response.json();
      return data.data?.[0]?.b64_json;
  }

  // 3. OpenAI DALL-E 3 (Ultimate Fallback)
  async function generateOpenAIImage(prompt) {
      const apiKey = keyManager.getOpenAIKey();
      if (!apiKey) return null;

      console.log("[Image Gen] Attempting with OpenAI DALL-E 3...");
      const response = await fetch("https://api.openai.com/v1/images/generations", {
          method: "POST",
          headers: {
              "Content-Type": "application/json",
              "Authorization": `Bearer ${apiKey}`
          },
          body: JSON.stringify({
              model: "dall-e-3",
              prompt: prompt,
              n: 1,
              size: "1024x1024",
              response_format: "b64_json"
          })
      });

      const data = await response.json();
      if (data.error) throw new Error(`OpenAI Error: ${data.error.message}`);
      return data.data[0].b64_json;
  }

  // Helper: Gemini Retry Logic
  async function executeWithRetry(operation, retryCount = 0, keysTried = 1) {
      if (!keyManager.getCurrentKey()) throw new Error("API_KEY missing");
      try {
          // Dynamic Import SDK
          let GoogleGenAI;
          try {
              const sdk = await import("@google/genai");
              GoogleGenAI = sdk.GoogleGenAI;
          } catch (e) { throw new Error(`SDK Load Failed: ${e.message}`); }

          const ai = new GoogleGenAI({ apiKey: keyManager.getCurrentKey() });
          return await operation(ai);
      } catch (error) {
          const msg = error.message || '';
          console.warn(`[Gemini Error Slot ${keyManager.getCurrentKeySlotIndex()}] ${msg}`);
          const isQuotaError = msg.includes('429') || msg.includes('Quota') || msg.includes('exhausted') || msg.includes('503');

          if (isQuotaError && keysTried < keyManager.geminiKeys.length) {
              keyManager.switchToNextKey();
              return executeWithRetry(operation, 0, keysTried + 1);
          }
          throw error;
      }
  }

  // --- REQUEST HANDLER ---

  try {
    const { action, payload } = req.body;
    if (!action) return res.status(400).json({ error: "Missing 'action'" });

    // --- Action: getServiceStatus ---
    if (action === 'getServiceStatus') {
        const status = keyManager.getKeyConfigStatus();
        return res.status(200).json({ 
            keyStatus: status,
            totalConfigured: status.filter(s => s).length,
            hasOpenAI: !!keyManager.getOpenAIKey()
        });
    }

    // --- Action: fetchRss ---
    if (action === 'fetchRss') {
        const { url } = payload;
        const rssRes = await fetch(url);
        return res.status(200).json({ text: await rssRes.text() });
    }

    // --- Action: fetchOgImage ---
    if (action === 'fetchOgImage') {
        const { url } = payload;
        const htmlRes = await fetch(url, { headers: { 'User-Agent': 'Bot' } });
        const html = await htmlRes.text();
        const match = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i);
        return res.status(200).json({ imageUrl: match ? match[1] : null });
    }

    // --- Action: generateContent (Text) ---
    if (action === 'generateContent') {
      const { model, contents, config } = payload;
      const result = await executeWithRetry(async (ai) => {
          const response = await ai.models.generateContent({ model, contents, config });
          return { text: response.text };
      });
      return res.status(200).json(result);
    }

    // --- Action: generateImages (COMMERCIAL WATERFALL) ---
    if (action === 'generateImages') {
      const { prompt, safetySettings } = payload;

      // PRIORITY 1: IDEOGRAM
      try {
          const ideogramB64 = await generateIdeogramImage(prompt);
          if (ideogramB64) {
              return res.status(200).json({ base64: ideogramB64, provider: 'ideogram' });
          }
      } catch (e) {
          console.warn("[Waterfall] Ideogram failed, trying next...", e.message);
      }

      // PRIORITY 2: GEMINI (Imagen 3)
      try {
          const geminiResult = await executeWithRetry(async (ai) => {
              console.log("[Waterfall] Attempting Imagen 3...");
              const response = await ai.models.generateImages({
                  model: 'imagen-3.0-generate-002',
                  prompt: prompt,
                  config: { numberOfImages: 1, aspectRatio: "1:1", safetySettings }
              });
              const bytes = response.generatedImages?.[0]?.image?.imageBytes;
              if (!bytes) throw new Error("No bytes from Imagen");
              return { base64: bytes, provider: 'imagen-3' };
          });
          return res.status(200).json(geminiResult);
      } catch (geminiError) {
          console.warn("[Waterfall] Imagen 3 failed:", geminiError.message);

          // Fallback inside Gemini: Try Flash Image if Imagen 3 fails
          try {
              const flashResult = await executeWithRetry(async (ai) => {
                  console.log("[Waterfall] Fallback to Gemini Flash Image...");
                  const response = await ai.models.generateContent({
                      model: 'gemini-2.5-flash-image',
                      contents: { parts: [{ text: prompt }] }
                  });
                  const bytes = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
                  if (!bytes) throw new Error("No data from Flash Image");
                  return { base64: bytes, provider: 'gemini-flash' };
              });
              return res.status(200).json(flashResult);
          } catch (flashError) {
              console.warn("[Waterfall] Gemini Flash failed:", flashError.message);
          }
      }

      // PRIORITY 3: GROK / xAI
      try {
          const grokB64 = await generateGrokImage(prompt);
          if (grokB64) {
              return res.status(200).json({ base64: grokB64, provider: 'grok' });
          }
      } catch (e) {
          console.warn("[Waterfall] Grok failed:", e.message);
      }

      // PRIORITY 4: OPENAI (Last Resort)
      try {
          const openAIB64 = await generateOpenAIImage(prompt);
          if (openAIB64) {
              return res.status(200).json({ base64: openAIB64, provider: 'openai' });
          }
      } catch (e) {
          console.warn("[Waterfall] OpenAI failed:", e.message);
      }

      // If all fail
      return res.status(500).json({ error: "All image providers failed." });
    }

    // --- Action: generateVideos ---
    if (action === 'generateVideos') {
       const { model, prompt, config } = payload;
       const result = await executeWithRetry(async (ai) => {
           let operation = await ai.models.generateVideos({ model, prompt, config });
           let attempts = 0;
           while (!operation.done && attempts < 20) { 
               await delay(3000);
               operation = await ai.operations.getVideosOperation({ operation: operation });
               attempts++;
           }
           if (!operation.done) throw new Error("Video timeout");
           const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
           if (!uri) throw new Error("No URI");

           const vidRes = await fetch(`${uri}&key=${keyManager.getCurrentKey()}`);
           const buf = await vidRes.arrayBuffer();
           return { videoBase64: Buffer.from(buf).toString('base64') };
       });
       return res.status(200).json(result);
    }

    return res.status(400).json({ error: `Unknown action: ${action}` });

  } catch (error) {
    console.error('[API Error]:', error);
    return res.status(500).json({ error: error.message || 'Server Error' });
  }
};

import { callBackend } from './core';
import { BrandSettings, ImageIntent } from '../../types';
import { buildCommercialImagePrompt } from '../promptTemplates';

const ensureEnglishPrompt = async (prompt: string): Promise<string> => {
    if (/^[\x00-\x7F]*$/.test(prompt)) return prompt;
    try {
        const response = await callBackend('generateContent', {
            model: 'gemini-2.5-flash',
            contents: `Translate to descriptive English image prompt: "${prompt}". Output ONLY string.`
        });
        return response.text.trim();
    } catch (e) { return prompt; }
};

export const generateImage = async (
    prompt: string, 
    userRole: string = 'user', 
    settings?: BrandSettings, 
    intent: ImageIntent = 'lifestyle'
): Promise<string> => {
    const noLimitTrigger = /no limit/i.test(prompt);
    let basePrompt = prompt.replace(/no limit/ig, '').trim();

    // 1. Construct the Commercial Design Prompt
    let finalPrompt = "";
    if (settings) {
        const englishSubject = await ensureEnglishPrompt(basePrompt);
        finalPrompt = buildCommercialImagePrompt(englishSubject, settings, intent, userRole);
    } else {
        finalPrompt = await ensureEnglishPrompt(basePrompt);
        finalPrompt += ", photorealistic, cinematic lighting, photography style";
    }

    console.log("🎨 [Commercial Design Prompt]", finalPrompt);

    // 2. Select Engine
    // 'pro', 'business', 'admin' -> Priority: Backend Waterfall (Ideogram -> Imagen -> Grok)
    // 'user', 'starter' -> Frontend Economy Mode (Pollinations)

    const isProTier = ['pro', 'business', 'admin'].includes(userRole);

    if (!isProTier) {
         console.log("🎨 [ImageGen] Economy Mode: Pollinations");
         return `https://image.pollinations.ai/prompt/${encodeURIComponent(finalPrompt)}?n=${Math.floor(Math.random()*100000)}&model=flux&enhance=true`;
    }

    try {
        console.log(`🎨 [ImageGen] Pro Mode: calling Backend Waterfall`);
        const safetySettings = noLimitTrigger ? [{ category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' }] : undefined;

        // We call 'generateImages'. The backend now handles the waterfall (Ideogram -> Imagen -> Grok).
        // We don't specify model here to let backend decide based on keys.
        const response = await callBackend('generateImages', { 
