            contents: userMessage,
            config: { 
                systemInstruction: systemPrompt,
                maxOutputTokens: 300 // Keep replies concise
            }
        });
        return response.text || "小幫手目前在休息中，請稍後再試 😊";
    } catch (e) {
        return "連線稍微有點不穩定，請您檢查網路或稍後再試喔！🙏";
    }
};

