                        )}
                    </div>

                    {/* Quick Chips */}
                    <div className="p-3 bg-gray-900/50 border-t border-gray-800 overflow-x-auto whitespace-nowrap custom-scrollbar">
                        <div className="flex gap-2">
                            {QUICK_QUESTIONS.map((q, i) => (
                                <button 
