export const register = async (email: string, pass: string) => {
    if (!isMock) {
        const cred = await auth.createUserWithEmailAndPassword(email, pass);
        await createUserProfile({ uid: cred.user!.uid, email: email });
        await checkAndRestoreAdmin(cred.user!.uid, email);
        return { user: cred.user };
    } 

    const uid = 'user_' + Date.now();
    await createUserProfile({ uid, email });
    localStorage.setItem(SESSION_KEY, uid);
    window.dispatchEvent(new Event('auth_state_change'));
    return { user: { uid, email } };
};

export const logout = async () => {
    if (!isMock) await auth.signOut();
    else {
        localStorage.removeItem(SESSION_KEY);
        window.dispatchEvent(new Event('auth_state_change'));
    }
};

export const subscribeAuth = (callback: (user: { uid: string, email: string } | null) => void) => {
    if (!isMock) {
        return auth.onAuthStateChanged(async (firebaseUser: any) => {
            if (firebaseUser) {
                const profile = await getUserProfile(firebaseUser.uid);
                if (profile && profile.isSuspended) {
                    await logout();
                    callback(null);
                } else {
                    callback({ uid: firebaseUser.uid, email: firebaseUser.email || '' });
                }
            } else {
                callback(null);
            }
        });
    }

    const check = () => {
         const uid = localStorage.getItem(SESSION_KEY);
         if(uid) {
             const u = MockStore.getUser(uid);
             const email = u ? u.email : 'demo@example.com';
             callback({ uid, email });
         } else {
             callback(null);
         }
    };

    if (typeof window !== 'undefined') {
        window.addEventListener('auth_state_change', check);
        setTimeout(check, 0); 
    }
    return () => {
        if (typeof window !== 'undefined') window.removeEventListener('auth_state_change', check);
    };
};

export const sendPasswordReset = async (email: string) => {
    if (!isMock) await auth.sendPasswordResetEmail(email);
    else console.log(`[Mock] Password reset sent to ${email}`);
};

/**
 * Exchange Threads OAuth Code for Long-Lived Token via Backend
 */
export const exchangeThreadsAuth = async (code: string, clientId: string, clientSecret: string, redirectUri: string) => {
    if (isMock) {
        return { 
            token: 'mock_threads_long_token_' + Date.now(), 
            userId: 'mock_user_123',
            username: 'mock_threads_user'
        };
    }

    const user = getCurrentUser();
    if (!user) throw new Error("Authentication required for token exchange");

    const token = await user.getIdToken();

    const res = await fetch('/api/auth/threads/exchange', {
        method: 'POST',
        headers: { 
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ code, clientId, clientSecret, redirectUri })
    });

    const data = await res.json();
    if (!data.success) {
        throw new Error(data.error?.message || 'Token exchange failed');
    }
    return data.data;
};

import { Request, Response, NextFunction } from 'express';
import { ResponseBuilder } from '../../core/apiResponse';
import { MembershipService } from '../membership/membership.service';

export class AuthController {
  static async getMe(req: Request, res: Response, next: NextFunction) {
    try {
      const uid = (req as any).user.uid;
      // In real scenario, we'd inject service
      const db = new MembershipService(); 
      // Simplified: assume we get user data
      ResponseBuilder.success(res, { uid, message: "User Profile" });
    } catch (err) {
      next(err);
    }
  }

  static async exchangeThreads(req: Request, res: Response, next: NextFunction) {
    try {
        const { code, clientId, clientSecret, redirectUri } = req.body;

        if (!code || !clientId || !clientSecret || !redirectUri) {
            return ResponseBuilder.error(res, "Missing parameters", 'AUTH_002' as any, 400);
        }

        // 1. Exchange Code for Short Token
        const params = new URLSearchParams();
        params.append('client_id', clientId);
        params.append('client_secret', clientSecret);
        params.append('grant_type', 'authorization_code');
        params.append('redirect_uri', redirectUri);
        params.append('code', code);

        const tokenRes = await fetch('https://graph.threads.net/oauth/access_token', {
            method: 'POST',
            body: params
        });

        const tokenData = await tokenRes.json();
        if (tokenData.error) {
            throw new Error(`Meta API Error (Step 1): ${tokenData.error.message}`);
        }

        const shortToken = tokenData.access_token;
        const userId = tokenData.user_id;

        // 2. Exchange for Long Token
        const longTokenUrl = `https://graph.threads.net/access_token?grant_type=th_exchange_token&client_secret=${clientSecret}&access_token=${shortToken}`;
        const longRes = await fetch(longTokenUrl);
        const longData = await longRes.json();

        if (longData.error) {
             throw new Error(`Meta API Error (Step 2): ${longData.error.message}`);
        }

        const longToken = longData.access_token;

        // 3. Get Username (Optional, but good for UI)
        let username = 'Unknown';
        try {
            const userRes = await fetch(`https://graph.threads.net/v1.0/me?fields=id,username,name&access_token=${longToken}`);
            const userData = await userRes.json();
            if (userData.username) username = userData.username;
        } catch (e) {
            console.warn("Failed to fetch username", e);
        }

        ResponseBuilder.success(res, {
            token: longToken,
            userId: userId,
            username: username
        });

    } catch(e: any) {
        next(e);
    }
  }
}

