                        className="w-full bg-black border border-pink-600 hover:bg-pink-900/30 text-white px-6 py-2 rounded font-bold shadow-lg transition-all flex items-center justify-center gap-2 h-[40px]"
                    >
                        🔗 連接 Threads (OAuth)
                    </button>

                    <p className="text-[10px] text-gray-500 mt-2 text-center">
                        * 請確保 Meta App 設定中的 Redirect URI 包含本網站網址。
                        <br/>
                        * 開發模式下，僅 App 開發者或測試者帳號可登入。
                    </p>
                </div>
            </section>
        </form>
    </div>
  );
};

