export const login = async (email: string, pass: string) => {
    // 1. Mock Admin Backdoor
    if (isMock && email === 'ricky22407@gmail.com' && pass === 'testautosocial1106') {
         const uid = 'demo_admin';
         if (!MockStore.getUser(uid)) {
             MockStore.saveUser({ 
