                                    />
                                    <input 
                                        value={color}
                                        onChange={e => {
                                            const newColors = [...formData.brandColors];
                                            newColors[index] = e.target.value;
                                            handleChange('brandColors', newColors);
                                        }}
                                        className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-xs"
                                    />
