                        </div>
                        {formData.logoUrl && (
                            <div className="mt-2 p-2 bg-white/10 rounded inline-block">
                                <img src={formData.logoUrl} alt="Logo Preview" className="h-8 object-contain" />
                            </div>
                        )}
