                <div className="mt-4 pt-4 border-t border-gray-700">
                    <div className="flex justify-between items-center mb-4">
                        <label className="block text-sm text-gray-300 font-bold">品牌語氣指南 (AI Analyzed Tone)</label>
                        <button 
