export default SettingsForm;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ImageIntent } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string }> = ({ message }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">AI Processing...</p>
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle'); // NEW

  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");

      // [BILLING LOGIC] Pay-Per-Click Enforced
      // Deduct points BEFORE any service call or cache check.
      // Even if the result comes from cache (0 cost for us), the user pays for the "Search" action.
      const COST = 3; 
      const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH'); 
      if (!allowed) return; 

      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);
          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！(扣除 ${COST} 點)`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, 10, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);
            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: res.imagePrompt || `Professional commercial photo of ${topic}` 
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: res.imagePrompt || ''
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    if (!draft.imagePrompt.trim()) return alert("請輸入圖片提示詞 (Prompt)");

    // Pricing Update: Regen 1->2, New 3->5
    const cost = mediaUrl ? 2 : 5; 
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI', { prompt: draft.imagePrompt });
    if (!allowed) return;

    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      // Use new generateImage with Settings & Intent
      let url = await generateImage(draft.imagePrompt, user.role, settings, imageIntent);
      if (settings.logoUrl) url = await applyWatermark(url, settings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
    }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;
        if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        const res = await publishPostToFacebook(
            settings.facebookPageId, 
            settings.facebookToken, 
            draft.caption, 
            mediaUrl, 
            draft.firstComment, 
            syncInstagram,
            scheduledUnixTime
        );

        if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = schedule ? 'scheduled' : 'published';
            await onPostCreated(newPost);

            if (schedule) setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
            else setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
        } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
        }

    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  // Keep the overlay for initial generation, but button logic below handles regeneration
  if (isGeneratingMedia) return <LoadingOverlay message="AI 設計師正在繪製商業圖..." />;
  if (isPublishing) return <LoadingOverlay message="正在傳送至 Facebook..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 md:space-y-12 animate-fade-in pt-4 md:pt-10">
          <div className="text-center space-y-3">
              <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  What's Next?
              </h2>
              <p className="text-gray-400 font-bold tracking-widest uppercase text-xs md:text-base">輸入核心主題，讓 AI 為您打造吸睛內容</p>
          </div>

          <div className="glass-card p-6 md:p-12 rounded-[2rem] shadow-2xl space-y-6 md:space-y-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none"></div>

              <div className="flex p-1.5 bg-black/40 rounded-2xl border border-white/5 relative z-10">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'brand' ? 'bg-primary text-black shadow-[0_0_20px_rgba(0,242,234,0.4)]' : 'text-gray-500 hover:text-white'}`}>品牌模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'viral' ? 'bg-secondary text-white shadow-[0_0_20px_rgba(255,0,85,0.4)]' : 'text-gray-500 hover:text-white'}`}>爆文模式 (小紅書)</button>
              </div>

              <div className="flex flex-col md:flex-row gap-3 relative z-10">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 p-4 md:p-5 rounded-2xl text-lg md:text-xl font-medium placeholder-gray-600 outline-none w-full" placeholder="輸入主題 (例如：夏季保養、今日新聞...)" />
                  <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 px-8 py-4 md:py-0 rounded-2xl text-white font-bold transition-all flex flex-row md:flex-col items-center justify-center gap-2 md:gap-1 border border-gray-700 hover:border-white/20 whitespace-nowrap">
                    <span className="text-sm">🔥 挖掘靈感</span><span className="text-[9px] bg-primary/20 text-primary px-2 rounded-full font-black">3 點數</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader border-t-primary"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-white/5 rounded-2xl bg-black/20 custom-scrollbar relative z-10">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => setTopic(t.title)} className={`p-4 rounded-xl cursor-pointer transition-all group backdrop-blur-md ${topic === t.title ? 'bg-primary/20 border-primary border' : 'bg-white/5 border-transparent border hover:border-white/20 hover:bg-white/10'}`}>
                              <h4 className="font-bold text-white text-sm mb-1 line-clamp-1 group-hover:text-primary transition-colors">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button onClick={handleNext} disabled={!topic} className={`w-full py-5 md:py-6 rounded-2xl font-black text-white shadow-2xl hover:opacity-90 transition-all disabled:opacity-30 text-lg md:text-xl tracking-widest uppercase relative z-10 ${mode === 'viral' ? 'bg-gradient-to-r from-orange-600 to-red-600' : 'bg-gradient-to-r from-blue-600 to-primary'}`}>
                開始生成內容 <span className="text-sm font-normal opacity-70 ml-2">(10 點數)</span>
              </button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pt-4 pb-20">
        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl relative overflow-hidden">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯器 ({mode === 'viral' ? '爆文模式' : '品牌模式'})</h3>
                    <button onClick={() => setStep(1)} className="text-[10px] font-bold text-red-400 hover:text-white transition-colors uppercase tracking-widest border border-red-500/30 px-2 py-1 rounded">← 重設主題</button>
                </div>

                <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">貼文文案 (Caption)</label>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-[300px] p-6 text-white mb-6 resize-none outline-none custom-scrollbar leading-relaxed text-[15px] rounded-2xl" />

                {/* New Image Settings */}
                <div className="mb-6 p-4 bg-black/30 rounded-xl border border-gray-700">
                    <label className="text-[10px] text-primary font-bold mb-2 block uppercase tracking-wider">商業設計設定</label>
                    <div className="flex gap-2 mb-4 overflow-x-auto">
                        {(['product_showcase', 'promotion', 'lifestyle', 'educational', 'festival'] as ImageIntent[]).map(intent => (
                            <button 
                                key={intent}
                                onClick={() => setImageIntent(intent)}
                                className={`px-3 py-2 rounded-lg text-xs font-bold whitespace-nowrap border transition-all ${imageIntent === intent ? 'bg-primary text-black border-primary' : 'bg-transparent text-gray-400 border-gray-600 hover:border-gray-400'}`}
                            >
                                {intent === 'product_showcase' ? '📦 產品特寫' : intent === 'promotion' ? '🏷️ 促銷Banner' : intent === 'lifestyle' ? '🏖️ 情境生活' : intent === 'educational' ? '📚 知識圖卡' : '🎉 節慶賀圖'}
                            </button>
                        ))}
                    </div>

                    <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">視覺提示詞 (Visual Prompt)</label>
                    <textarea value={draft.imagePrompt} onChange={e => setDraft({...draft, imagePrompt: e.target.value})} className="w-full h-24 p-4 text-gray-300 text-xs outline-none resize-none leading-relaxed rounded-xl" placeholder="描述圖片內容..." />
                </div>

                <div className="space-y-4">
                    <button 
                        onClick={handleGenMedia} 
                        disabled={isGeneratingMedia}
                        className={`w-full py-5 rounded-2xl font-black text-white shadow-lg transition-all flex items-center justify-center gap-3 tracking-widest uppercase border border-white/10 disabled:opacity-50 disabled:cursor-not-allowed ${mediaUrl ? 'bg-black/40 hover:bg-black/60' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:brightness-110'}`}
                    >
                        {isGeneratingMedia ? (
                            <>
                                <div className="loader w-4 h-4 border-t-white"></div>
                                AI 設計師繪製中...
                            </>
                        ) : mediaUrl ? (
                            <>重新繪製 <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">2 點數</span></>
                        ) : (
                            <>生成商業設計圖 (Ideogram/Imagen) <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">5 點數</span></>
                        )}
                    </button>
                </div>
            </div>
        </div>

        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl flex flex-col min-h-[600px] relative">
                <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm mb-6">預覽效果</h3>

                <div className="bg-white rounded-[2rem] overflow-hidden flex-1 border-8 border-gray-900 shadow-2xl flex flex-col relative mx-auto w-full max-w-sm">
                    <div className="bg-white text-black text-[10px] font-bold p-3 flex justify-between px-6"><span>9:41</span><span>📶 🔋</span></div>
                    <div className="p-4 border-b border-gray-100 flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-yellow-400 to-red-500 flex items-center justify-center text-white text-xs font-bold">B</div>
                        <div className="space-y-0.5"><div className="h-2 w-20 bg-gray-200 rounded"></div><div className="h-1.5 w-12 bg-gray-100 rounded"></div></div>
                    </div>
                    <div className="p-4 overflow-y-auto max-h-[400px] custom-scrollbar flex-1 bg-white">
                        <p className="text-black text-[14px] whitespace-pre-wrap mb-4 leading-relaxed font-sans">{draft.caption}</p>
                        {mediaUrl && <img src={mediaUrl} className="w-full h-auto rounded-xl shadow-sm border border-gray-100 animate-fade-in" />}
                        {!mediaUrl && (
                            <div className="w-full aspect-square bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-300 gap-2">
                                <span className="text-2xl opacity-50">🖼️</span>
                                <span className="text-[10px] font-bold uppercase tracking-widest">等待圖片生成...</span>
                            </div>
                        )}
                        <div className="flex gap-4 mt-4 text-gray-400">
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full ml-auto"></div>
                        </div>
                    </div>
                </div>

                {publishResult ? (
                    <div className={`mt-8 p-5 rounded-2xl text-center font-bold border transition-all ${publishResult.success ? 'bg-green-500/20 text-green-400 border-green-500/50' : 'bg-red-500/20 text-red-400 border-red-500/50'}`}>
                        <div className="text-[15px] mb-1">{publishResult.msg}</div>
                        <button onClick={() => setPublishResult(null)} className="text-[10px] uppercase font-black tracking-widest text-white/50 hover:text-white transition-colors underline underline-offset-4">返回編輯</button>
                    </div>
                ) : (
                    <div className="mt-8 space-y-4">
                        <div className="bg-black/40 p-4 rounded-xl border border-white/5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                            <div className="flex-1 w-full">
                                <label className="block text-[9px] text-gray-500 font-black uppercase tracking-[0.2em] mb-1">FB 排程發佈 (選填)</label>
                                <input type="datetime-local" value={scheduleDate} onChange={e => setScheduleDate(e.target.value)} className="w-full bg-transparent text-white outline-none text-sm font-bold p-0 border-none" />
                            </div>
                            <div className={`px-3 py-1 rounded text-[10px] font-black uppercase tracking-widest border ${isLimitReached ? 'text-red-400 border-red-900/50' : 'text-primary border-primary/20'}`}>
                                {scheduledPostsCount}/{limit} 席位
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => handleFinalize(true)} disabled={isLimitReached} className={`flex-1 py-4 rounded-xl font-black transition-all border uppercase tracking-widest text-xs ${isLimitReached ? 'border-gray-800 text-gray-700 cursor-not-allowed' : 'border-gray-600 text-gray-400 hover:border-white hover:text-white'}`}>
                                {isLimitReached ? '已滿' : '排程發佈 (FB API)'}
                            </button>
                            <button onClick={() => handleFinalize(false)} className="flex-1 bg-white text-black py-4 rounded-xl font-black shadow-[0_0_20px_rgba(255,255,255,0.2)] hover:bg-gray-200 transition-all transform active:scale-95 text-xs uppercase tracking-widest">
                                立即發佈
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile, TrendingTopic } from '../../types';
import { getTrendingTopics, generateThreadsBatch, fetchNewsImageFromUrl } from '../../services/geminiService';
import { publishThreadsPost } from '../../services/threadsService';
import { checkAndUseQuota } from '../../services/authService';
import { getThreadsSystemInstruction } from '../../services/promptTemplates';
import { LoadingOverlay, ImagePreview, generateStockUrl } from './ThreadsCommon';

type ImageSourceType = 'ai' | 'stock' | 'news' | 'upload' | 'none';

interface GeneratedPost {
  id: string;
  topic: string; 
  caption: string;
  imagePrompt: string;
  imageQuery: string;
  imageUrl?: string; 
  newsImageUrl?: string; 
  uploadedImageBase64?: string;
  targetAccountId?: string;
  status: 'idle' | 'publishing' | 'done' | 'failed';
  log?: string;
  imageSourceType: ImageSourceType;
  paidForGeneration?: boolean; 
}

interface Props {
    settings: BrandSettings;
    accounts: ThreadsAccount[];
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const ContentGenerator: React.FC<Props> = ({ settings, accounts, user, onQuotaUpdate }) => {
    // State
    const [genStep, setGenStep] = useState<1 | 2>(1);
    const [manualTopic, setManualTopic] = useState('');
    const [selectedTopics, setSelectedTopics] = useState<string[]>([]);
    const [genCount, setGenCount] = useState<1 | 2 | 3>(1);
    const [preSelectedImageMode, setPreSelectedImageMode] = useState<ImageSourceType>('none');
    const [selectedGenAccountId, setSelectedGenAccountId] = useState<string>(''); 
    const [generatedPosts, setGeneratedPosts] = useState<GeneratedPost[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);
    const [isRegeneratingImage, setIsRegeneratingImage] = useState<string | null>(null);
    const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
    const [loadingTrends, setLoadingTrends] = useState(false);
    const [trendError, setTrendError] = useState('');

    // Effects
    useEffect(() => {
        if (accounts.length > 0) {
            const currentSelectionExists = accounts.some(a => a.id === selectedGenAccountId);
            if (!selectedGenAccountId || !currentSelectionExists) {
                setSelectedGenAccountId(accounts[0].id);
            }
        }
    }, [accounts]);

    const loadTrends = async (overrideKeyword?: string) => {
        if (!user) return alert("請先登入");

        // [BILLING LOGIC] Pay-Per-Click Enforced
        // Always deduct points for trend search action, regardless of cache state.
        const COST = 2; 
        const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH');
        if (!allowed) return; 

        onQuotaUpdate();
        setLoadingTrends(true);
        setTrendError('');
        setTrendingTopics([]);

        try {
            const query = overrideKeyword || manualTopic || settings.industry || '台灣熱門時事';
            const trends = await getTrendingTopics(query);
            if (trends.length === 0) setTrendError("目前找不到相關新聞，請嘗試手動輸入其他話題。");
            setTrendingTopics(trends);
        } catch (e: any) {
            console.warn("Trend load error", e);
            setTrendError("無法載入即時趨勢，請檢查網路或稍後再試。");
        } finally {
            setLoadingTrends(false);
        }
    };

    const selectTopic = (title: string) => {
        if (selectedTopics.includes(title)) setSelectedTopics([]);
        else { setSelectedTopics([title]); setManualTopic(''); }
    };

    const handleManualTopicChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setManualTopic(e.target.value);
        if (e.target.value) setSelectedTopics([]);
    };

    const proceedToGenerateUI = () => {
        if (selectedTopics.length === 0 && !manualTopic) return alert("請先選擇或輸入一個話題");
        setGenStep(2);
    };

    const calculateCost = (count: number, mode: ImageSourceType) => {
        const baseCost = 2; 
        let extraCost = 0;
        if (mode === 'ai') extraCost = 5; 
        else if (mode === 'news') extraCost = 1;
        else if (mode === 'stock') extraCost = 1;
        return (baseCost + extraCost) * count;
    };

    const handleGenerateBatch = async () => {
        if (!user) return alert("請先登入");
        const topicSource = selectedTopics.length > 0 ? selectedTopics[0] : manualTopic;
        if (!topicSource) return alert("無效話題");

        const targetAccount = accounts.find(a => a.id === selectedGenAccountId);
        if (!targetAccount) return alert("錯誤：請先在上方選單選擇要發文的帳號");

        const totalCost = calculateCost(genCount, preSelectedImageMode);
        if (!confirm(`確定為帳號「${targetAccount.username}」生成 ${genCount} 篇貼文？\n\n消耗：${totalCost} 點配額`)) return;

        const allowed = await checkAndUseQuota(user.user_id, totalCost, 'THREADS_BATCH_GEN', { count: genCount, mode: preSelectedImageMode });
        if (!allowed) return; 
        onQuotaUpdate();

        setIsGenerating(true);
        setGeneratedPosts([]);

        try {
            const instruction = getThreadsSystemInstruction(
                targetAccount.accountType || 'personal',
                targetAccount.styleGuide,
                targetAccount.safetyFilter
            );

            const results = await generateThreadsBatch(topicSource, genCount, settings, [instruction]);
            const sourceTopicData = trendingTopics.find(t => t.title === topicSource);
            const initialNewsImg = sourceTopicData?.imageUrl;
            const newsUrl = sourceTopicData?.url;

            const newPosts: GeneratedPost[] = await Promise.all(results.map(async (r, i) => {
                let finalMode = preSelectedImageMode;
                let finalImageUrl = undefined;
                let errorLog = undefined;
                const uniqueSeed = Date.now().toString() + i;

                if (finalMode === 'ai') {
                    const encoded = encodeURIComponent(r.imagePrompt);
                    finalImageUrl = `https://image.pollinations.ai/prompt/${encoded}?n=${uniqueSeed}&model=flux`;
                } else if (finalMode === 'stock') {
                    finalImageUrl = generateStockUrl(r.imageQuery || r.imagePrompt, uniqueSeed);
                } else if (finalMode === 'news') {
                    if (initialNewsImg) finalImageUrl = initialNewsImg;
                    else if (newsUrl) {
                        const ogImg = await fetchNewsImageFromUrl(newsUrl);
                        if (ogImg) finalImageUrl = ogImg;
                    }
                    if (!finalImageUrl) {
                        try {
                           finalImageUrl = generateStockUrl(`News photo about ${topicSource}, realistic, journalism style`, uniqueSeed);
                        } catch (e) { finalMode = 'none'; errorLog = '無法取得新聞圖片'; }
                    }
                }

                return {
                    id: Date.now() + '_' + i,
                    topic: topicSource,
                    caption: r.caption,
                    imagePrompt: r.imagePrompt,
                    imageQuery: r.imageQuery,
                    newsImageUrl: finalMode === 'news' ? finalImageUrl : undefined,
                    imageUrl: (finalMode === 'ai' || finalMode === 'stock' || finalMode === 'news') ? finalImageUrl : undefined,
                    imageSourceType: finalMode,
                    log: errorLog,
                    status: 'idle',
                    targetAccountId: targetAccount.id
                };
            }));

            setGeneratedPosts(newPosts);
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const getPreviewUrl = (post: GeneratedPost) => {
        if (post.imageSourceType === 'upload' && post.uploadedImageBase64) return post.uploadedImageBase64;
        if (post.imageSourceType === 'news' && post.newsImageUrl) return post.newsImageUrl;
        if (post.imageUrl) return post.imageUrl;
        return '';
    };

    const handleImageModeChange = async (post: GeneratedPost, newMode: ImageSourceType) => {
        if (newMode === 'stock' || newMode === 'ai') { 
            if (!user) return alert("請先登入");
            const COST = 2; 
            const allowed = await checkAndUseQuota(user.user_id, COST, 'THREADS_REGEN_IMAGE');
            if (!allowed) return; 
            onQuotaUpdate();

            setIsRegeneratingImage(post.id);
            const newSeed = Date.now().toString() + Math.floor(Math.random() * 9999);
            const visualSubject = post.imageQuery || post.topic; 
            const newUrl = generateStockUrl(visualSubject, newSeed);

            setTimeout(() => {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode, imageUrl: newUrl } : p));
                setIsRegeneratingImage(null);
            }, 500); 
        } else {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode } : p));
        }
    };

    const handlePublish = async (post: GeneratedPost) => {
        if (!post.targetAccountId) return alert("錯誤：未指定發佈帳號");
        const acc = accounts.find(a => a.id === post.targetAccountId);
        if (!acc) return alert("錯誤：找不到對應的帳號資料，請檢查帳號是否已被移除。");
        if (!post.caption) return alert("內容為空，無法發佈");

        setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'publishing', log: '發佈中...' } : p));
        try {
            const imgUrl = post.imageSourceType === 'none' ? undefined : getPreviewUrl(post);
            const res = await publishThreadsPost(acc, post.caption, imgUrl);
            if (res.success) {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'done', log: '發佈成功！' } : p));
            } else {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `發佈失敗: ${res.error}` } : p));
                alert(`發佈失敗: ${res.error}`);
            }
        } catch (e: any) {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `系統錯誤: ${e.message}` } : p));
        }
    };

    if (loadingTrends) return <LoadingOverlay message="正在搜尋熱門話題" detail="AI 正在分析全網新聞與社群趨勢..." />;
    if (isGenerating) return <LoadingOverlay message="AI 正在量產 Threads 貼文" detail={`正在模擬 ${genCount} 篇不同語氣的真實貼文，並準備圖片中...`} />;

    return (
        <div className="space-y-6">
            {genStep === 1 && (
                <div className="bg-card p-6 rounded-xl border border-gray-700">
                     <h3 className="text-xl font-bold text-white mb-4">步驟 1: 選擇話題</h3>
                     <div className="mb-6 p-4 bg-dark/50 rounded-lg border border-gray-600">
                         <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-wider">第一步：設定或搜尋話題</label>
                         <div className="flex flex-col md:flex-row gap-2">
                             <input 
                                 value={manualTopic} 
                                 onChange={handleManualTopicChange} 
                                 className="flex-1 bg-dark border border-gray-600 rounded p-3 text-white placeholder-gray-500 focus:border-primary outline-none transition-colors" 
                                 placeholder="輸入關鍵字 (例如: AI, 美食, 房地產)..." 
                             />
                             <button 
                                 onClick={() => loadTrends()} 
                                 className="bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-3 md:py-0 rounded font-bold transition-colors whitespace-nowrap flex items-center justify-center gap-2"
                             >
                                 搜尋趨勢 (2點)
                             </button>
                         </div>
                         <p className="text-[10px] text-gray-500 mt-2">提示：輸入關鍵字後點擊「搜尋」，AI 將為您挖掘該領域的最新熱門新聞。</p>
                     </div>
                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-4 max-h-[60vh] overflow-y-auto custom-scrollbar p-1">
                          <div onClick={() => loadTrends(settings.industry)} className="flex flex-col items-center justify-center bg-gray-800/50 border border-gray-600 hover:border-gray-400 rounded-lg p-6 cursor-pointer min-h-[160px] text-center shadow-lg transition-transform active:scale-95 group">
                              <span className="text-lg font-bold text-gray-300 group-hover:text-white">挖掘綜合熱門靈感</span>
                              <span className="text-[10px] bg-primary/20 text-primary px-2 py-0.5 rounded mt-2 font-bold tracking-wider">2 點數</span>
                              <p className="text-xs text-gray-500 mt-2">查看 {settings.industry || '台灣'} 目前最紅的話題</p>
                          </div>
                          {trendingTopics.map((t, i) => (
                              <div key={i} onClick={() => selectTopic(t.title)} className={`flex flex-col justify-between p-4 rounded-lg border cursor-pointer min-h-[160px] transition-all relative overflow-hidden ${selectedTopics.includes(t.title) ? 'bg-primary/20 border-primary ring-2 ring-primary' : 'bg-dark border-gray-700 hover:border-gray-500'}`}>
                                  {t.imageUrl && <div className="absolute inset-0 opacity-10 bg-cover bg-center z-0" style={{backgroundImage: `url(${t.imageUrl})`}}></div>}
                                  <div className="relative z-10">
                                      <h4 className="font-bold text-white text-base line-clamp-2 mb-2 leading-tight">{t.title}</h4>
                                      <p className="text-xs text-gray-400 line-clamp-3 leading-relaxed">{t.description || "點擊查看詳情，AI 將自動延伸話題..."}</p>
                                  </div>
                                  <div className="relative z-10 mt-2 text-[10px] text-gray-500 flex justify-between items-center">
                                      <span>來源: {t.url ? new URL(t.url).hostname.replace('www.', '') : 'News'}</span>
                                      {selectedTopics.includes(t.title) && <span className="text-primary font-bold">✓ 已選擇</span>}
                                  </div>
                              </div>
                          ))}
                     </div>
                     <div className="mt-6 flex justify-end"><button onClick={proceedToGenerateUI} className="bg-primary hover:bg-blue-600 text-white px-8 py-3 rounded font-bold shadow-lg w-full md:w-auto">下一步</button></div>
                </div>
            )}

            {genStep === 2 && (
                <div className="space-y-6">
                    <div className="bg-card p-6 rounded-xl border border-gray-700">
                         <div className="flex justify-between items-center mb-6">
                             <h3 className="text-xl font-bold text-white">步驟 2: 生成與發佈</h3>
                             <button onClick={() => setGenStep(1)} className="text-sm text-gray-400 hover:text-white border border-gray-600 px-3 py-1 rounded hover:bg-gray-700 transition-colors">↩ 返回選題</button>
                         </div>
                         <div className="mb-6 bg-blue-900/20 p-4 rounded border border-blue-800">
                             <label className="block text-sm text-blue-300 font-bold mb-2">1. 選擇發文帳號 (決定語氣與人設) *</label>
                             <select value={selectedGenAccountId} onChange={(e) => setSelectedGenAccountId(e.target.value)} className="w-full bg-dark border border-blue-500 rounded p-3 text-white">
                                 {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.username} ({acc.accountType === 'brand' ? '品牌' : '個人'})</option>)}
                              </select>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                             <div className="bg-dark/50 p-4 rounded border border-gray-600"><label className="block text-sm text-gray-400 mb-2">當前話題</label><div className="font-bold text-xl text-white">{selectedTopics[0] || manualTopic}</div></div>
                             <div className="space-y-4">
                                 <div><label className="block text-sm text-gray-400 mb-1">數量</label><div className="flex gap-2">{[1,2,3].map(n => <button key={n} onClick={() => setGenCount(n as any)} className={`flex-1 py-2 rounded border ${genCount === n ? 'bg-white text-black' : 'border-gray-600'}`}>{n}</button>)}</div></div>
                                 <div><label className="block text-sm text-gray-400 mb-1">圖片</label><select value={preSelectedImageMode} onChange={(e) => setPreSelectedImageMode(e.target.value as any)} className="w-full bg-dark border border-gray-600 rounded p-2 text-white"><option value="none">無圖片</option><option value="stock">擬真圖庫</option><option value="ai">AI繪圖 (推薦)</option></select></div>
                             </div>
                         </div>
                         <button onClick={handleGenerateBatch} disabled={!selectedGenAccountId} className="w-full bg-gradient-to-r from-pink-600 to-purple-600 text-white py-4 rounded-xl font-bold text-lg shadow-lg">生成貼文</button>
                    </div>

                    {generatedPosts.length > 0 && (
                        <div className="space-y-8">
                            {generatedPosts.map((post) => (
                                <div key={post.id} className="bg-card rounded-xl border border-gray-700 overflow-hidden flex flex-col md:flex-row">
                                    <div className="w-full md:w-1/3 bg-black flex items-center justify-center relative min-h-[300px]">
                                        {getPreviewUrl(post) ? (
                                            <ImagePreview src={getPreviewUrl(post)} alt="Generated Content" />
                                        ) : <span className="text-gray-500">無圖片</span>}
                                        <div className="absolute bottom-2 left-2 flex gap-2">
                                            <button onClick={() => handleImageModeChange(post, 'stock')} disabled={isRegeneratingImage === post.id} className="text-xs bg-gray-700 hover:bg-gray-600 text-white px-3 py-2 rounded shadow-lg font-bold border border-gray-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1">
                                                {isRegeneratingImage === post.id ? (<><div className="loader w-3 h-3 border-2 border-t-white"></div>生成中...</>) : '隨機換圖 (2點)'}
                                            </button>
                                        </div>
                                    </div>
                                    <div className="flex-1 p-6 flex flex-col">
                                        <textarea value={post.caption} onChange={(e) => setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, caption: e.target.value } : p))} className="w-full flex-1 bg-dark border border-gray-600 rounded p-3 text-white mb-4 resize-none" />
                                        <div className="flex justify-between items-center">
                                            <span className={`text-xs font-bold ${post.status === 'done' ? 'text-green-400' : post.status === 'failed' ? 'text-red-400' : 'text-gray-500'}`}>{post.log || (post.status === 'idle' ? '準備就緒' : '')}</span>
                                            <button onClick={() => handlePublish(post)} disabled={post.status === 'publishing' || post.status === 'done'} className={`px-6 py-3 rounded font-bold transition-all ${post.status === 'done' ? 'bg-green-600 text-white cursor-default' : 'bg-white text-black hover:bg-gray-200'}`}>
                                                {post.status === 'publishing' ? '發佈中...' : post.status === 'done' ? '已發佈' : '立即發佈'}
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default ContentGenerator;

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile, TrendingTopic } from '../../types';
import { getTrendingTopics, generateThreadsBatch, fetchNewsImageFromUrl } from '../../services/geminiService';
import { publishThreadsPost } from '../../services/threadsService';
import { checkAndUseQuota } from '../../services/authService';
import { getThreadsSystemInstruction } from '../../services/promptTemplates';
import { LoadingOverlay, ImagePreview, generateStockUrl } from './ThreadsCommon';

type ImageSourceType = 'ai' | 'stock' | 'news' | 'upload' | 'none';

interface GeneratedPost {
  id: string;
  topic: string; 
  caption: string;
  imagePrompt: string;
  imageQuery: string;
  imageUrl?: string; 
  newsImageUrl?: string; 
  uploadedImageBase64?: string;
  targetAccountId?: string;
  status: 'idle' | 'publishing' | 'done' | 'failed';
  log?: string;
  imageSourceType: ImageSourceType;
  paidForGeneration?: boolean; 
}

interface Props {
    settings: BrandSettings;
    accounts: ThreadsAccount[];
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const ContentGenerator: React.FC<Props> = ({ settings, accounts, user, onQuotaUpdate }) => {
    // State
    const [genStep, setGenStep] = useState<1 | 2>(1);
    const [manualTopic, setManualTopic] = useState('');
    const [selectedTopics, setSelectedTopics] = useState<string[]>([]);
    const [genCount, setGenCount] = useState<1 | 2 | 3>(1);
    const [preSelectedImageMode, setPreSelectedImageMode] = useState<ImageSourceType>('none');
    const [selectedGenAccountId, setSelectedGenAccountId] = useState<string>(''); 
    const [generatedPosts, setGeneratedPosts] = useState<GeneratedPost[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);
    const [isRegeneratingImage, setIsRegeneratingImage] = useState<string | null>(null);
    const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
    const [loadingTrends, setLoadingTrends] = useState(false);
    const [trendError, setTrendError] = useState('');

    // Effects
    useEffect(() => {
        if (accounts.length > 0) {
            const currentSelectionExists = accounts.some(a => a.id === selectedGenAccountId);
            if (!selectedGenAccountId || !currentSelectionExists) {
                setSelectedGenAccountId(accounts[0].id);
            }
        }
    }, [accounts]);

    const loadTrends = async (overrideKeyword?: string) => {
        if (!user) return alert("請先登入");

        // [BILLING LOGIC] Pay-Per-Click Enforced
        // Standardized to 3 points matching the Pricing Panel
        const COST = 3; 
        const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH');
        if (!allowed) return; 

        onQuotaUpdate();
        setLoadingTrends(true);
        setTrendError('');
        setTrendingTopics([]);

        try {
            const query = overrideKeyword || manualTopic || settings.industry || '台灣熱門時事';
            const trends = await getTrendingTopics(query);
            if (trends.length === 0) setTrendError("目前找不到相關新聞，請嘗試手動輸入其他話題。");
            setTrendingTopics(trends);
        } catch (e: any) {
            console.warn("Trend load error", e);
            setTrendError("無法載入即時趨勢，請檢查網路或稍後再試。");
        } finally {
            setLoadingTrends(false);
        }
    };

    const selectTopic = (title: string) => {
        if (selectedTopics.includes(title)) setSelectedTopics([]);
        else { setSelectedTopics([title]); setManualTopic(''); }
    };

    const handleManualTopicChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setManualTopic(e.target.value);
        if (e.target.value) setSelectedTopics([]);
    };

    const proceedToGenerateUI = () => {
        if (selectedTopics.length === 0 && !manualTopic) return alert("請先選擇或輸入一個話題");
        setGenStep(2);
    };

    const calculateCost = (count: number, mode: ImageSourceType) => {
        const baseCost = 2; // Text generation base
        let extraCost = 0;
        if (mode === 'ai') extraCost = 5; // New Image
        else if (mode === 'news') extraCost = 1;
        else if (mode === 'stock') extraCost = 1;
        return (baseCost + extraCost) * count;
    };

    const handleGenerateBatch = async () => {
        if (!user) return alert("請先登入");
        const topicSource = selectedTopics.length > 0 ? selectedTopics[0] : manualTopic;
        if (!topicSource) return alert("無效話題");

        const targetAccount = accounts.find(a => a.id === selectedGenAccountId);
        if (!targetAccount) return alert("錯誤：請先在上方選單選擇要發文的帳號");

        const totalCost = calculateCost(genCount, preSelectedImageMode);
        if (!confirm(`確定為帳號「${targetAccount.username}」生成 ${genCount} 篇貼文？\n\n消耗：${totalCost} 點配額`)) return;

        const allowed = await checkAndUseQuota(user.user_id, totalCost, 'THREADS_BATCH_GEN', { count: genCount, mode: preSelectedImageMode });
        if (!allowed) return; 
        onQuotaUpdate();

        setIsGenerating(true);
        setGeneratedPosts([]);

        try {
            const instruction = getThreadsSystemInstruction(
                targetAccount.accountType || 'personal',
                targetAccount.styleGuide,
                targetAccount.safetyFilter
            );

            const results = await generateThreadsBatch(topicSource, genCount, settings, [instruction]);
            const sourceTopicData = trendingTopics.find(t => t.title === topicSource);
            const initialNewsImg = sourceTopicData?.imageUrl;
            const newsUrl = sourceTopicData?.url;

            const newPosts: GeneratedPost[] = await Promise.all(results.map(async (r, i) => {
                let finalMode = preSelectedImageMode;
                let finalImageUrl = undefined;
                let errorLog = undefined;
                const uniqueSeed = Date.now().toString() + i;

                if (finalMode === 'ai') {
                    const encoded = encodeURIComponent(r.imagePrompt);
                    finalImageUrl = `https://image.pollinations.ai/prompt/${encoded}?n=${uniqueSeed}&model=flux`;
                } else if (finalMode === 'stock') {
                    finalImageUrl = generateStockUrl(r.imageQuery || r.imagePrompt, uniqueSeed);
                } else if (finalMode === 'news') {
                    if (initialNewsImg) finalImageUrl = initialNewsImg;
                    else if (newsUrl) {
                        const ogImg = await fetchNewsImageFromUrl(newsUrl);
                        if (ogImg) finalImageUrl = ogImg;
                    }
                    if (!finalImageUrl) {
                        try {
                           finalImageUrl = generateStockUrl(`News photo about ${topicSource}, realistic, journalism style`, uniqueSeed);
                        } catch (e) { finalMode = 'none'; errorLog = '無法取得新聞圖片'; }
                    }
                }

                return {
                    id: Date.now() + '_' + i,
                    topic: topicSource,
                    caption: r.caption,
                    imagePrompt: r.imagePrompt,
                    imageQuery: r.imageQuery,
                    newsImageUrl: finalMode === 'news' ? finalImageUrl : undefined,
                    imageUrl: (finalMode === 'ai' || finalMode === 'stock' || finalMode === 'news') ? finalImageUrl : undefined,
                    imageSourceType: finalMode,
                    log: errorLog,
                    status: 'idle',
                    targetAccountId: targetAccount.id
                };
            }));

            setGeneratedPosts(newPosts);
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const getPreviewUrl = (post: GeneratedPost) => {
        if (post.imageSourceType === 'upload' && post.uploadedImageBase64) return post.uploadedImageBase64;
        if (post.imageSourceType === 'news' && post.newsImageUrl) return post.newsImageUrl;
        if (post.imageUrl) return post.imageUrl;
        return '';
    };

    const handleImageModeChange = async (post: GeneratedPost, newMode: ImageSourceType) => {
        if (newMode === 'stock' || newMode === 'ai') { 
            if (!user) return alert("請先登入");

            // [BILLING LOGIC] Regeneration Cost
            // 2 Points for re-generating or switching image mode
            const COST = 2; 
            const allowed = await checkAndUseQuota(user.user_id, COST, 'THREADS_REGEN_IMAGE');
            if (!allowed) return; 
            onQuotaUpdate();

            setIsRegeneratingImage(post.id);
            const newSeed = Date.now().toString() + Math.floor(Math.random() * 9999);
            const visualSubject = post.imageQuery || post.topic; 
            const newUrl = generateStockUrl(visualSubject, newSeed);

            setTimeout(() => {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode, imageUrl: newUrl } : p));
                setIsRegeneratingImage(null);
            }, 500); 
        } else {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode } : p));
        }
    };

    const handlePublish = async (post: GeneratedPost) => {
        if (!post.targetAccountId) return alert("錯誤：未指定發佈帳號");
        const acc = accounts.find(a => a.id === post.targetAccountId);
        if (!acc) return alert("錯誤：找不到對應的帳號資料，請檢查帳號是否已被移除。");
        if (!post.caption) return alert("內容為空，無法發佈");

        setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'publishing', log: '發佈中...' } : p));
        try {
            const imgUrl = post.imageSourceType === 'none' ? undefined : getPreviewUrl(post);
            const res = await publishThreadsPost(acc, post.caption, imgUrl);
            if (res.success) {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'done', log: '發佈成功！' } : p));
            } else {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `發佈失敗: ${res.error}` } : p));
                alert(`發佈失敗: ${res.error}`);
            }
        } catch (e: any) {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `系統錯誤: ${e.message}` } : p));
        }
    };

    if (loadingTrends) return <LoadingOverlay message="正在搜尋熱門話題" detail="AI 正在分析全網新聞與社群趨勢..." />;
    if (isGenerating) return <LoadingOverlay message="AI 正在量產 Threads 貼文" detail={`正在模擬 ${genCount} 篇不同語氣的真實貼文，並準備圖片中...`} />;

    return (
        <div className="space-y-6">
            {genStep === 1 && (
                <div className="bg-card p-6 rounded-xl border border-gray-700">
                     <h3 className="text-xl font-bold text-white mb-4">步驟 1: 選擇話題</h3>
                     <div className="mb-6 p-4 bg-dark/50 rounded-lg border border-gray-600">
                         <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-wider">第一步：設定或搜尋話題</label>
                         <div className="flex flex-col md:flex-row gap-2">
                             <input 
                                 value={manualTopic} 
                                 onChange={handleManualTopicChange} 
                                 className="flex-1 bg-dark border border-gray-600 rounded p-3 text-white placeholder-gray-500 focus:border-primary outline-none transition-colors" 
                                 placeholder="輸入關鍵字 (例如: AI, 美食, 房地產)..." 
                             />
                             <button 
                                 onClick={() => loadTrends()} 
                                 className="bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-3 md:py-0 rounded font-bold transition-colors whitespace-nowrap flex items-center justify-center gap-2"
                             >
                                 搜尋趨勢 (3點)
                             </button>
                         </div>
                         <p className="text-[10px] text-gray-500 mt-2">提示：輸入關鍵字後點擊「搜尋」，AI 將為您挖掘該領域的最新熱門新聞。</p>
                     </div>
                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-4 max-h-[60vh] overflow-y-auto custom-scrollbar p-1">
                          <div onClick={() => loadTrends(settings.industry)} className="flex flex-col items-center justify-center bg-gray-800/50 border border-gray-600 hover:border-gray-400 rounded-lg p-6 cursor-pointer min-h-[160px] text-center shadow-lg transition-transform active:scale-95 group">
                              <span className="text-lg font-bold text-gray-300 group-hover:text-white">挖掘綜合熱門靈感</span>
                              <span className="text-[10px] bg-primary/20 text-primary px-2 py-0.5 rounded mt-2 font-bold tracking-wider">3 點數</span>
                              <p className="text-xs text-gray-500 mt-2">查看 {settings.industry || '台灣'} 目前最紅的話題</p>
                          </div>
                          {trendingTopics.map((t, i) => (
                              <div key={i} onClick={() => selectTopic(t.title)} className={`flex flex-col justify-between p-4 rounded-lg border cursor-pointer min-h-[160px] transition-all relative overflow-hidden ${selectedTopics.includes(t.title) ? 'bg-primary/20 border-primary ring-2 ring-primary' : 'bg-dark border-gray-700 hover:border-gray-500'}`}>
                                  {t.imageUrl && <div className="absolute inset-0 opacity-10 bg-cover bg-center z-0" style={{backgroundImage: `url(${t.imageUrl})`}}></div>}
                                  <div className="relative z-10">
                                      <h4 className="font-bold text-white text-base line-clamp-2 mb-2 leading-tight">{t.title}</h4>
                                      <p className="text-xs text-gray-400 line-clamp-3 leading-relaxed">{t.description || "點擊查看詳情，AI 將自動延伸話題..."}</p>
                                  </div>
                                  <div className="relative z-10 mt-2 text-[10px] text-gray-500 flex justify-between items-center">
                                      <span>來源: {t.url ? new URL(t.url).hostname.replace('www.', '') : 'News'}</span>
                                      {selectedTopics.includes(t.title) && <span className="text-primary font-bold">✓ 已選擇</span>}
                                  </div>
                              </div>
                          ))}
                     </div>
                     <div className="mt-6 flex justify-end"><button onClick={proceedToGenerateUI} className="bg-primary hover:bg-blue-600 text-white px-8 py-3 rounded font-bold shadow-lg w-full md:w-auto">下一步</button></div>
                </div>
            )}

            {genStep === 2 && (
                <div className="space-y-6">
                    <div className="bg-card p-6 rounded-xl border border-gray-700">
                         <div className="flex justify-between items-center mb-6">
                             <h3 className="text-xl font-bold text-white">步驟 2: 生成與發佈</h3>
                             <button onClick={() => setGenStep(1)} className="text-sm text-gray-400 hover:text-white border border-gray-600 px-3 py-1 rounded hover:bg-gray-700 transition-colors">↩ 返回選題</button>
                         </div>
                         <div className="mb-6 bg-blue-900/20 p-4 rounded border border-blue-800">
                             <label className="block text-sm text-blue-300 font-bold mb-2">1. 選擇發文帳號 (決定語氣與人設) *</label>
                             <select value={selectedGenAccountId} onChange={(e) => setSelectedGenAccountId(e.target.value)} className="w-full bg-dark border border-blue-500 rounded p-3 text-white">
                                 {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.username} ({acc.accountType === 'brand' ? '品牌' : '個人'})</option>)}
                              </select>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                             <div className="bg-dark/50 p-4 rounded border border-gray-600"><label className="block text-sm text-gray-400 mb-2">當前話題</label><div className="font-bold text-xl text-white">{selectedTopics[0] || manualTopic}</div></div>
                             <div className="space-y-4">
                                 <div><label className="block text-sm text-gray-400 mb-1">數量</label><div className="flex gap-2">{[1,2,3].map(n => <button key={n} onClick={() => setGenCount(n as any)} className={`flex-1 py-2 rounded border ${genCount === n ? 'bg-white text-black' : 'border-gray-600'}`}>{n}</button>)}</div></div>
                                 <div><label className="block text-sm text-gray-400 mb-1">圖片</label><select value={preSelectedImageMode} onChange={(e) => setPreSelectedImageMode(e.target.value as any)} className="w-full bg-dark border border-gray-600 rounded p-2 text-white"><option value="none">無圖片</option><option value="stock">擬真圖庫</option><option value="ai">AI繪圖 (推薦)</option></select></div>
                             </div>
                         </div>
                         <button onClick={handleGenerateBatch} disabled={!selectedGenAccountId} className="w-full bg-gradient-to-r from-pink-600 to-purple-600 text-white py-4 rounded-xl font-bold text-lg shadow-lg">生成貼文</button>
                    </div>

                    {generatedPosts.length > 0 && (
                        <div className="space-y-8">
                            {generatedPosts.map((post) => (
                                <div key={post.id} className="bg-card rounded-xl border border-gray-700 overflow-hidden flex flex-col md:flex-row">
                                    <div className="w-full md:w-1/3 bg-black flex items-center justify-center relative min-h-[300px]">
                                        {getPreviewUrl(post) ? (
                                            <ImagePreview src={getPreviewUrl(post)} alt="Generated Content" />
                                        ) : <span className="text-gray-500">無圖片</span>}
                                        <div className="absolute bottom-2 left-2 flex gap-2">
                                            <button onClick={() => handleImageModeChange(post, 'stock')} disabled={isRegeneratingImage === post.id} className="text-xs bg-gray-700 hover:bg-gray-600 text-white px-3 py-2 rounded shadow-lg font-bold border border-gray-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1">
                                                {isRegeneratingImage === post.id ? (<><div className="loader w-3 h-3 border-2 border-t-white"></div>生成中...</>) : '隨機換圖 (2點)'}
                                            </button>
                                        </div>
                                    </div>
                                    <div className="flex-1 p-6 flex flex-col">
                                        <textarea value={post.caption} onChange={(e) => setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, caption: e.target.value } : p))} className="w-full flex-1 bg-dark border border-gray-600 rounded p-3 text-white mb-4 resize-none" />
                                        <div className="flex justify-between items-center">
                                            <span className={`text-xs font-bold ${post.status === 'done' ? 'text-green-400' : post.status === 'failed' ? 'text-red-400' : 'text-gray-500'}`}>{post.log || (post.status === 'idle' ? '準備就緒' : '')}</span>
                                            <button onClick={() => handlePublish(post)} disabled={post.status === 'publishing' || post.status === 'done'} className={`px-6 py-3 rounded font-bold transition-all ${post.status === 'done' ? 'bg-green-600 text-white cursor-default' : 'bg-white text-black hover:bg-gray-200'}`}>
                                                {post.status === 'publishing' ? '發佈中...' : post.status === 'done' ? '已發佈' : '立即發佈'}
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default ContentGenerator;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ImageIntent } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string }> = ({ message }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">AI Processing...</p>
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle'); // NEW

  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");

      // [BILLING LOGIC] Pay-Per-Click Enforced
      // Deduct points BEFORE any service call or cache check.
      // Even if the result comes from cache (0 cost for us), the user pays for the "Search" action.
      const COST = 3; 
      const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH'); 
      if (!allowed) return; 

      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);
          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！(扣除 ${COST} 點)`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, 10, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);
            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: res.imagePrompt || `Professional commercial photo of ${topic}` 
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: res.imagePrompt || ''
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    if (!draft.imagePrompt.trim()) return alert("請輸入圖片提示詞 (Prompt)");

    // Pricing Update: Regen 1->2, New 3->5
    const cost = mediaUrl ? 2 : 5; 
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI', { prompt: draft.imagePrompt });
    if (!allowed) return;

    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      // Use new generateImage with Settings & Intent
      let url = await generateImage(draft.imagePrompt, user.role, settings, imageIntent);
      if (settings.logoUrl) url = await applyWatermark(url, settings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
    }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;
        if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        const res = await publishPostToFacebook(
            settings.facebookPageId, 
            settings.facebookToken, 
            draft.caption, 
            mediaUrl, 
            draft.firstComment, 
            syncInstagram,
            scheduledUnixTime
        );

        if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = schedule ? 'scheduled' : 'published';
            await onPostCreated(newPost);

            if (schedule) setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
            else setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
        } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
        }

    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  // Keep the overlay for initial generation, but button logic below handles regeneration
  if (isGeneratingMedia) return <LoadingOverlay message="AI 設計師正在繪製商業圖..." />;
  if (isPublishing) return <LoadingOverlay message="正在傳送至 Facebook..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 md:space-y-12 animate-fade-in pt-4 md:pt-10">
          <div className="text-center space-y-3">
              <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  What's Next?
              </h2>
              <p className="text-gray-400 font-bold tracking-widest uppercase text-xs md:text-base">輸入核心主題，讓 AI 為您打造吸睛內容</p>
          </div>

          <div className="glass-card p-6 md:p-12 rounded-[2rem] shadow-2xl space-y-6 md:space-y-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none"></div>

              <div className="flex p-1.5 bg-black/40 rounded-2xl border border-white/5 relative z-10">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'brand' ? 'bg-primary text-black shadow-[0_0_20px_rgba(0,242,234,0.4)]' : 'text-gray-500 hover:text-white'}`}>品牌模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'viral' ? 'bg-secondary text-white shadow-[0_0_20px_rgba(255,0,85,0.4)]' : 'text-gray-500 hover:text-white'}`}>爆文模式 (小紅書)</button>
              </div>

              <div className="flex flex-col md:flex-row gap-3 relative z-10">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 p-4 md:p-5 rounded-2xl text-lg md:text-xl font-medium placeholder-gray-600 outline-none w-full" placeholder="輸入主題 (例如：夏季保養、今日新聞...)" />
                  <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 px-8 py-4 md:py-0 rounded-2xl text-white font-bold transition-all flex flex-row md:flex-col items-center justify-center gap-2 md:gap-1 border border-gray-700 hover:border-white/20 whitespace-nowrap">
                    <span className="text-sm">🔥 挖掘靈感</span><span className="text-[9px] bg-primary/20 text-primary px-2 rounded-full font-black">3 點數</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader border-t-primary"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-white/5 rounded-2xl bg-black/20 custom-scrollbar relative z-10">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => setTopic(t.title)} className={`p-4 rounded-xl cursor-pointer transition-all group backdrop-blur-md ${topic === t.title ? 'bg-primary/20 border-primary border' : 'bg-white/5 border-transparent border hover:border-white/20 hover:bg-white/10'}`}>
                              <h4 className="font-bold text-white text-sm mb-1 line-clamp-1 group-hover:text-primary transition-colors">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button onClick={handleNext} disabled={!topic} className={`w-full py-5 md:py-6 rounded-2xl font-black text-white shadow-2xl hover:opacity-90 transition-all disabled:opacity-30 text-lg md:text-xl tracking-widest uppercase relative z-10 ${mode === 'viral' ? 'bg-gradient-to-r from-orange-600 to-red-600' : 'bg-gradient-to-r from-blue-600 to-primary'}`}>
                開始生成內容 <span className="text-sm font-normal opacity-70 ml-2">(10 點數)</span>
              </button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pt-4 pb-20">
        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl relative overflow-hidden">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯器 ({mode === 'viral' ? '爆文模式' : '品牌模式'})</h3>
                    <button onClick={() => setStep(1)} className="text-[10px] font-bold text-red-400 hover:text-white transition-colors uppercase tracking-widest border border-red-500/30 px-2 py-1 rounded">← 重設主題</button>
                </div>

                <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">貼文文案 (Caption)</label>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-[300px] p-6 text-white mb-6 resize-none outline-none custom-scrollbar leading-relaxed text-[15px] rounded-2xl" />

                {/* New Image Settings */}
                <div className="mb-6 p-4 bg-black/30 rounded-xl border border-gray-700">
                    <label className="text-[10px] text-primary font-bold mb-2 block uppercase tracking-wider">商業設計設定</label>
                    <div className="flex gap-2 mb-4 overflow-x-auto">
                        {(['product_showcase', 'promotion', 'lifestyle', 'educational', 'festival'] as ImageIntent[]).map(intent => (
                            <button 
                                key={intent}
                                onClick={() => setImageIntent(intent)}
                                className={`px-3 py-2 rounded-lg text-xs font-bold whitespace-nowrap border transition-all ${imageIntent === intent ? 'bg-primary text-black border-primary' : 'bg-transparent text-gray-400 border-gray-600 hover:border-gray-400'}`}
                            >
                                {intent === 'product_showcase' ? '📦 產品特寫' : intent === 'promotion' ? '🏷️ 促銷Banner' : intent === 'lifestyle' ? '🏖️ 情境生活' : intent === 'educational' ? '📚 知識圖卡' : '🎉 節慶賀圖'}
                            </button>
                        ))}
                    </div>

                    <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">視覺提示詞 (Visual Prompt)</label>
                    <textarea value={draft.imagePrompt} onChange={e => setDraft({...draft, imagePrompt: e.target.value})} className="w-full h-24 p-4 text-gray-300 text-xs outline-none resize-none leading-relaxed rounded-xl" placeholder="描述圖片內容..." />
                </div>

                <div className="space-y-4">
                    <button 
                        onClick={handleGenMedia} 
                        disabled={isGeneratingMedia}
                        className={`w-full py-5 rounded-2xl font-black text-white shadow-lg transition-all flex items-center justify-center gap-3 tracking-widest uppercase border border-white/10 disabled:opacity-50 disabled:cursor-not-allowed ${mediaUrl ? 'bg-black/40 hover:bg-black/60' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:brightness-110'}`}
                    >
                        {isGeneratingMedia ? (
                            <>
                                <div className="loader w-4 h-4 border-t-white"></div>
                                AI 設計師繪製中...
                            </>
                        ) : mediaUrl ? (
                            <>重新繪製 <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">2 點數</span></>
                        ) : (
                            <>生成商業設計圖 (Ideogram/Imagen) <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">5 點數</span></>
                        )}
                    </button>
                </div>
            </div>
        </div>

        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl flex flex-col min-h-[600px] relative">
                <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm mb-6">預覽效果</h3>

                <div className="bg-white rounded-[2rem] overflow-hidden flex-1 border-8 border-gray-900 shadow-2xl flex flex-col relative mx-auto w-full max-w-sm">
                    <div className="bg-white text-black text-[10px] font-bold p-3 flex justify-between px-6"><span>9:41</span><span>📶 🔋</span></div>
                    <div className="p-4 border-b border-gray-100 flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-yellow-400 to-red-500 flex items-center justify-center text-white text-xs font-bold">B</div>
                        <div className="space-y-0.5"><div className="h-2 w-20 bg-gray-200 rounded"></div><div className="h-1.5 w-12 bg-gray-100 rounded"></div></div>
                    </div>
                    <div className="p-4 overflow-y-auto max-h-[400px] custom-scrollbar flex-1 bg-white">
                        <p className="text-black text-[14px] whitespace-pre-wrap mb-4 leading-relaxed font-sans">{draft.caption}</p>
                        {mediaUrl && <img src={mediaUrl} className="w-full h-auto rounded-xl shadow-sm border border-gray-100 animate-fade-in" />}
                        {!mediaUrl && (
                            <div className="w-full aspect-square bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-300 gap-2">
                                <span className="text-2xl opacity-50">🖼️</span>
                                <span className="text-[10px] font-bold uppercase tracking-widest">等待圖片生成...</span>
                            </div>
                        )}
                        <div className="flex gap-4 mt-4 text-gray-400">
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full ml-auto"></div>
                        </div>
                    </div>
                </div>

                {publishResult ? (
                    <div className={`mt-8 p-5 rounded-2xl text-center font-bold border transition-all ${publishResult.success ? 'bg-green-500/20 text-green-400 border-green-500/50' : 'bg-red-500/20 text-red-400 border-red-500/50'}`}>
                        <div className="text-[15px] mb-1">{publishResult.msg}</div>
                        <button onClick={() => setPublishResult(null)} className="text-[10px] uppercase font-black tracking-widest text-white/50 hover:text-white transition-colors underline underline-offset-4">返回編輯</button>
                    </div>
                ) : (
                    <div className="mt-8 space-y-4">
                        <div className="bg-black/40 p-4 rounded-xl border border-white/5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                            <div className="flex-1 w-full">
                                <label className="block text-[9px] text-gray-500 font-black uppercase tracking-[0.2em] mb-1">FB 排程發佈 (選填)</label>
                                <input type="datetime-local" value={scheduleDate} onChange={e => setScheduleDate(e.target.value)} className="w-full bg-transparent text-white outline-none text-sm font-bold p-0 border-none" />
                            </div>
                            <div className={`px-3 py-1 rounded text-[10px] font-black uppercase tracking-widest border ${isLimitReached ? 'text-red-400 border-red-900/50' : 'text-primary border-primary/20'}`}>
                                {scheduledPostsCount}/{limit} 席位
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => handleFinalize(true)} disabled={isLimitReached} className={`flex-1 py-4 rounded-xl font-black transition-all border uppercase tracking-widest text-xs ${isLimitReached ? 'border-gray-800 text-gray-700 cursor-not-allowed' : 'border-gray-600 text-gray-400 hover:border-white hover:text-white'}`}>
                                {isLimitReached ? '已滿' : '排程發佈 (FB API)'}
                            </button>
                            <button onClick={() => handleFinalize(false)} className="flex-1 bg-white text-black py-4 rounded-xl font-black shadow-[0_0_20px_rgba(255,255,255,0.2)] hover:bg-gray-200 transition-all transform active:scale-95 text-xs uppercase tracking-widest">
                                立即發佈
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ImageIntent } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string }> = ({ message }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">AI Processing...</p>
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle'); // NEW

  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");

      // [BILLING] Search Trends: 3 Points
      const COST = 3; 
      const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH'); 
      if (!allowed) return; 

      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);
          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！(扣除 ${COST} 點)`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;

    // [BILLING] FB Draft: 5 Points (Lowered from 10)
    const allowed = await checkAndUseQuota(user.user_id, 5, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);
            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: res.imagePrompt || `Professional commercial photo of ${topic}` 
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: res.imagePrompt || ''
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    if (!draft.imagePrompt.trim()) return alert("請輸入圖片提示詞 (Prompt)");

    // [BILLING] FB Image: Regen 5 Points, First Time 8 Points
    const cost = mediaUrl ? 5 : 8; 
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI', { prompt: draft.imagePrompt });
    if (!allowed) return;

    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      // Use new generateImage with Settings & Intent
      let url = await generateImage(draft.imagePrompt, user.role, settings, imageIntent);
      if (settings.logoUrl) url = await applyWatermark(url, settings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
    }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;
        if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        const res = await publishPostToFacebook(
            settings.facebookPageId, 
            settings.facebookToken, 
            draft.caption, 
            mediaUrl, 
            draft.firstComment, 
            syncInstagram,
            scheduledUnixTime
        );

        if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = schedule ? 'scheduled' : 'published';
            await onPostCreated(newPost);

            if (schedule) setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
            else setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
        } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
        }

    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  // Keep the overlay for initial generation, but button logic below handles regeneration
  if (isGeneratingMedia) return <LoadingOverlay message="AI 設計師正在繪製商業圖..." />;
  if (isPublishing) return <LoadingOverlay message="正在傳送至 Facebook..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 md:space-y-12 animate-fade-in pt-4 md:pt-10">
          <div className="text-center space-y-3">
              <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  What's Next?
              </h2>
              <p className="text-gray-400 font-bold tracking-widest uppercase text-xs md:text-base">輸入核心主題，讓 AI 為您打造吸睛內容</p>
          </div>

          <div className="glass-card p-6 md:p-12 rounded-[2rem] shadow-2xl space-y-6 md:space-y-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none"></div>

              <div className="flex p-1.5 bg-black/40 rounded-2xl border border-white/5 relative z-10">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'brand' ? 'bg-primary text-black shadow-[0_0_20px_rgba(0,242,234,0.4)]' : 'text-gray-500 hover:text-white'}`}>品牌模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'viral' ? 'bg-secondary text-white shadow-[0_0_20px_rgba(255,0,85,0.4)]' : 'text-gray-500 hover:text-white'}`}>爆文模式 (小紅書)</button>
              </div>

              <div className="flex flex-col md:flex-row gap-3 relative z-10">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 p-4 md:p-5 rounded-2xl text-lg md:text-xl font-medium placeholder-gray-600 outline-none w-full" placeholder="輸入主題 (例如：夏季保養、今日新聞...)" />
                  <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 px-8 py-4 md:py-0 rounded-2xl text-white font-bold transition-all flex flex-row md:flex-col items-center justify-center gap-2 md:gap-1 border border-gray-700 hover:border-white/20 whitespace-nowrap">
                    <span className="text-sm">🔥 挖掘靈感</span><span className="text-[9px] bg-primary/20 text-primary px-2 rounded-full font-black">3 點數</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader border-t-primary"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-white/5 rounded-2xl bg-black/20 custom-scrollbar relative z-10">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => setTopic(t.title)} className={`p-4 rounded-xl cursor-pointer transition-all group backdrop-blur-md ${topic === t.title ? 'bg-primary/20 border-primary border' : 'bg-white/5 border-transparent border hover:border-white/20 hover:bg-white/10'}`}>
                              <h4 className="font-bold text-white text-sm mb-1 line-clamp-1 group-hover:text-primary transition-colors">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button onClick={handleNext} disabled={!topic} className={`w-full py-5 md:py-6 rounded-2xl font-black text-white shadow-2xl hover:opacity-90 transition-all disabled:opacity-30 text-lg md:text-xl tracking-widest uppercase relative z-10 ${mode === 'viral' ? 'bg-gradient-to-r from-orange-600 to-red-600' : 'bg-gradient-to-r from-blue-600 to-primary'}`}>
                開始生成內容 <span className="text-sm font-normal opacity-70 ml-2">(5 點數)</span>
              </button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pt-4 pb-20">
        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl relative overflow-hidden">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯器 ({mode === 'viral' ? '爆文模式' : '品牌模式'})</h3>
                    <button onClick={() => setStep(1)} className="text-[10px] font-bold text-red-400 hover:text-white transition-colors uppercase tracking-widest border border-red-500/30 px-2 py-1 rounded">← 重設主題</button>
                </div>

                <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">貼文文案 (Caption)</label>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-[300px] p-6 text-white mb-6 resize-none outline-none custom-scrollbar leading-relaxed text-[15px] rounded-2xl" />

                {/* New Image Settings */}
                <div className="mb-6 p-4 bg-black/30 rounded-xl border border-gray-700">
                    <label className="text-[10px] text-primary font-bold mb-2 block uppercase tracking-wider">商業設計設定</label>
                    <div className="flex gap-2 mb-4 overflow-x-auto">
                        {(['product_showcase', 'promotion', 'lifestyle', 'educational', 'festival'] as ImageIntent[]).map(intent => (
                            <button 
                                key={intent}
                                onClick={() => setImageIntent(intent)}
                                className={`px-3 py-2 rounded-lg text-xs font-bold whitespace-nowrap border transition-all ${imageIntent === intent ? 'bg-primary text-black border-primary' : 'bg-transparent text-gray-400 border-gray-600 hover:border-gray-400'}`}
                            >
                                {intent === 'product_showcase' ? '📦 產品特寫' : intent === 'promotion' ? '🏷️ 促銷Banner' : intent === 'lifestyle' ? '🏖️ 情境生活' : intent === 'educational' ? '📚 知識圖卡' : '🎉 節慶賀圖'}
                            </button>
                        ))}
                    </div>

                    <label className="text-[10px] text-gray-500 font-bold mb-2 block uppercase tracking-wider">視覺提示詞 (Visual Prompt)</label>
                    <textarea value={draft.imagePrompt} onChange={e => setDraft({...draft, imagePrompt: e.target.value})} className="w-full h-24 p-4 text-gray-300 text-xs outline-none resize-none leading-relaxed rounded-xl" placeholder="描述圖片內容..." />
                </div>

                <div className="space-y-4">
                    <button 
                        onClick={handleGenMedia} 
                        disabled={isGeneratingMedia}
                        className={`w-full py-5 rounded-2xl font-black text-white shadow-lg transition-all flex items-center justify-center gap-3 tracking-widest uppercase border border-white/10 disabled:opacity-50 disabled:cursor-not-allowed ${mediaUrl ? 'bg-black/40 hover:bg-black/60' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:brightness-110'}`}
                    >
                        {isGeneratingMedia ? (
                            <>
                                <div className="loader w-4 h-4 border-t-white"></div>
                                AI 設計師繪製中...
                            </>
                        ) : mediaUrl ? (
                            <>重新繪製 <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">5 點數</span></>
                        ) : (
                            <>生成商業設計圖 (Ideogram/Imagen) <span className="text-[10px] font-black bg-white/20 px-2 py-0.5 rounded-full">8 點數</span></>
                        )}
                    </button>
                </div>
            </div>
        </div>

        <div className="space-y-6">
            <div className="glass-card p-6 md:p-8 rounded-3xl flex flex-col min-h-[600px] relative">
                <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm mb-6">預覽效果</h3>

                <div className="bg-white rounded-[2rem] overflow-hidden flex-1 border-8 border-gray-900 shadow-2xl flex flex-col relative mx-auto w-full max-w-sm">
                    <div className="bg-white text-black text-[10px] font-bold p-3 flex justify-between px-6"><span>9:41</span><span>📶 🔋</span></div>
                    <div className="p-4 border-b border-gray-100 flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-yellow-400 to-red-500 flex items-center justify-center text-white text-xs font-bold">B</div>
                        <div className="space-y-0.5"><div className="h-2 w-20 bg-gray-200 rounded"></div><div className="h-1.5 w-12 bg-gray-100 rounded"></div></div>
                    </div>
                    <div className="p-4 overflow-y-auto max-h-[400px] custom-scrollbar flex-1 bg-white">
                        <p className="text-black text-[14px] whitespace-pre-wrap mb-4 leading-relaxed font-sans">{draft.caption}</p>
                        {mediaUrl && <img src={mediaUrl} className="w-full h-auto rounded-xl shadow-sm border border-gray-100 animate-fade-in" />}
                        {!mediaUrl && (
                            <div className="w-full aspect-square bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-300 gap-2">
                                <span className="text-2xl opacity-50">🖼️</span>
                                <span className="text-[10px] font-bold uppercase tracking-widest">等待圖片生成...</span>
                            </div>
                        )}
                        <div className="flex gap-4 mt-4 text-gray-400">
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full"></div>
                             <div className="w-5 h-5 bg-gray-100 rounded-full ml-auto"></div>
                        </div>
                    </div>
                </div>

                {publishResult ? (
                    <div className={`mt-8 p-5 rounded-2xl text-center font-bold border transition-all ${publishResult.success ? 'bg-green-500/20 text-green-400 border-green-500/50' : 'bg-red-500/20 text-red-400 border-red-500/50'}`}>
                        <div className="text-[15px] mb-1">{publishResult.msg}</div>
                        <button onClick={() => setPublishResult(null)} className="text-[10px] uppercase font-black tracking-widest text-white/50 hover:text-white transition-colors underline underline-offset-4">返回編輯</button>
                    </div>
                ) : (
                    <div className="mt-8 space-y-4">
                        <div className="bg-black/40 p-4 rounded-xl border border-white/5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                            <div className="flex-1 w-full">
                                <label className="block text-[9px] text-gray-500 font-black uppercase tracking-[0.2em] mb-1">FB 排程發佈 (選填)</label>
                                <input type="datetime-local" value={scheduleDate} onChange={e => setScheduleDate(e.target.value)} className="w-full bg-transparent text-white outline-none text-sm font-bold p-0 border-none" />
                            </div>
                            <div className={`px-3 py-1 rounded text-[10px] font-black uppercase tracking-widest border ${isLimitReached ? 'text-red-400 border-red-900/50' : 'text-primary border-primary/20'}`}>
                                {scheduledPostsCount}/{limit} 席位
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => handleFinalize(true)} disabled={isLimitReached} className={`flex-1 py-4 rounded-xl font-black transition-all border uppercase tracking-widest text-xs ${isLimitReached ? 'border-gray-800 text-gray-700 cursor-not-allowed' : 'border-gray-600 text-gray-400 hover:border-white hover:text-white'}`}>
                                {isLimitReached ? '已滿' : '排程發佈 (FB API)'}
                            </button>
                            <button onClick={() => handleFinalize(false)} className="flex-1 bg-white text-black py-4 rounded-xl font-black shadow-[0_0_20px_rgba(255,255,255,0.2)] hover:bg-gray-200 transition-all transform active:scale-95 text-xs uppercase tracking-widest">
                                立即發佈
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile, TrendingTopic } from '../../types';
import { getTrendingTopics, generateThreadsBatch, fetchNewsImageFromUrl } from '../../services/geminiService';
import { publishThreadsPost } from '../../services/threadsService';
import { checkAndUseQuota } from '../../services/authService';
import { getThreadsSystemInstruction } from '../../services/promptTemplates';
import { LoadingOverlay, ImagePreview, generateStockUrl } from './ThreadsCommon';

type ImageSourceType = 'ai' | 'stock' | 'news' | 'upload' | 'none';

interface GeneratedPost {
  id: string;
  topic: string; 
  caption: string;
  imagePrompt: string;
  imageQuery: string;
  imageUrl?: string; 
  newsImageUrl?: string; 
  uploadedImageBase64?: string;
  targetAccountId?: string;
  status: 'idle' | 'publishing' | 'done' | 'failed';
  log?: string;
  imageSourceType: ImageSourceType;
  paidForGeneration?: boolean; 
}

interface Props {
    settings: BrandSettings;
    accounts: ThreadsAccount[];
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const ContentGenerator: React.FC<Props> = ({ settings, accounts, user, onQuotaUpdate }) => {
    // State
    const [genStep, setGenStep] = useState<1 | 2>(1);
    const [manualTopic, setManualTopic] = useState('');
    const [selectedTopics, setSelectedTopics] = useState<string[]>([]);
    const [genCount, setGenCount] = useState<1 | 2 | 3>(1);
    const [preSelectedImageMode, setPreSelectedImageMode] = useState<ImageSourceType>('none');
    const [selectedGenAccountId, setSelectedGenAccountId] = useState<string>(''); 
    const [generatedPosts, setGeneratedPosts] = useState<GeneratedPost[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);
    const [isRegeneratingImage, setIsRegeneratingImage] = useState<string | null>(null);
    const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
    const [loadingTrends, setLoadingTrends] = useState(false);
    const [trendError, setTrendError] = useState('');

    // Effects
    useEffect(() => {
        if (accounts.length > 0) {
            const currentSelectionExists = accounts.some(a => a.id === selectedGenAccountId);
            if (!selectedGenAccountId || !currentSelectionExists) {
                setSelectedGenAccountId(accounts[0].id);
            }
        }
    }, [accounts]);

    const loadTrends = async (overrideKeyword?: string) => {
        if (!user) return alert("請先登入");

        // [BILLING] Trend Search: 3 Points
        const COST = 3; 
        const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH');
        if (!allowed) return; 

        onQuotaUpdate();
        setLoadingTrends(true);
        setTrendError('');
        setTrendingTopics([]);

        try {
            const query = overrideKeyword || manualTopic || settings.industry || '台灣熱門時事';
            const trends = await getTrendingTopics(query);
            if (trends.length === 0) setTrendError("目前找不到相關新聞，請嘗試手動輸入其他話題。");
            setTrendingTopics(trends);
        } catch (e: any) {
            console.warn("Trend load error", e);
            setTrendError("無法載入即時趨勢，請檢查網路或稍後再試。");
        } finally {
            setLoadingTrends(false);
        }
    };

    const selectTopic = (title: string) => {
        if (selectedTopics.includes(title)) setSelectedTopics([]);
        else { setSelectedTopics([title]); setManualTopic(''); }
    };

    const handleManualTopicChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setManualTopic(e.target.value);
        if (e.target.value) setSelectedTopics([]);
    };

    const proceedToGenerateUI = () => {
        if (selectedTopics.length === 0 && !manualTopic) return alert("請先選擇或輸入一個話題");
        setGenStep(2);
    };

    const calculateCost = (count: number, mode: ImageSourceType) => {
        const baseCost = 2; // Text generation base
        let extraCost = 0;
        // [BILLING] AI Image (First): 6 Points Total -> Base 2 + Extra 4
        if (mode === 'ai') extraCost = 4; 
        else if (mode === 'news') extraCost = 1;
        else if (mode === 'stock') extraCost = 1;
        return (baseCost + extraCost) * count;
    };

    const handleGenerateBatch = async () => {
        if (!user) return alert("請先登入");
        const topicSource = selectedTopics.length > 0 ? selectedTopics[0] : manualTopic;
        if (!topicSource) return alert("無效話題");

        const targetAccount = accounts.find(a => a.id === selectedGenAccountId);
        if (!targetAccount) return alert("錯誤：請先在上方選單選擇要發文的帳號");

        const totalCost = calculateCost(genCount, preSelectedImageMode);
        if (!confirm(`確定為帳號「${targetAccount.username}」生成 ${genCount} 篇貼文？\n\n消耗：${totalCost} 點配額`)) return;

        const allowed = await checkAndUseQuota(user.user_id, totalCost, 'THREADS_BATCH_GEN', { count: genCount, mode: preSelectedImageMode });
        if (!allowed) return; 
        onQuotaUpdate();

        setIsGenerating(true);
        setGeneratedPosts([]);

        try {
            const instruction = getThreadsSystemInstruction(
                targetAccount.accountType || 'personal',
                targetAccount.styleGuide,
                targetAccount.safetyFilter
            );

            const results = await generateThreadsBatch(topicSource, genCount, settings, [instruction]);
            const sourceTopicData = trendingTopics.find(t => t.title === topicSource);
            const initialNewsImg = sourceTopicData?.imageUrl;
            const newsUrl = sourceTopicData?.url;

            const newPosts: GeneratedPost[] = await Promise.all(results.map(async (r, i) => {
                let finalMode = preSelectedImageMode;
                let finalImageUrl = undefined;
                let errorLog = undefined;
                const uniqueSeed = Date.now().toString() + i;

                if (finalMode === 'ai') {
                    const encoded = encodeURIComponent(r.imagePrompt);
                    finalImageUrl = `https://image.pollinations.ai/prompt/${encoded}?n=${uniqueSeed}&model=flux`;
                } else if (finalMode === 'stock') {
                    finalImageUrl = generateStockUrl(r.imageQuery || r.imagePrompt, uniqueSeed);
                } else if (finalMode === 'news') {
                    if (initialNewsImg) finalImageUrl = initialNewsImg;
                    else if (newsUrl) {
                        const ogImg = await fetchNewsImageFromUrl(newsUrl);
                        if (ogImg) finalImageUrl = ogImg;
                    }
                    if (!finalImageUrl) {
                        try {
                           finalImageUrl = generateStockUrl(`News photo about ${topicSource}, realistic, journalism style`, uniqueSeed);
                        } catch (e) { finalMode = 'none'; errorLog = '無法取得新聞圖片'; }
                    }
                }

                return {
                    id: Date.now() + '_' + i,
                    topic: topicSource,
                    caption: r.caption,
                    imagePrompt: r.imagePrompt,
                    imageQuery: r.imageQuery,
                    newsImageUrl: finalMode === 'news' ? finalImageUrl : undefined,
                    imageUrl: (finalMode === 'ai' || finalMode === 'stock' || finalMode === 'news') ? finalImageUrl : undefined,
                    imageSourceType: finalMode,
                    log: errorLog,
                    status: 'idle',
                    targetAccountId: targetAccount.id
                };
            }));

            setGeneratedPosts(newPosts);
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const getPreviewUrl = (post: GeneratedPost) => {
        if (post.imageSourceType === 'upload' && post.uploadedImageBase64) return post.uploadedImageBase64;
        if (post.imageSourceType === 'news' && post.newsImageUrl) return post.newsImageUrl;
        if (post.imageUrl) return post.imageUrl;
        return '';
    };

    const handleImageModeChange = async (post: GeneratedPost, newMode: ImageSourceType) => {
        if (newMode === 'stock' || newMode === 'ai') { 
            if (!user) return alert("請先登入");

            // [BILLING] Threads Image Regen: 4 Points
            const COST = 4; 
            const allowed = await checkAndUseQuota(user.user_id, COST, 'THREADS_REGEN_IMAGE');
            if (!allowed) return; 
            onQuotaUpdate();

            setIsRegeneratingImage(post.id);
            const newSeed = Date.now().toString() + Math.floor(Math.random() * 9999);
            const visualSubject = post.imageQuery || post.topic; 
            const newUrl = generateStockUrl(visualSubject, newSeed);

            setTimeout(() => {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode, imageUrl: newUrl } : p));
                setIsRegeneratingImage(null);
            }, 500); 
        } else {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: newMode } : p));
        }
    };

    const handlePublish = async (post: GeneratedPost) => {
        if (!post.targetAccountId) return alert("錯誤：未指定發佈帳號");
        const acc = accounts.find(a => a.id === post.targetAccountId);
        if (!acc) return alert("錯誤：找不到對應的帳號資料，請檢查帳號是否已被移除。");
        if (!post.caption) return alert("內容為空，無法發佈");

        setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'publishing', log: '發佈中...' } : p));
        try {
            const imgUrl = post.imageSourceType === 'none' ? undefined : getPreviewUrl(post);
            const res = await publishThreadsPost(acc, post.caption, imgUrl);
            if (res.success) {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'done', log: '發佈成功！' } : p));
            } else {
                setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `發佈失敗: ${res.error}` } : p));
                alert(`發佈失敗: ${res.error}`);
            }
        } catch (e: any) {
            setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, status: 'failed', log: `系統錯誤: ${e.message}` } : p));
        }
    };

    if (loadingTrends) return <LoadingOverlay message="正在搜尋熱門話題" detail="AI 正在分析全網新聞與社群趨勢..." />;
    if (isGenerating) return <LoadingOverlay message="AI 正在量產 Threads 貼文" detail={`正在模擬 ${genCount} 篇不同語氣的真實貼文，並準備圖片中...`} />;

    return (
        <div className="space-y-6">
            {genStep === 1 && (
                <div className="bg-card p-6 rounded-xl border border-gray-700">
                     <h3 className="text-xl font-bold text-white mb-4">步驟 1: 選擇話題</h3>
                     <div className="mb-6 p-4 bg-dark/50 rounded-lg border border-gray-600">
                         <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-wider">第一步：設定或搜尋話題</label>
                         <div className="flex flex-col md:flex-row gap-2">
                             <input 
                                 value={manualTopic} 
                                 onChange={handleManualTopicChange} 
                                 className="flex-1 bg-dark border border-gray-600 rounded p-3 text-white placeholder-gray-500 focus:border-primary outline-none transition-colors" 
                                 placeholder="輸入關鍵字 (例如: AI, 美食, 房地產)..." 
                             />
                             <button 
                                 onClick={() => loadTrends()} 
                                 className="bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-3 md:py-0 rounded font-bold transition-colors whitespace-nowrap flex items-center justify-center gap-2"
                             >
                                 搜尋趨勢 (3點)
                             </button>
                         </div>
                         <p className="text-[10px] text-gray-500 mt-2">提示：輸入關鍵字後點擊「搜尋」，AI 將為您挖掘該領域的最新熱門新聞。</p>
                     </div>
                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-4 max-h-[60vh] overflow-y-auto custom-scrollbar p-1">
