module.exports = async function (req, res) {
  // 1. Security Check (Vercel Cron Header)
  const authHeader = req.headers['authorization'];
  if (process.env.CRON_SECRET && authHeader !== `Bearer ${process.env.CRON_SECRET}`) {
      return res.status(401).end('Unauthorized');
  }

  if (!admin.apps.length) {
      return res.status(500).json({ error: "Firebase Admin not initialized" });
  }

  console.log("[Cron] Starting Daily Expiration Check...");
  const db = admin.firestore();
  const now = Date.now();
  const ONE_DAY = 24 * 60 * 60 * 1000;

  try {
      const usersSnap = await db.collection('users').get();
      let expiredCount = 0;
      let warningCount = 0;

      const batch = db.batch();
      let batchOps = 0;

      for (const doc of usersSnap.docs) {
          const user = doc.data();
          const expiryDate = user.quota_reset_date || 0;

          if (!expiryDate) continue; // No expiry set (legacy or admin)

          // 1. Check for Expiration
          if (now > expiryDate && user.quota_total > 0) {
              console.log(`[Expire] User ${user.email} points expired.`);
              // Reset quota
              batch.update(doc.ref, {
                  quota_used: 0,
                  quota_total: 0, // Wipe balance
                  updated_at: now
              });
              expiredCount++;
              batchOps++;
          }
          else if (now < expiryDate) {
              // 2. Check for Warnings
              const msLeft = expiryDate - now;
              const daysLeft = Math.ceil(msLeft / ONE_DAY);
              const currentLevel = user.expiry_warning_level || 0;

              // 3-Month Warning (Approx 90 days)
              if (daysLeft <= 90 && daysLeft > 30 && currentLevel < 1) {
                  await sendExpiryWarningEmail(user.email, 90);
                  batch.update(doc.ref, { expiry_warning_level: 1 });
                  warningCount++;
                  batchOps++;
              }
              // 1-Month Warning (Approx 30 days)
              else if (daysLeft <= 30 && currentLevel < 2) {
                  await sendExpiryWarningEmail(user.email, 30);
                  batch.update(doc.ref, { expiry_warning_level: 2 });
                  warningCount++;
                  batchOps++;
              }
          }

          // Commit batch if getting large (Firestore limit 500)
          if (batchOps >= 400) {
              await batch.commit();
              batchOps = 0; // Reset counter, batch object re-use is tricky, usually create new batch
              // Ideally we'd create a new batch here, but for simplicity in this snippet we assume < 400 changes per run or simple loop
          }
      }

      if (batchOps > 0) {
          await batch.commit();
      }

      return res.status(200).json({ 
          success: true, 
          stats: {
              processed: usersSnap.size,
              expired: expiredCount,
              warningsSent: warningCount
          }
      });

  } catch (e) {
      console.error("[Cron Error]", e);
      return res.status(500).json({ error: e.message });
  }
};

