export const getCurrentUser = () => {
    if (!isMock) return auth.currentUser;
    const uid = localStorage.getItem(SESSION_KEY);
    if (uid) {
         const u = MockStore.getUser(uid);
         return { uid: uid, email: u ? u.email : 'demo@example.com' };
    }
    return null;
};

export const login = async (email: string, pass: string) => {
    // 1. Real Firebase Login
    if (!isMock) {
        const cred = await auth.signInWithEmailAndPassword(email, pass);
        return { user: cred.user };
    } 

    // 2. Mock User Login (Dev Mode)
    const user = MockStore.findUserByEmail(email);
    if (user) {
        localStorage.setItem(SESSION_KEY, user.user_id);
        window.dispatchEvent(new Event('auth_state_change'));
        return { user: { uid: user.user_id, email: user.email } };
    }

    // Auto-register in Mock mode if user doesn't exist to simplify testing
    return await register(email, pass);
};

export const register = async (email: string, pass: string) => {
    if (!isMock) {
        const cred = await auth.createUserWithEmailAndPassword(email, pass);
        await createUserProfile({ uid: cred.user!.uid, email: email });
        return { user: cred.user };
    } 

    const uid = 'user_' + Date.now();
    await createUserProfile({ uid, email });
    localStorage.setItem(SESSION_KEY, uid);
    window.dispatchEvent(new Event('auth_state_change'));
    return { user: { uid, email } };
};

export const logout = async () => {
    if (!isMock) await auth.signOut();
    else {
        localStorage.removeItem(SESSION_KEY);
        window.dispatchEvent(new Event('auth_state_change'));
    }
};

export const subscribeAuth = (callback: (user: { uid: string, email: string } | null) => void) => {
    if (!isMock) {
        return auth.onAuthStateChanged(async (firebaseUser: any) => {
            if (firebaseUser) {
                const profile = await getUserProfile(firebaseUser.uid);
                if (profile && profile.isSuspended) {
                    await logout();
                    callback(null);
                } else {
                    callback({ uid: firebaseUser.uid, email: firebaseUser.email || '' });
                }
            } else {
                callback(null);
            }
        });
    }

    const check = () => {
         const uid = localStorage.getItem(SESSION_KEY);
         if(uid) {
             const u = MockStore.getUser(uid);
             const email = u ? u.email : 'demo@example.com';
             callback({ uid, email });
         } else {
             callback(null);
         }
    };

    if (typeof window !== 'undefined') {
        window.addEventListener('auth_state_change', check);
        setTimeout(check, 0); 
    }
    return () => {
        if (typeof window !== 'undefined') window.removeEventListener('auth_state_change', check);
    };
};

export const sendPasswordReset = async (email: string) => {
    if (!isMock) await auth.sendPasswordResetEmail(email);
    else console.log(`[Mock] Password reset sent to ${email}`);
};

/**
 * Exchange Threads OAuth Code for Long-Lived Token via Backend
 * NOTE: App credentials are now handled server-side for security.
 */
export const exchangeThreadsAuth = async (code: string, redirectUri: string) => {
    if (isMock) {
        return { 
            token: 'mock_threads_long_token_' + Date.now(), 
            userId: 'mock_user_123',
            username: 'mock_threads_user'
        };
    }

    const user = getCurrentUser();
    if (!user) throw new Error("Authentication required for token exchange");

    const token = await user.getIdToken();

    const res = await fetch('/api/auth/threads/exchange', {
        method: 'POST',
        headers: { 
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ code, redirectUri })
    });

    const data = await res.json();
    if (!data.success) {
        throw new Error(data.error?.message || 'Token exchange failed');
    }
    return data.data;
};

import React, { useState, useEffect } from 'react';
import { login, register, sendPasswordReset } from '../services/authService';

interface Props {
  onLoginSuccess: () => void;
}

const Login: React.FC<Props> = ({ onLoginSuccess }) => {
  const [mode, setMode] = useState<'LOGIN' | 'REGISTER' | 'FORGOT'>('LOGIN');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const savedEmail = localStorage.getItem('autosocial_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccessMsg('');

    try {
      if (mode === 'REGISTER') {
        await register(email.trim(), password.trim());
        onLoginSuccess();
      } else if (mode === 'LOGIN') {
        await login(email.trim(), password.trim());

        // Handle Remember Me
        if (rememberMe) {
          localStorage.setItem('autosocial_remembered_email', email.trim());
        } else {
          localStorage.removeItem('autosocial_remembered_email');
        }

        onLoginSuccess();
      } else if (mode === 'FORGOT') {
        await sendPasswordReset(email.trim());
        setSuccessMsg(`密碼重設信已發送至 ${email}，請檢查信箱。`);
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || '發生錯誤');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen relative overflow-hidden">
      {/* Login Card */}
      <div className="glass-card p-10 rounded-3xl w-full max-w-md animate-fade-in relative z-10 border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)]">
        <div className="text-center mb-8">
            <h1 className="text-4xl font-black text-white tracking-tighter mb-2">
                AUTO<span className="text-neon-cyan">SOCIAL</span>
            </h1>
            <p className="text-sm font-bold text-gray-400 tracking-[0.2em] uppercase">
                AI 社群自動化中控台
            </p>
        </div>

        <h2 className="text-2xl font-bold text-center text-white mb-2">
          {mode === 'REGISTER' ? '建立帳戶' : mode === 'FORGOT' ? '重設密碼' : '歡迎回來'}
        </h2>

        <div className="text-gray-400 text-center mb-8 text-sm">
          {mode === 'REGISTER' ? '開始您的自動化之旅' : mode === 'FORGOT' ? '我們會發送重設連結給您' : (
             <>
                一篇貼文最低 <span className="text-primary font-bold">NT$3</span>，立即體驗全自動社群經營！
             </>
          )}
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wider">Email</label>
            <input 
              type="email" 
              name="email"
              required
              autoComplete="username"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full p-4 rounded-xl outline-none text-white font-medium"
              placeholder="name@example.com"
            />
          </div>

          {mode !== 'FORGOT' && (
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wider">Password</label>
              <input 
                type="password"
                name="password" 
                required
                autoComplete={mode === 'REGISTER' ? "new-password" : "current-password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-4 rounded-xl outline-none text-white font-medium"
              />
            </div>
          )}

          {mode === 'LOGIN' && (
            <div className="flex items-center gap-2">
              <input 
                type="checkbox" 
                id="rememberMe"
                checked={rememberMe}
                onChange={(e) => setRememberMe(e.target.checked)}
                className="w-4 h-4 rounded border-gray-600 bg-black/30 text-primary focus:ring-primary cursor-pointer"
              />
              <label htmlFor="rememberMe" className="text-sm text-gray-400 cursor-pointer select-none">
                記住帳號 (Remember Email)
              </label>
            </div>
          )}

          {error && <div className="text-red-400 text-xs font-bold text-center bg-red-900/20 p-3 rounded border border-red-900/50">{error}</div>}
          {successMsg && <div className="text-green-400 text-xs font-bold text-center bg-green-900/20 p-3 rounded border border-green-900/50">{successMsg}</div>}

          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-gradient-to-r from-primary to-blue-600 hover:to-blue-500 text-black py-4 rounded-xl font-black transition-all transform active:scale-95 disabled:opacity-50 disabled:scale-100 shadow-[0_0_20px_rgba(0,242,234,0.3)] hover:shadow-[0_0_30px_rgba(0,242,234,0.5)] uppercase tracking-wider"
          >
            {loading ? <div className="loader mx-auto border-t-black"></div> : (mode === 'REGISTER' ? '註冊' : mode === 'FORGOT' ? '發送' : '登入')}
          </button>
        </form>

        <div className="mt-8 flex flex-col gap-3 text-center text-xs font-medium">
          {mode === 'LOGIN' && (
             <>
                <button type="button" onClick={() => setMode('REGISTER')} className="text-gray-400 hover:text-white transition-colors">還沒有帳號？ <span className="text-primary underline decoration-primary/50 underline-offset-4">免費註冊</span></button>
                <button type="button" onClick={() => setMode('FORGOT')} className="text-gray-500 hover:text-gray-400">忘記密碼？</button>
             </>
          )}
          {mode === 'REGISTER' && (
             <button type="button" onClick={() => setMode('LOGIN')} className="text-gray-400 hover:text-white transition-colors">已有帳號？ <span className="text-primary underline decoration-primary/50 underline-offset-4">點此登入</span></button>
          )}
          {mode === 'FORGOT' && (
             <button type="button" onClick={() => setMode('LOGIN')} className="text-gray-400 hover:text-white transition-colors">想起密碼了？ <span className="text-primary underline decoration-primary/50 underline-offset-4">返回登入</span></button>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ImageIntent } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent, generateImagePromptString } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string, subMessage?: string }> = ({ message, subMessage }) => (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-xl animate-fade-in text-center">
        <div className="loader mb-6 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-black text-white mb-2 tracking-tight">{message}</h2>
        {subMessage && <p className="text-gray-400 font-mono text-xs uppercase tracking-widest">{subMessage}</p>}
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');

  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle'); 

  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
  const [generatingPhase, setGeneratingPhase] = useState<string>(''); // For granular loading status

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");

      const COST = 3; 
      const allowed = await checkAndUseQuota(user.user_id, COST, 'TREND_SEARCH'); 
      if (!allowed) return; 

      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const query = topic.trim() || settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(query);
          setTrendingTopics(trends);
          if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！(扣除 ${COST} 點)`);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async () => {
    if (!topic || !user) return;

    // [BILLING] FB Draft: 5 Points
    const allowed = await checkAndUseQuota(user.user_id, 5, 'GENERATE_POST_DRAFT');
    if (!allowed) return; 

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setMediaUrl(undefined); 

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(topic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);

            // Logic Change: Do NOT auto-fill image prompt here. Let user choose intent first.
            setDraft({ 
                caption: res.caption || '', 
                firstComment: res.ctaText || '', 
                imagePrompt: '' // Intentionally empty to force generation on intent selection
            });
        } else {
            const res = await generateViralContent(topic, {
                audience: '社群大眾',
                viralType: 'auto',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions?.[0] || '生成內容為空，請重試',
                firstComment: '',
                imagePrompt: '' // Intentionally empty
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;

    // [BILLING] FB Image: Regen 5 Points, First Time 8 Points
    const cost = mediaUrl ? 5 : 8; 
    const allowed = await checkAndUseQuota(user.user_id, cost, 'GENERATE_IMAGE_AI');
    if (!allowed) return;

    onQuotaUpdate();
    setIsGeneratingMedia(true);
    setGeneratingPhase('正在構思畫面...');

    try {
        let finalPrompt = draft.imagePrompt;

        // Logic Change: If prompt is empty (first run) or user changed intent without editing prompt manually
        // We generate the prompt NOW based on Caption + Intent
        if (!finalPrompt.trim()) {
             const aiPrompt = await generateImagePromptString(draft.caption, imageIntent, settings);
             finalPrompt = aiPrompt;
             setDraft(prev => ({ ...prev, imagePrompt: aiPrompt }));
        }

        setGeneratingPhase('AI 設計師繪圖中 (標準畫質)...');

        // Use new generateImage with Settings & Intent
        let url = await generateImage(finalPrompt, user.role, settings, imageIntent);
        if (settings.logoUrl) {
            setGeneratingPhase('正在壓上品牌浮水印...');
            url = await applyWatermark(url, settings.logoUrl);
        }
        setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
        setGeneratingPhase('');
    }
  };

  // Helper to clear prompt when intent changes, forcing re-generation of prompt next click
  const handleIntentChange = (newIntent: ImageIntent) => {
      setImageIntent(newIntent);
      // Optional: If user hasn't manually heavily edited, clear it so we generate a new one for new intent
      // For safety, we only clear if no media generated yet, or if user confirms? 
      // Let's just keep the old prompt but the user can clear it if they want. 
      // User request: "If user unhappy, can re-select intent... click generate again -> new image"
      // So we should probably clear the prompt IF it was auto-generated, to allow new generation logic to kick in.
      // For simplicity, we won't auto-clear, but rely on the user to edit or clear if they want a fresh start from AI.
      // Actually, per user request: "First click -> generate prompt + image". 
      // If they change intent, they likely want a NEW prompt.
      // Let's clear the prompt ONLY IF no image exists yet, or if they explicitly want to reset.
      // Implementation: We'll leave it. The `handleGenMedia` uses `draft.imagePrompt` if present.
      // If user wants new prompt based on new intent, they should clear the text box or we add a "Auto-Generate Prompt" button.
      // Better UX based on request: If they click "Generate" and box is empty, it auto-gens. 
      // So if they switch intent, they can clear the box manually to force new prompt.
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    let scheduledUnixTime: number | undefined = undefined;

    if (schedule) {
        if (!scheduleDate) return alert("請選擇預計發佈時間");
        const targetTime = new Date(scheduleDate).getTime();
        const now = Date.now();
        const diffMinutes = (targetTime - now) / 1000 / 60;
        if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
        if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
        scheduledUnixTime = Math.floor(targetTime / 1000);
    }

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        const res = await publishPostToFacebook(
            settings.facebookPageId, 
            settings.facebookToken, 
            draft.caption, 
            mediaUrl, 
            draft.firstComment, 
            syncInstagram,
            scheduledUnixTime
        );

        if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = schedule ? 'scheduled' : 'published';
            await onPostCreated(newPost);

            if (schedule) setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
            else setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
        } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
        }

    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  if (isGeneratingMedia) return <LoadingOverlay message={generatingPhase} subMessage="請稍候，正在為您打造專屬素材" />;
  if (isPublishing) return <LoadingOverlay message="正在傳送至 Facebook..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 md:space-y-12 animate-fade-in pt-4 md:pt-10">
          <div className="text-center space-y-3">
              <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                  What's Next?
              </h2>
              <p className="text-gray-400 font-bold tracking-widest uppercase text-xs md:text-base">輸入核心主題，讓 AI 為您打造吸睛內容</p>
          </div>

          <div className="glass-card p-6 md:p-12 rounded-[2rem] shadow-2xl space-y-6 md:space-y-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 blur-[100px] rounded-full pointer-events-none"></div>

              <div className="flex p-1.5 bg-black/40 rounded-2xl border border-white/5 relative z-10">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'brand' ? 'bg-primary text-black shadow-[0_0_20px_rgba(0,242,234,0.4)]' : 'text-gray-500 hover:text-white'}`}>品牌模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-3 md:py-4 rounded-xl font-bold tracking-wide transition-all text-sm md:text-base ${mode === 'viral' ? 'bg-secondary text-white shadow-[0_0_20px_rgba(255,0,85,0.4)]' : 'text-gray-500 hover:text-white'}`}>爆文模式 (小紅書)</button>
              </div>

              <div className="flex flex-col md:flex-row gap-3 relative z-10">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 p-4 md:p-5 rounded-2xl text-lg md:text-xl font-medium placeholder-gray-600 outline-none w-full" placeholder="輸入主題 (例如：夏季保養、今日新聞...)" />
                  <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 px-8 py-4 md:py-0 rounded-2xl text-white font-bold transition-all flex flex-row md:flex-col items-center justify-center gap-2 md:gap-1 border border-gray-700 hover:border-white/20 whitespace-nowrap">
                    <span className="text-sm">🔥 挖掘靈感</span><span className="text-[9px] bg-primary/20 text-primary px-2 rounded-full font-black">3 點數</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader border-t-primary"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-white/5 rounded-2xl bg-black/20 custom-scrollbar relative z-10">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => setTopic(t.title)} className={`p-4 rounded-xl cursor-pointer transition-all group backdrop-blur-md ${topic === t.title ? 'bg-primary/20 border-primary border' : 'bg-white/5 border-transparent border hover:border-white/20 hover:bg-white/10'}`}>
                              <h4 className="font-bold text-white text-sm mb-1 line-clamp-1 group-hover:text-primary transition-colors">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button onClick={handleNext} disabled={!topic} className={`w-full py-5 md:py-6 rounded-2xl font-black text-white shadow-2xl hover:opacity-90 transition-all disabled:opacity-30 text-lg md:text-xl tracking-widest uppercase relative z-10 ${mode === 'viral' ? 'bg-gradient-to-r from-orange-600 to-red-600' : 'bg-gradient-to-r from-blue-600 to-primary'}`}>
                開始生成文案 <span className="text-sm font-normal opacity-70 ml-2">(5 點數)</span>
              </button>
          </div>
      </div>
  );

  return (
